// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: '1samuel',
  name: '1 Samuel',
  englishName: '1 Samuel',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Now there was a certain man of Ramathaim Zophim, of the hill country of Ephraim, and his name was Elkanah, the son of Jeroham, the son of Elihu, the son of Tohu, the son of Zuph, an Ephraimite.', pt: 'Houve um homem de Ramataim-Zofim, da região montanhosa de Efraim, cujo nome era Elcana, filho de Jeroão, filho de Eliú, filho de Toú, filho de Zufe, efraimita.' },
      { v: 2, en: 'He had two wives. The name of one was Hannah, and the name of other Peninnah. Peninnah had children, but Hannah had no children.', pt: 'Tinha ele duas mulheres: uma se chamava Ana, e a outra Penina. Penina tinha filhos, porém Ana não os tinha.' },
      { v: 3, en: 'This man went up out of his city from year to year to worship and to sacrifice to Yahweh of Armies in Shiloh. The two sons of Eli, Hophni and Phinehas, priests to Yahweh, were there.', pt: 'De ano em ano este homem subia da sua cidade para adorar e sacrificar ae Senhor dos exércites em Siló. Assistiam ali os sacerdotes do Senhor, Hofni e Finéias, os dois filhos de Eli.' },
      { v: 4, en: 'When the day came that Elkanah sacrificed, he gave to Peninnah his wife, and to all her sons and her daughters, portions;', pt: 'No dia em que Elcana sacrificava, costumava dar quinhões a Penina, sua mulher, e a todos os seus filhos e filhas;' },
      { v: 5, en: 'but to Hannah he gave a double portion, for he loved Hannah, but Yahweh had shut up her womb.', pt: 'porém a Ana, embora a amasse, dava um só quinhão, porquanto o Senhor lhe havia cerrado a madre.' },
      { v: 6, en: 'Her rival provoked her severely, to irritate her, because Yahweh had shut up her womb.', pt: 'Ora, a sua rival muito a provocava para irritá-la, porque o Senhor lhe havia cerrado a madre.' },
      { v: 7, en: 'As he did so year by year, when she went up to Yahweh’s house. Her rival provoked her; therefore she wept, and didn’t eat.', pt: 'E assim sucedia de ano em ano que, ao subirem à casa do Senhor, Penina provocava a Ana; pelo que esta chorava e não comia.' },
      { v: 8, en: 'Elkanah her husband said to her, “Hannah, why do you weep? Why don’t you eat? Why is your heart grieved? Am I not better to you than ten sons?”', pt: 'Então Elcana, seu marido, lhe perguntou: Ana, por que choras? e porque não comes? e por que está triste o teu coração? Não te sou eu melhor de que dez filhos?' },
      { v: 9, en: 'So Hannah rose up after they had finished eating and drinking in Shiloh. Now Eli the priest was sitting on his seat by the doorpost of Yahweh’s temple.', pt: 'Então Ana se levantou, depois que comeram e beberam em Siló; e Eli, sacerdote, estava sentado, numa cadeira, junto a um pilar do templo do Senhor.' },
      { v: 10, en: 'She was in bitterness of soul, and prayed to Yahweh, weeping bitterly.', pt: 'Ela, pois, com amargura de alma, orou ao Senhor, e chorou muito,' },
      { v: 11, en: 'She vowed a vow, and said, “Yahweh of Armies, if you will indeed look at the affliction of your servant, and remember me, and not forget your servant, but will give to your servant a boy, then I will give him to Yahweh all the days of his life, and no razor shall come on his head.”', pt: 'e fez um voto, dizendo: ç Senhor dos exércitos! se deveras atentares para a aflição da tua serva, e de mim te lembrares, e da tua serva não te esqueceres, mas lhe deres um filho varão, ao Senhor o darei por todos os dias da sua vida, e pela sua cabeça não passará navalha.' },
      { v: 12, en: 'As she continued praying before Yahweh, Eli saw her mouth.', pt: 'Continuando ela a orar perante e Senhor, Eli observou a sua boca;' },
      { v: 13, en: 'Now Hannah spoke in her heart. Only her lips moved, but her voice was not heard. Therefore Eli thought she was drunk.', pt: 'porquanto Ana falava no seu coração; só se moviam os seus lábios, e não se ouvia a sua voz; pelo que Eli a teve por embriagada,' },
      { v: 14, en: 'Eli said to her, “How long will you be drunk? Get rid of your wine!”', pt: 'e lhe disse: Até quando estarás tu embriagada? Aparta de ti o teu vinho.' },
      { v: 15, en: 'Hannah answered, “No, my lord, I am a woman of a sorrowful spirit. I have not been drinking wine or strong drink, but I poured out my soul before Yahweh.', pt: 'Mas Ana respondeu: Não, Senhor meu, eu sou uma mulher atribulada de espírito; não bebi vinho nem bebida forte, porém derramei a minha alma perante o Senhor.' },
      { v: 16, en: 'Don’t consider your servant a wicked woman; for I have been speaking out of the abundance of my complaint and my provocation.”', pt: 'Não tenhas, pois, a tua serva por filha de Belial; porque da multidão dos meus cuidados e do meu desgosto tenho falado até agora.' },
      { v: 17, en: 'Then Eli answered, “Go in peace; and may the God of Israel grant your petition that you have asked of him.”', pt: 'Então lhe respondeu Eli: Vai-te em paz; e o Deus de Israel te conceda a petição que lhe fizeste.' },
      { v: 18, en: 'She said, “Let your servant find favor in your sight.” So the woman went her way, and ate; and her facial expression wasn’t sad any more.', pt: 'Ao que disse ela: Ache a tua serva graça aos teus olhos. Assim a mulher se foi o seu caminho, e comeu, e já não era triste o seu semblante.' },
      { v: 19, en: 'They rose up in the morning early, and worshiped before Yahweh, and returned, and came to their house to Ramah. Then Elkanah knew Hannah his wife; and Yahweh remembered her.', pt: 'Depois, levantando-se de madrugada, adoraram perante o Senhor e, voltando, foram a sua casa em Ramá. Elcana conheceu a Ana, sua mulher, e o Senhor se lembrou dela.' },
      { v: 20, en: 'When the time had come, Hannah conceived, and bore a son; and she named him Samuel, saying, “Because I have asked him of Yahweh.”', pt: 'De modo que Ana concebeu e, no tempo devido, teve um filho, ao qual chamou Samuel; porque, dizia ela, o tenho pedido ao Senhor.' },
      { v: 21, en: 'The man Elkanah, and all his house, went up to offer to Yahweh the yearly sacrifice, and his vow.', pt: 'Subiu, pois aquele homem, Elcana, com toda a sua casa, para oferecer ao Senhor o sacrifício anual e cumprir o seu voto.' },
      { v: 22, en: 'But Hannah didn’t go up; for she said to her husband, “Not until the child is weaned; then I will bring him, that he may appear before Yahweh, and stay there forever.”', pt: 'Ana, porém, não subiu, pois disse a seu marido: Quando o menino for desmamado, então e levarei, para que apareça perante o Senhor, e lá fique para sempre.' },
      { v: 23, en: 'Elkanah her husband said to her, “Do what seems good to you. Wait until you have weaned him; only may Yahweh establish his word.” So the woman waited and nursed her son, until she weaned him.', pt: 'E Elcana, seu marido, lhe disse: faze o que bem te parecer; fica até que o desmames; tão-somente confirme o Senhor a sua palavra. Assim ficou a mulher, e amamentou seu filho, até que o desmamou.' },
      { v: 24, en: 'When she had weaned him, she took him up with her, with three bulls, and one ephah of meal, and a bottle of wine, and brought him to Yahweh’s house in Shiloh. The child was young.', pt: 'Depois de o ter desmamado, ela o tomou consigo, com um touro de três anos, uma efa de farinha e um odre de vinho, e o levou à casa do Senhor, em Siló; e era o menino ainda muito criança.' },
      { v: 25, en: 'They killed the bull, and brought the child to Eli.', pt: 'Então degolaram o touro, e trouxeram o menino a Eli;' },
      { v: 26, en: 'She said, “Oh, my lord, as your soul lives, my lord, I am the woman who stood by you here, praying to Yahweh.', pt: 'e disse ela: Ah, meu Senhor! tão certamente como vive a tua alma, meu Senhor, eu sou aquela mulher que aqui esteve contigo, orando ao Senhor.' },
      { v: 27, en: 'I prayed for this child; and Yahweh has given me my petition which I asked of him.', pt: 'Por este menino orava eu, e o Senhor atendeu a petição que eu lhe fiz.' },
      { v: 28, en: 'Therefore I have also given him to Yahweh. As long as he lives he is given to Yahweh.” He worshiped Yahweh there.', pt: 'Por isso eu também o entreguei ao Senhor; por todos os dias que viver, ao Senhor está entregue. E adoraram ali ao Senhor.' },
    ],
    2: [
      { v: 1, en: 'Hannah prayed, and said: “My heart exults in Yahweh! My horn is exalted in Yahweh. My mouth is enlarged over my enemies, because I rejoice in your salvation.', pt: 'Então Ana orou, dizendo: O meu coração exulta no Senhor; o meu poder está exaltado no Senhor; a minha boca dilata-se contra os meus imimigos, porquanto me regozijo na tua salvação.' },
      { v: 2, en: 'There is no one as holy as Yahweh, For there is no one besides you, nor is there any rock like our God.', pt: 'Ninguém há santo como o Senhor; não há outro fora de ti; não há rocha como a nosso Deus.' },
      { v: 3, en: '“Don’t keep talking so exceedingly proudly. Don’t let arrogance come out of your mouth, For Yahweh is a God of knowledge. By him actions are weighed.', pt: 'Não faleis mais palavras tão altivas, nem saia da vossa boca a arrogância; porque o Senhor é o Deus da sabedoria, e por ele são pesadas as ações.' },
      { v: 4, en: '“The bows of the mighty men are broken. Those who stumbled are armed with strength.', pt: 'Os arcos dos fortes estão quebrados, e os fracos são cingidos de força.' },
      { v: 5, en: 'Those who were full have hired themselves out for bread. Those who were hungry are satisfied. Yes, the barren has borne seven. She who has many children languishes.', pt: 'Os que eram fartos se alugam por pão, e deixam de ter fome os que eram famintos; até a estéril teve sete filhos, e a que tinha muitos filhos enfraquece.' },
      { v: 6, en: '“Yahweh kills, and makes alive. He brings down to Sheol, and brings up.', pt: 'O Senhor é o que tira a vida e a dá; faz descer ao Seol e faz subir dali.' },
      { v: 7, en: 'Yahweh makes poor, and makes rich. He brings low, he also lifts up.', pt: 'O Senhor empobrece e enriquece; abate e também exalta.' },
      { v: 8, en: 'He raises up the poor out of the dust. He lifts up the needy from the dunghill, To make them sit with princes, and inherit the throne of glory. For the pillars of the earth are Yahweh’s. He has set the world on them.', pt: 'Levanta do pó o pobre, do monturo eleva o necessitado, para os fazer sentar entre os príncipes, para os fazer herdar um trono de glória; porque do Senhor são as colunas da terra, sobre elas pôs ele o mundo.' },
      { v: 9, en: 'He will keep the feet of his holy ones, but the wicked shall be put to silence in darkness; for no man shall prevail by strength.', pt: 'Ele guardará os pés dos seus santos, porém os ímpios ficarão mudos nas trevas, porque o homem não prevalecerá pela força.' },
      { v: 10, en: 'Those who strive with Yahweh shall be broken to pieces. He will thunder against them in the sky. “Yahweh will judge the ends of the earth. He will give strength to his king, and exalt the horn of his anointed.”', pt: 'Os que contendem com o Senhor serão quebrantados; desde os céus trovejará contra eles. O Senhor julgará as extremidades da terra; dará força ao seu rei, e exaltará o poder do seu ungido.' },
      { v: 11, en: 'Elkanah went to Ramah to his house. The child served Yahweh before Eli the priest.', pt: 'Então Elcana se retirou a Ramá, à sua casa. O menino, porém, ficou servindo ao Senhor perante e sacerdote Eli.' },
      { v: 12, en: 'Now the sons of Eli were wicked men. They didn’t know Yahweh.', pt: 'Ora, os filhos de Eli eram homens ímpios; não conheciam ao Senhor.' },
      { v: 13, en: 'The custom of the priests with the people was that when anyone offered a sacrifice, the priest’s servant came while the meat was boiling, with a fork of three teeth in his hand;', pt: 'Porquanto o costume desses sacerdotes para com o povo era que, oferecendo alguém um sacrifício, e estando-se a cozer a carne, vinha o servo do sacerdote, tendo na mão um garfo de três dentes,' },
      { v: 14, en: 'and he stabbed it into the pan, or kettle, or cauldron, or pot. The priest took all that the fork brought up for himself. So they did in Shiloh to all the Israelites who came there.', pt: 'e o metia na panela, ou no tacho, ou no caldeirão, ou na marmita; e tudo quanto a garfo tirava, o sacerdote tomava para si. Assim faziam a todos os de Israel que chegavam ali em Siló.' },
      { v: 15, en: 'Yes, before they burned the fat, the priest’s servant came, and said to the man who sacrificed, “Give meat to roast for the priest; for he will not accept boiled meat from you, but raw.”', pt: 'Também, antes de queimarem a gordura, vinha o servo do sacerdote e dizia ao homem que sacrificava: Dá carne de assar para o sacerdote; porque não receberá de ti carne cozida, mas crua.' },
      { v: 16, en: 'If the man said to him, “Let the fat be burned first, and then take as much as your soul desires”; then he would say, “No, but you shall give it to me now; and if not, I will take it by force.”', pt: 'se lhe respondia o homem: Sem dúvida, logo há de ser queimada a gordura e depois toma quanto desejar a tua alma; então ele lhe dizia: Não hás de dá-la agora; se não, à força a tomarei.' },
      { v: 17, en: 'The sin of the young men was very great before Yahweh; for the men despised the offering of Yahweh.', pt: 'Era, pois, muito grande o pecado destes mancebos perante o Senhor, porquanto os homens vieram a desprezar a oferta do Senhor.' },
      { v: 18, en: 'But Samuel ministered before Yahweh, being a child, clothed with a linen ephod.', pt: 'Samuel, porém, ministrava perante o Senhor, sendo ainda menino, vestido de um éfode de linho.' },
      { v: 19, en: 'Moreover his mother made him a little robe, and brought it to him from year to year, when she came up with her husband to offer the yearly sacrifice.', pt: 'E sua mãe lhe fazia de ano em ano uma túnica pequena, e lha trazia quando com seu marido subia para oferecer o sacrifício anual.' },
      { v: 20, en: 'Eli blessed Elkanah and his wife, and said, “May Yahweh give you offspring from this woman for the petition which was asked of Yahweh.” Then they went to their own home.', pt: 'Então Eli abençoava a Elcana e a sua mulher, e dizia: O Senhor te dê desta mulher descendência, pelo empréstimo que fez ao Senhor. E voltavam para o seu lugar.' },
      { v: 21, en: 'Yahweh visited Hannah, and she conceived, and bore three sons and two daughters. The child Samuel grew before Yahweh.', pt: 'Visitou, pois, o Senhor a Ana, que concebeu, e teve três filhos e duas filhas. Entrementes, o menino Samuel crescia diante do Senhor.' },
      { v: 22, en: 'Now Eli was very old; and he heard all that his sons did to all Israel, and how that they slept with the women who served at the door of the Tent of Meeting.', pt: 'Eli era já muito velho; e ouvia tudo quanto seus filhos faziam a todo o Israel, e como se deitavam com as mulheres que ministravam à porta da tenda da revelação.' },
      { v: 23, en: 'He said to them, “Why do you do such things? for I hear of your evil dealings from all this people.', pt: 'E disse-lhes: Por que fazeis tais coisas? pois ouço de todo este povo os vossos malefícios.' },
      { v: 24, en: 'No, my sons; for it is no good report that I hear! You make Yahweh’s people disobey.', pt: 'Não, filhos meus, não é boa fama esta que ouço. Fazeis transgredir o povo do Senhor.' },
      { v: 25, en: 'If one man sins against another, God will judge him; but if a man sins against Yahweh, who will intercede for him?” Notwithstanding, they didn’t listen to the voice of their father, because Yahweh intended to kill them.', pt: 'Se um homem pecar contra outro, Deus o julgará; mas se um homem pecar contra o Senhor, quem intercederá por ele? Todavia eles não ouviram a voz de seu pai, porque o Senhor os queria destruir.' },
      { v: 26, en: 'The child Samuel grew on, and increased in favor both with Yahweh, and also with men.', pt: 'E o menino Samuel ia crescendo em estatura e em graça diante do Senhor, como também diante dos homens.' },
      { v: 27, en: 'A man of God came to Eli, and said to him, “Yahweh says, ‘Did I reveal myself to the house of your father, when they were in Egypt in bondage to Pharaoh’s house?', pt: 'Veio um homem de Deus a Eli, e lhe disse: Assim diz o Senhor: Não me revelei, na verdade, à casa de teu pai, estando eles ainda no Egito, sujeitos à casa de Faraó?' },
      { v: 28, en: 'Didn’t I choose him out of all the tribes of Israel to be my priest, to go up to my altar, to burn incense, to wear an ephod before me? Didn’t I give to the house of your father all the offerings of the children of Israel made by fire?', pt: 'E eu o escolhi dentre todas as tribos de Israel para ser o meu sacerdote, para subir ao meu altar, para queimar o incenso, e para trazer o éfode perante mim; e dei à casa de teu pai todas as ofertas queimadas dos filhos de Israel.' },
      { v: 29, en: 'Why do you kick at my sacrifice and at my offering, which I have commanded in my habitation, and honor your sons above me, to make yourselves fat with the best of all the offerings of Israel my people?’', pt: 'Por que desprezais o meu sacrifício e a minha oferta, que ordenei se fizessem na minha morada, e por que honras a teus filhos mais de que a mim, de modo a vos engordardes do principal de todas as ofertas do meu povo Israel?' },
      { v: 30, en: '“Therefore Yahweh, the God of Israel, says, ‘I said indeed that your house, and the house of your father, should walk before me forever.’ But now Yahweh says, ‘Far be it from me; for those who honor me I will honor, and those who despise me will be cursed.', pt: 'Portanto, diz o Senhor Deus de Israel: Na verdade eu tinha dito que a tua casa e a casa de teu pai andariam diante de mim perpetuamente. Mas agora o Senhor diz: Longe de mim tal coisa, porque honrarei aos que me honram, mas os que me desprezam serão desprezados.' },
      { v: 31, en: 'Behold, the days come, that I will cut off your arm, and the arm of your father’s house, that there will not be an old man in your house.', pt: 'Eis que vêm dias em que cortarei o teu braço e o braço da casa de teu pai, para que não haja mais ancião algum em tua casa.' },
      { v: 32, en: 'You will see the affliction of my habitation, in all the wealth which I will give Israel; and there shall not be an old man in your house forever.', pt: 'E tu, na angústia, olharás com inveja toda a prosperidade que hei de trazer sobre Israel; e não haverá por todos os dias ancião algum em tua casa.' },
      { v: 33, en: 'The man of yours, whom I don’t cut off from my altar, will consume your eyes and grieve your heart; and all the increase of your house will die in the flower of their age.', pt: 'O homem da tua linhagem a quem eu não desarraigar do meu altar será para consumir-te os olhos e para entristecer-te a alma; e todos es descendentes da tua casa morrerão pela espada dos homens.' },
      { v: 34, en: '“‘This will be the sign to you, that will come on your two sons, on Hophni and Phinehas: in one day they will both die.', pt: 'E te será por sinal o que sobrevirá a teus dois filhos, a Hofni e a Finéias; ambos morrerão no mesmo dia.' },
      { v: 35, en: 'I will raise me up a faithful priest, that will do according to that which is in my heart and in my mind. I will build him a sure house; and he will walk before my anointed forever.', pt: 'E eu suscitarei para mim um sacerdote fiel, que fará segundo o que está no meu coração e na minha mente. Edificar-lhe-ei uma casa duradoura, e ele andará sempre diante de meu ungido.' },
      { v: 36, en: 'It will happen, that everyone who is left in your house will come and bow down to him for a piece of silver and a loaf of bread, and will say, “Please put me into one of the priests’ offices, that I may eat a morsel of bread.”’”', pt: 'Também todo aquele que ficar de resto da tua casa virá a inclinar-se diante dele por uma moeda de prata e por um pedaço de pão, e dirá: Rogo-te que me admitas a algum cargo sacerdotal, para que possa comer um bocado de pão.' },
    ],
    3: [
      { v: 1, en: 'The child Samuel ministered to Yahweh before Eli. Yahweh’s word was precious in those days. There were not many visions, then.', pt: 'Entretanto, o menino Samuel servia ao Senhor perante Eli. E a palavra de Senhor era muito rara naqueles dias; as visões não eram freqüentes.' },
      { v: 2, en: 'At that time, when Eli was laid down in his place (now his eyes had begun to grow dim, so that he could not see),', pt: 'Sucedeu naquele tempo que, estando Eli deitado ne seu lugar (ora, os seus olhos começavam já a escurecer, de modo que não podia ver),' },
      { v: 3, en: 'and God’s lamp hadn’t yet gone out, and Samuel had laid down in Yahweh’s temple, where God’s ark was;', pt: 'e ainda não se havendo apagado a lâmpada de Deus, e estando Samuel também deitado no templo do Senhor, onde estava a arca de Deus,' },
      { v: 4, en: 'Yahweh called Samuel; and he said, “Here I am.”', pt: 'o Senhor chamou: Samuel! Samuel! Ele respondeu: Eis-me aqui.' },
      { v: 5, en: 'He ran to Eli, and said, “Here I am; for you called me.” He said, “I didn’t call. Lie down again.” He went and lay down.', pt: 'E correndo a Eli, disse-lhe: Eis-me aqui, porque tu me chamaste. Mas ele disse: Eu não te chamei; torna a deitar-te. E ele foi e se deitou.' },
      { v: 6, en: 'Yahweh called yet again, “Samuel!” Samuel arose and went to Eli, and said, “Here I am; for you called me.” He answered, “I didn’t call, my son. Lie down again.”', pt: 'Tornou o Senhor a chamar: Samuel! E Samuel se levantou, foi a Eli e disse: Eis-me aqui, porque tu me chamaste. Mas ele disse: Eu não te chamei, filho meu; torna a deitar-te.' },
      { v: 7, en: 'Now Samuel didn’t yet know Yahweh, neither was Yahweh’s word yet revealed to him.', pt: 'Ora, Samuel ainda não conhecia ao Senhor, e a palavra de Senhor ainda não lhe tinha sido revelada.' },
      { v: 8, en: 'Yahweh called Samuel again the third time. He arose and went to Eli, and said, “Here I am; for you called me.” Eli perceived that Yahweh had called the child.', pt: 'O Senhor, pois, tornou a chamar a Samuel pela terceira vez. E ele, levantando-se, foi a Eli e disse: Eis-me aqui, porque tu me chamaste. Então entendeu Eli que o Senhor chamava o menino.' },
      { v: 9, en: 'Therefore Eli said to Samuel, “Go, lie down. It shall be, if he calls you, that you shall say, ‘Speak, Yahweh; for your servant hears.’” So Samuel went and lay down in his place.', pt: 'Pelo que Eli disse a Samuel: Vai deitar-te, e há de ser que, se te chamar, dirás: Fala, Senhor, porque o teu servo ouve. Foi, pois, Samuel e deitou-se no seu lugar.' },
      { v: 10, en: 'Yahweh came, and stood, and called as at other times, “Samuel! Samuel!” Then Samuel said, “Speak; for your servant hears.”', pt: 'Depois veio o Senhor, parou e chamou como das outras vezes: Samuel! Samuel! Ao que respondeu Samuel: Fala, porque o teu servo ouve.' },
      { v: 11, en: 'Yahweh said to Samuel, “Behold, I will do a thing in Israel, at which both the ears of everyone who hears it will tingle.', pt: 'Então disse o Senhor a Samuel: Eis que vou fazer uma coisa em Israel, a qual fará tinir ambos os ouvidos a todo o que a ouvir.' },
      { v: 12, en: 'In that day I will perform against Eli all that I have spoken concerning his house, from the beginning even to the end.', pt: 'Naquele mesmo dia cumprirei contra Eli, de princípio a fim, tudo quanto tenho falado a respeito da sua casa.' },
      { v: 13, en: 'For I have told him that I will judge his house forever, for the iniquity which he knew, because his sons brought a curse on themselves, and he didn’t restrain them.', pt: 'Porque já lhe fiz: saber que hei de julgar a sua casa para sempre, por causa da iniqüidade de que ele bem sabia, pois os seus filhos blasfemavam a Deus, e ele não os repreendeu.' },
      { v: 14, en: 'Therefore I have sworn to the house of Eli, that the iniquity of Eli’s house shall not be removed with sacrifice or offering forever.”', pt: 'Portanto, jurei à casa de Eli que nunca jamais será expiada a sua iniqüidade, nem com sacrifícios, nem com ofertas.' },
      { v: 15, en: 'Samuel lay until the morning, and opened the doors of Yahweh’s house. Samuel feared to show Eli the vision.', pt: 'Samuel ficou deitado até pela manhã, e então abriu as portas da casa do Senhor; Samuel, porém, temia relatar essa visão a Eli.' },
      { v: 16, en: 'Then Eli called Samuel, and said, “Samuel, my son!” He said, “Here I am.”', pt: 'Mas chamou Eli a Samuel, e disse: Samuel, meu filho! Ao que este respondeu: Eis-me aqui.' },
      { v: 17, en: 'He said, “What is the thing that he has spoken to you? Please don’t hide it from me. God do so to you, and more also, if you hide anything from me of all the things that he spoke to you.”', pt: 'Eli perguntou-lhe: Que te falou o Senhor? peço-te que não mo encubras; assim Deus te faça, e outro tanto, se me encobrires alguma coisa de tudo o que te falou.' },
      { v: 18, en: 'Samuel told him every bit, and hid nothing from him. He said, “It is Yahweh. Let him do what seems good to him.”', pt: 'Samuel, pois, relatou-lhe tudo, e nada lhe encobriu. Então disse Eli: Ele é o Senhor, faça o que bem parecer aos seus olhos.' },
      { v: 19, en: 'Samuel grew, and Yahweh was with him, and let none of his words fall to the ground.', pt: 'Samuel crescia, e o Senhor era com ele e não deixou nenhuma de todas as suas palavras cair em terra.' },
      { v: 20, en: 'All Israel from Dan even to Beersheba knew that Samuel was established to be a prophet of Yahweh.', pt: 'E todo o Israel, desde Dã até Berseba, conheceu que Samuel estava confirmado como profeta do Senhor.' },
      { v: 21, en: 'Yahweh appeared again in Shiloh; for Yahweh revealed himself to Samuel in Shiloh by Yahweh’s word.', pt: 'E voltou o Senhor a aparecer em Siló; porquanto o Senhor se manifestava a Samuel em Siló pela sua palavra. E chegava a palavra de Samuel a todo o Israel.' },
    ],
    4: [
      { v: 1, en: 'The word of Samuel came to all Israel. Now Israel went out against the Philistines to battle, and encamped beside Ebenezer; and the Philistines encamped in Aphek.', pt: 'Ora, saiu Israel à batalha contra os filisteus, e acampou-se perto de Ebenézer; e os filisteus se acamparam junto a Afeque.' },
      { v: 2, en: 'The Philistines put themselves in array against Israel. When they joined battle, Israel was defeated by the Philistines, who killed about four thousand men of the army in the field.', pt: 'E os filisteus se dispuseram em ordem de batalha contra Israel; e, travada a peleja, Israel foi ferido diante dos filisteus, que mataram no campo cerca de quatro mil homens do exército.' },
      { v: 3, en: 'When the people had come into the camp, the elders of Israel said, “Why has Yahweh defeated us today before the Philistines? Let us get the ark of Yahweh’s covenant out of Shiloh and bring it to us, that it may come among us, and save us out of the hand of our enemies.”', pt: 'Quando o povo voltou ao arraial, disseram os anciãos de Israel: Por que nos feriu o Senhor hoje diante dos filisteus? Tragamos para nós de Siló a arca do pacto do Senhor, para que ela venha para o meio de nós, e nos livre da mão de nossos inimigos.' },
      { v: 4, en: 'So the people sent to Shiloh; and they brought from there the ark of the covenant of Yahweh of Armies, who sits above the cherubim: and the two sons of Eli, Hophni and Phinehas, were there with the ark of the covenant of God.', pt: 'Enviou, pois, o povo a Siló, e trouxeram de lá a arca do pacto do Senhor dos exércitos, que se assenta sobre os querubins; e os dois filhos de Eli, Hofni e Finéias, estavam ali com a arca do pacto de Deus.' },
      { v: 5, en: 'When the ark of Yahweh’s covenant came into the camp, all Israel shouted with a great shout, so that the earth rang again.', pt: 'Quando a arca do pacto do Senhor chegou ao arraial, prorrompeu todo o Israel em grandes gritos, de modo que a terra vibrou.' },
      { v: 6, en: 'When the Philistines heard the noise of the shout, they said, “What does the noise of this great shout in the camp of the Hebrews mean?” They understood that Yahweh’s ark had come into the camp.', pt: 'E os filisteus, ouvindo o som da gritaria, disseram: Que quer dizer esta grande vozearia no arraial dos hebreus? Quando souberam que a arca do Senhor havia chegado ao arraial,' },
      { v: 7, en: 'The Philistines were afraid, for they said, “God has come into the camp.” They said, “Woe to us! For there has not been such a thing before.', pt: 'os filisteus se atemorizaram; e diziam: Os deuses vieram ao arraial. Diziam mais: Ai de nós! porque nunca antes sucedeu tal coisa.' },
      { v: 8, en: 'Woe to us! Who shall deliver us out of the hand of these mighty gods? These are the gods that struck the Egyptians with all kinds of plagues in the wilderness.', pt: 'Ai de nós! quem nos livrará da mão destes deuses possantes? Estes são os deuses que feriram aos egípcios com toda sorte de pragas no deserto.' },
      { v: 9, en: 'Be strong, and behave like men, O you Philistines, that you not be servants to the Hebrews, as they have been to you. Strengthen yourselves like men, and fight!”', pt: 'Esforçai-vos, e portai-vos varonilmente, ó filisteus, para que porventura não venhais a ser escravos dos hebreus, como eles o foram vossos; portai-vos varonilmente e pelejai.' },
      { v: 10, en: 'The Philistines fought, and Israel was defeated, and each man fled to his tent. There was a very great slaughter; for thirty thousand footmen of Israel fell.', pt: 'Então pelejaram os filisteus, e Israel foi derrotado, fugindo cada um para a sua tenda; e houve mui grande matança, pois caíram de Israel trinta mil homens de infantaria.' },
      { v: 11, en: 'God’s ark was taken; and the two sons of Eli, Hophni and Phinehas, were slain.', pt: 'Também foi tomada a arca de Deus, e os dois filhos de Eli, Hofni e Finéias, foram mortos.' },
      { v: 12, en: 'A man of Benjamin ran out of the army, and came to Shiloh the same day, with his clothes torn, and with dirt on his head.', pt: 'Então um homem de Benjamim, correndo do campo de batalha chegou no mesmo dia a Siló, com as vestes rasgadas e terra sobre a cabeça.' },
      { v: 13, en: 'When he came, behold, Eli was sitting on his seat by the road watching; for his heart trembled for God’s ark. When the man came into the city and told about it, all the city cried out.', pt: 'Ao chegar ele, estava Eli sentado numa cadeira ao pé do caminho vigiando, porquanto o seu coração estava tremendo pela arca de Deus. E quando aquele homem chegou e anunciou isto na cidade, a cidade toda prorrompeu em lamentações.' },
      { v: 14, en: 'When Eli heard the noise of the crying, he said, “What does the noise of this tumult mean?” The man hurried, and came and told Eli.', pt: 'E Eli, ouvindo a voz do lamento, perguntou: Que quer dizer este alvoroço? Então o homem, apressando-se, chegou e o anunciou a Eli.' },
      { v: 15, en: 'Now Eli was ninety-eight years old. His eyes were set, so that he could not see.', pt: 'Ora, Eli tinha noventa e oito anos; e os seus olhos haviam cegado, de modo que já não podia ver.' },
      { v: 16, en: 'The man said to Eli, “I am he who came out of the army, and I fled today out of the army.” He said, “How did the matter go, my son?”', pt: 'E disse aquele homem a Eli: Estou vindo do campo de batalha, donde fugi hoje mesmo. Perguntou Eli: Que foi que sucedeu, meu filho?' },
      { v: 17, en: 'He who brought the news answered, “Israel has fled before the Philistines, and there has been also a great slaughter among the people. Your two sons also, Hophni and Phinehas, are dead, and God’s ark has been captured.”', pt: 'Então respondeu o que trazia as novas, e disse: Israel fugiu de diante dos filisteus, e houve grande matança entre o povo; além disto, também teus dois filhos, Hofni e Finéias, são mortos, e a arca de Deus é tomada.' },
      { v: 18, en: 'When he made mention of God’s ark, Eli fell from off his seat backward by the side of the gate; and his neck broke, and he died; for he was an old man, and heavy. He had judged Israel forty years.', pt: 'Quando ele fez menção da arca de Deus, Eli caiu da cadeira para trás, junto à porta, e quebrou-se-lhe o pescoço, e morreu, porquanto era homem velho e pesado. Ele tinha julgado a Israel quarenta anos.' },
      { v: 19, en: 'His daughter-in-law, Phinehas’ wife, was with child, near to be delivered. When she heard the news that God’s ark was taken, and that her father-in-law and her husband were dead, she bowed herself and gave birth; for her pains came on her.', pt: 'E estando sua nora, a mulher de Finéias, grávida e próxima ao parto, e ouvindo estas novas, de que a arca de Deus era tomada, e de que seu sogro e seu marido eram mortos, encurvou-se e deu à luz, porquanto as dores lhe sobrevieram.' },
      { v: 20, en: 'About the time of her death the women who stood by her said to her, “Don’t be afraid; for you have given birth to a son.” But she didn’t answer, neither did she regard it.', pt: 'E, na hora em que ia morrendo, disseram as mulheres que estavam com ela: Não temas, pois tiveste um filho. Ela, porém, não respondeu, nem deu atenção a isto.' },
      { v: 21, en: 'She named the child Ichabod, saying, “The glory has departed from Israel”; because God’s ark was taken, and because of her father-in-law and her husband.', pt: 'E chamou ao menino de Icabô, dizendo: De Israel se foi a glória! Porque fora tomada a arca de Deus, e por causa de seu sogro e de seu marido.' },
      { v: 22, en: 'She said, “The glory has departed from Israel; for God’s ark has been taken.”', pt: 'E disse: De Israel se foi a glória, pois é tomada a arca de Deus.' },
    ],
    5: [
      { v: 1, en: 'Now the Philistines had taken God’s ark, and they brought it from Ebenezer to Ashdod.', pt: 'Os filisteus, pois, tomaram a arca de Deus, e a levaram de Ebenézer a Asdode.' },
      { v: 2, en: 'The Philistines took God’s ark, and brought it into the house of Dagon, and set it by Dagon.', pt: 'Então os filisteus tomaram a arca de Deus e a introduziram na casa de Dagom, e a puseram junto a Dagom.' },
      { v: 3, en: 'When the people of Ashdod arose early on the next day, behold, Dagon had fallen on his face to the ground before Yahweh’s ark. They took Dagon, and set him in his place again.', pt: 'Levantando-se, porém, de madrugada no dia seginte os de Asdode, eis que Dagom estava caído com o rosto em terra diante da arca do Senhor; e tomaram a Dagom, e tornaram a pô-lo no seu lugar.' },
      { v: 4, en: 'When they arose early on the following morning, behold, Dagon had fallen on his face to the ground before Yahweh’s ark; and the head of Dagon and both the palms of his hands were cut off on the threshold. Only Dagon’s torso was intact.', pt: 'E, levantando-se eles de madrugada no dia seguinte, eis que Dagom estava caído com o rosto em terra diante da arca do Senhor; e a cabeça de Dagom e ambas as suas mãos estavam cortadas sobre o limiar; somente o tronco ficou a Dagom.' },
      { v: 5, en: 'Therefore neither the priests of Dagon, nor any who come into Dagon’s house, step on the threshold of Dagon in Ashdod, to this day.', pt: 'Pelo que nem os sacerdotes de Dagom, nem nenhum de todos os que entram na casa de Dagom, pisam o limiar de Dagom em Asdode, até o dia de hoje.' },
      { v: 6, en: 'But Yahweh’s hand was heavy on the people of Ashdod, and he destroyed them, and struck them with tumors, even Ashdod and its borders.', pt: 'Entretanto a mão do Senhor se agravou sobre os de Asdode, e os assolou, e os feriu com tumores, a Asdode e aos seus termos.' },
      { v: 7, en: 'When the men of Ashdod saw that it was so, they said, “The ark of the God of Israel shall not stay with us; for his hand is severe on us, and on Dagon our god.”', pt: 'O que tendo visto os homens de Asdode, disseram: Não fique conosco a arca do Deus de Israel, pois a sua mão é dura sobre nós, e sobre Dagom, nosso deus.' },
      { v: 8, en: 'They sent therefore and gathered together all the lords of the Philistines, and said, “What shall we do with the ark of the God of Israel?” They answered, “Let the ark of the God of Israel be carried over to Gath.” They carried the ark of the God of Israel there.', pt: 'Pelo que enviaram mensageiros e congregaram a si todos os chefes dos filisteus, e disseram: Que faremos nós da arca do Deus de Israel? Responderam: Seja levada para Gate. Assim levaram para lá a arca do Deus de Israel.' },
      { v: 9, en: 'It was so, that after they had carried it there, Yahweh’s hand was against the city with a very great confusion; and he struck the men of the city, both small and great so that tumors broke out on them.', pt: 'E desde que a levaram para lá, a mão do Senhor veio contra aquela cidade, causando grande pânico; pois feriu aos homens daquela cidade, desde o pequeno até o grande, e nasceram-lhes tumores.' },
      { v: 10, en: 'So they sent God’s ark to Ekron. As God’s ark came to Ekron, the Ekronites cried out, saying, “They have brought the ark of the God of Israel here to us, to kill us and our people.”', pt: 'Então enviaram a arca de Deus a Ecrom. Sucedeu porém que, vindo a arca de Deus a Ecrom, os de Ecrom exclamaram, dizendo: Transportaram para nós a arca de Deus de Israel, para nos matar a nós e ao nosso povo.' },
      { v: 11, en: 'They sent therefore and gathered together all the lords of the Philistines, and they said, “Send the ark of the God of Israel away, and let it go again to its own place, that it not kill us and our people.” For there was a deadly confusion throughout all the city. The hand of God was very heavy there.', pt: 'Enviaram, pois, mensageiros, e congregaram a todos os chefes dos filisteus, e disseram: Enviai daqui a arca do Deus de Israel, e volte ela para o seu lugar, para que não nos mate a nós e ao nosso povo. Porque havia pânico mortal em toda a cidade, e a mão de Deus muito se agravara sobre ela.' },
      { v: 12, en: 'The men who didn’t die were struck with the tumors; and the cry of the city went up to heaven.', pt: 'Pois os homens que não morriam eram feridos com tumores; de modo que o clamor da cidade subia até o céu.' },
    ],
    6: [
      { v: 1, en: 'Yahweh’s ark was in the country of the Philistines seven months.', pt: 'A arca do Senhor ficou na terra dos filisteus sete meses.' },
      { v: 2, en: 'The Philistines called for the priests and the diviners, saying, “What shall we do with Yahweh’s ark? Show us how we should send it to its place.”', pt: 'Então os filisteus chamaram os sacerdotes e os adivinhadores para dizer-lhes: Que faremos nós da arca do Senhor? Fazei-nos saber como havemos de enviá-la para o seu lugar.' },
      { v: 3, en: 'They said, “If you send away the ark of the God of Israel, don’t send it empty; but by all means return a trespass offering to him. Then you will be healed, and it will be known to you why his hand is not removed from you.”', pt: 'Responderam eles: Se enviardes a arca do Deus de Israel, não a envieis vazia, porém sem falta enviareis a ele uma oferta pela culpa; então sereis curados, e se vos fará saber por que a sua mão não se retira de vós.' },
      { v: 4, en: 'Then they said, “What should the trespass offering be which we shall return to him?” They said, “Five golden tumors, and five golden mice, for the number of the lords of the Philistines; for one plague was on you all, and on your lords.', pt: 'Então perguntaram: Qual é a oferta pela culpa que lhe havemos de enviar? Eles responderam: Segundo o número dos chefes dos filisteus, cinco tumores de ouro e cinco ratos de ouro, porque a praga é uma e a mesma sobre todos os vossos príncipes.' },
      { v: 5, en: 'Therefore you shall make images of your tumors, and images of your mice that mar the land; and you shall give glory to the God of Israel. Perhaps he will release his hand from you, from your gods, and from your land.', pt: 'Fazei, pois, imagens, dos vossos tumores, e dos ratos que andam destruindo a terra, e dai glória ao Deus de Israel; porventura aliviará o peso da sua mão de sobre vós, e de sobre vosso deus, e de sobre vossa terra:' },
      { v: 6, en: 'Why then do you harden your hearts, as the Egyptians and Pharaoh hardened their hearts? When he had worked wonderfully among them, didn’t they let the people go, and they departed?', pt: 'Por que, pois, endureceríeis os vossos corações, como os egípcios e Faraó endureceram os seus corações? Porventura depois de os haver Deus castigado, não deixaram ir o povo, e este não se foi?' },
      { v: 7, en: '“Now therefore take and prepare yourselves a new cart, and two milk cows, on which there has come no yoke; and tie the cows to the cart, and bring their calves home from them;', pt: 'Agora, pois, fazei um carro novo, tomai duas vacas que estejam criando, sobre as quais não tenha vindo o jugo, atai-as ao carro e levai os seus bezerros de após elas para casa.' },
      { v: 8, en: 'and take Yahweh’s ark, and lay it on the cart. Put the jewels of gold, which you return him for a trespass offering, in a coffer by its side; and send it away, that it may go.', pt: 'Tomai a arca de Senhor, e ponde-a sobre o carro; também metei num cofre, ao seu lado, as jóias de ouro que haveis de oferecer ao Senhor como ofertas pela culpa; e assim a enviareis, para que se vá.' },
      { v: 9, en: 'Behold; if it goes up by the way of its own border to Beth Shemesh, then he has done us this great evil; but if not, then we shall know that it is not his hand that struck us. It was a chance that happened to us.”', pt: 'Reparai então: se ela subir pelo caminho do seu termo a Bete-Semes, foi ele quem nos fez este grande mal; mas, se não, saberemos que não foi a sua mão que nos feriu, e que isto nos sucedeu por acaso.' },
      { v: 10, en: 'The men did so, and took two milk cows, and tied them to the cart, and shut up their calves at home.', pt: 'Assim, pois, fizeram aqueles homens: tomaram duas vacas que criavam, ataram-nas ao carro, e encerraram os bezerros em casa;' },
      { v: 11, en: 'They put Yahweh’s ark on the cart, and the coffer with the golden mice and the images of their tumors.', pt: 'também puseram a arca do Senhor sobre o carro, bem como e cofre com os ratos de ouro e com as imagens dos seus tumores.' },
      { v: 12, en: 'The cows took the straight way by the way to Beth Shemesh. They went along the highway, lowing as they went, and didn’t turn away to the right hand or to the left; and the lords of the Philistines went after them to the border of Beth Shemesh.', pt: 'Então as vacas foram caminhando diretamente pelo caminho de Bete-Semes, seguindo a estrada, andando e berrando, sem se desviarem nem para a direita nem para a esquerda; e os chefes dos filisteus foram seguindo-as até o termo de Bete-Semes.' },
      { v: 13, en: 'The people of Beth Shemesh were reaping their wheat harvest in the valley; and they lifted up their eyes, and saw the ark, and rejoiced to see it.', pt: 'Ora, andavam os de Bete-Semes fazendo a sega do trigo no vale; e, levantando os olhos, viram a arca e, vendo-a, se alegraram.' },
      { v: 14, en: 'The cart came into the field of Joshua of Beth Shemesh, and stood there, where there was a great stone. Then they split the wood of the cart, and offered up the cows for a burnt offering to Yahweh.', pt: 'Tendo chegado o carro ao campo de Josué, o bete-semita, parou ali, onde havia uma grande pedra. Fenderam a madeira do carro, e ofereceram as vacas ao Senhor em holocausto.' },
      { v: 15, en: 'The Levites took down Yahweh’s ark, and the coffer that was with it, in which the jewels of gold were, and put them on the great stone; and the men of Beth Shemesh offered burnt offerings and sacrificed sacrifices the same day to Yahweh.', pt: 'Nisso os levitas desceram a arca do Senhor, como também o cofre que estava junto a ela, em que se achavam as jóias de ouro, e puseram-nos sobre aquela grande pedra; e no mesmo dia os homens de Bete-Semes ofereceram holocaustos e sacrifícios ao Senhor.' },
      { v: 16, en: 'When the five lords of the Philistines had seen it, they returned to Ekron the same day.', pt: 'E os cinco chefes dos filisteus, tendo visto aquilo, voltaram para Ecrom no mesmo dia.' },
      { v: 17, en: 'These are the golden tumors which the Philistines returned for a trespass offering to Yahweh: for Ashdod one, for Gaza one, for Ashkelon one, for Gath one, for Ekron one;', pt: 'Estes, pois, são os tumores de ouro que os filisteus enviaram ao Senhor como oferta pela culpa: por Asdode um, por Gaza outro, por Asquelom outro, por Gate outro, por Ecrom outro.' },
      { v: 18, en: 'and the golden mice, according to the number of all the cities of the Philistines belonging to the five lords, both of fortified cities and of country villages, even to the great stone, on which they set down Yahweh’s ark. That stone remains to this day in the field of Joshua of Beth Shemesh.', pt: 'Como também os ratos de ouro, segundo o número de todas as cidades dos filisteus, pertencentes aos cinco chefes, desde as cidades fortificadas até as aldeias campestres. Disso é testemunha a grande pedra sobre a qual puseram a arca do Senhor, pedra que ainda está até o dia de hoje no campo de Josué, o bete-semita.' },
      { v: 19, en: 'He struck of the men of Beth Shemesh, because they had looked into Yahweh’s ark, he struck fifty thousand seventy of the men. Then the people mourned, because Yahweh had struck the people with a great slaughter.', pt: 'Ora, o Senhor feriu os homens de Bete-Semes, porquanto olharam para dentro da arca do Senhor; feriu do povo cinqüenta mil e setenta homens; então o povo se entristeceu, porque o Senhor o ferira com tão grande morticínio.' },
      { v: 20, en: 'The men of Beth Shemesh said, “Who is able to stand before Yahweh, this holy God? To whom shall he go up from us?”', pt: 'Disseram os homens de Bete-Semes: Quem poderia subsistir perante o Senhor, este Deus santo? e para quem subirá de nós?' },
      { v: 21, en: 'They sent messengers to the inhabitants of Kiriath Jearim, saying, “The Philistines have brought back Yahweh’s ark. Come down, and bring it up to yourselves.”', pt: 'Enviaram, pois, mensageiros aos habitantes de Quiriate-Jearim, para lhes dizerem: Os filisteus remeteram a arca do Senhor; descei, e fazei-a subir para vós.' },
    ],
    7: [
      { v: 1, en: 'The men of Kiriath Jearim came, and took Yahweh’s ark, and brought it into Abinadab’s house on the hill, and consecrated Eleazar his son to keep Yahweh’s ark.', pt: 'Vieram, pois, os homens de Quiriate-Jearim, tomaram a arca do Senhor e a levaram à casa de Abinadabe, no outeiro; e consagraram a Eleazar, filho dele, para que guardasse a arca da Senhor.' },
      { v: 2, en: 'From the day that the ark stayed in Kiriath Jearim, the time was long; for it was twenty years; and all the house of Israel lamented after Yahweh.', pt: 'E desde e dia em que a arca ficou em Queriate-Jearim passou-se muito tempo, chegando até vinte anos; então toda a casa de Israel suspirou pelo Senhor.' },
      { v: 3, en: 'Samuel spoke to all the house of Israel, saying, “If you are returning to Yahweh with all your heart, then put away the foreign gods and the Ashtaroth from among you, and direct your hearts to Yahweh, and serve him only; and he will deliver you out of the hand of the Philistines.”', pt: 'Samuel, pois, falou a toda a casa de Israel, dizendo: Se de todo o vosso coração voltais para o Senhor, lançai do meio de vós os deuses estranhos e as astarotes, preparai o vosso coração para com o Senhor, e servi a ele só; e ele vos livrará da mão dos filisteus.' },
      { v: 4, en: 'Then the children of Israel removed the Baals and the Ashtaroth, and served Yahweh only.', pt: 'Os filhos de Israel, pois, lançaram do meio deles os baalins e as astarotes, e serviram so ao Senhor.' },
      { v: 5, en: 'Samuel said, “Gather all Israel to Mizpah, and I will pray to Yahweh for you.”', pt: 'Disse mais Samuel: Congregai a todo o Israel em Mizpá, e orarei por vós ao Senhor.' },
      { v: 6, en: 'They gathered together to Mizpah, and drew water, and poured it out before Yahweh, and fasted on that day, and said there, “We have sinned against Yahweh.” Samuel judged the children of Israel in Mizpah.', pt: 'Congregaram-se, pois, em Mizpá, tiraram água e a derramaram perante o Senhor; jejuaram aquele dia, e ali disseram: Pecamos contra o Senhor. E Samuel julgava os filhos de Israel em Mizpá.' },
      { v: 7, en: 'When the Philistines heard that the children of Israel were gathered together at Mizpah, the lords of the Philistines went up against Israel. When the children of Israel heard it, they were afraid of the Philistines.', pt: 'Quando os filisteus ouviram que os filhos de Israel estavam congregados em Mizpá, subiram os chefes dos filisteus contra Israel. Ao saberem disto os filhos de Israel, temeram por causa dos filisteus.' },
      { v: 8, en: 'The children of Israel said to Samuel, “Don’t stop crying to Yahweh our God for us, that he will save us out of the hand of the Philistines.”', pt: 'Pelo que disseram a Samuel: Não cesses de clamar ao Senhor nosso Deus por nós, para que nos livre da mão dos filisteus.' },
      { v: 9, en: 'Samuel took a suckling lamb, and offered it for a whole burnt offering to Yahweh. Samuel cried to Yahweh for Israel; and Yahweh answered him.', pt: 'Então tomou Samuel um cordeiro de mama, e o ofereceu inteiro em holocausto ao Senhor; e Samuel clamou ao Senhor por Israel, e o Senhor o atendeu.' },
      { v: 10, en: 'As Samuel was offering up the burnt offering, the Philistines came near to battle against Israel; but Yahweh thundered with a great thunder on that day on the Philistines, and confused them; and they were struck down before Israel.', pt: 'Enquanto Samuel oferecia o holocausto, os filisteus chegaram para pelejar contra Israel; mas o Senhor trovejou naquele dia com grande estrondo sobre os filisteus, e os aterrou; de modo que foram derrotados diante dos filhos de Israel.' },
      { v: 11, en: 'The men of Israel went out of Mizpah, and pursued the Philistines, and struck them, until they came under Beth Kar.', pt: 'Os homens de Israel, saindo de Mizpá, perseguiram os filisteus e os feriram até abaixo de Bete-Car.' },
      { v: 12, en: 'Then Samuel took a stone, and set it between Mizpah and Shen, and called its name Ebenezer, saying, “Yahweh helped us until now.”', pt: 'Então Samuel tomou uma pedra, e a pôs entre Mizpá e Sem, e lhe chamou Ebenézer; e disse: Até aqui nos ajudou o Senhor.' },
      { v: 13, en: 'So the Philistines were subdued, and they stopped coming within the border of Israel. Yahweh’s hand was against the Philistines all the days of Samuel.', pt: 'Assim os filisteus foram subjugados, e não mais vieram aos termos de Israel, porquanto a mão do Senhor foi contra os filisteus todos os dias de Samuel.' },
      { v: 14, en: 'The cities which the Philistines had taken from Israel were restored to Israel, from Ekron even to Gath; and Israel recovered its border out of the hand of the Philistines. There was peace between Israel and the Amorites.', pt: 'E as cidades que os filisteus tinham tomado a Israel lhe foram restituídas, desde Ecrom até Gate, cujos termos também Israel arrebatou da mão dos filisteus. E havia paz entre Israel e os amorreus.' },
      { v: 15, en: 'Samuel judged Israel all the days of his life.', pt: 'Samuel julgou a Israel todos os dias da sua vida.' },
      { v: 16, en: 'He went from year to year in a circuit to Bethel, Gilgal, and Mizpah; and he judged Israel in all those places.', pt: 'De ano em ano rodeava por Betel, Gilgal e Mizpá, julgando a Israel em todos esses lugares.' },
      { v: 17, en: 'His return was to Ramah, for his house was there; and he judged Israel there; and he built an altar to Yahweh there.', pt: 'Depois voltava a Ramá, onde estava a sua casa, e ali julgava a Israel; e edificou ali um altar ao Senhor.' },
    ],
    8: [
      { v: 1, en: 'When Samuel was old, he made his sons judges over Israel.', pt: 'Ora, havendo Samuel envelhecido, constituiu a seus filhos por juízes sobre Israel.' },
      { v: 2, en: 'Now the name of his firstborn was Joel; and the name of his second, Abijah. They were judges in Beersheba.', pt: 'O seu filho primogênito chamava-se Joel, e o segundo Abias; e julgavam em Berseba.' },
      { v: 3, en: 'His sons didn’t walk in his ways, but turned away after dishonest gain, took bribes, and perverted justice.', pt: 'Seus filhos, porém, não andaram nos caminhos dele, mas desviaram-se após o lucro e, recebendo peitas, perverteram a justiça.' },
      { v: 4, en: 'Then all the elders of Israel gathered themselves together and came to Samuel to Ramah.', pt: 'Então todos os anciãos de Israel se congregaram, e vieram ter com Samuel, a Ramá,' },
      { v: 5, en: 'They said to him, “Behold, you are old, and your sons don’t walk in your ways. Now make us a king to judge us like all the nations.”', pt: 'e lhe disseram: Eis que já estás velho, e teus filhos não andam nos teus caminhos. Constitui-nos, pois, agora um rei para nos julgar, como o têm todas as nações.' },
      { v: 6, en: 'But the thing displeased Samuel, when they said, “Give us a king to judge us.” Samuel prayed to Yahweh.', pt: 'Mas pareceu mal aos olhos de Samuel, quando disseram: Dá-nos um rei para nos julgar. Então Samuel orou ao Senhor.' },
      { v: 7, en: 'Yahweh said to Samuel, “Listen to the voice of the people in all that they tell you; for they have not rejected you, but they have rejected me as the king over them.', pt: 'Disse o Senhor a Samuel: Ouve a voz do povo em tudo quanto te dizem, pois não é a ti que têm rejeitado, porém a mim, para que eu não reine sobre eles.' },
      { v: 8, en: 'According to all the works which they have done since the day that I brought them up out of Egypt even to this day, in that they have forsaken me, and served other gods, so they also do to you.', pt: 'Conforme todas as obras que fizeram desde o dia em que os tirei do Egito até o dia de hoje, deixando-me a mim e servindo a outros deuses, assim também fazem a ti.' },
      { v: 9, en: 'Now therefore listen to their voice. However you shall protest solemnly to them, and shall show them the way of the king who will reign over them.”', pt: 'Agora, pois, ouve a sua voz, contudo lhes protestarás solenemente, e lhes declararás qual será o modo de agir do rei que houver de reinar sobre eles.' },
      { v: 10, en: 'Samuel told all Yahweh’s words to the people who asked him for a king.', pt: 'Referiu, pois, Samuel todas as palavras do Senhor ao povo, que lhe havia pedido um rei,' },
      { v: 11, en: 'He said, “This will be the way of the king who shall reign over you: he will take your sons, and appoint them as his servants, for his chariots, and to be his horsemen; and they will run before his chariots.', pt: 'e disse: Este será o modo de agir do rei que houver de reinar sobre vós: tomará os vossos filhos, e os porá sobre os seus carros, e para serem seus cavaleiros, e para correrem adiante dos seus carros;' },
      { v: 12, en: 'He will appoint them to him for captains of thousands, and captains of fifties; and he will assign some to plow his ground, and to reap his harvest, and to make his instruments of war, and the instruments of his chariots.', pt: 'e os porá por chefes de mil e chefes de cinqüenta, para lavrarem os seus campos, fazerem as suas colheitas e fabricarem as suas armas de guerra e os petrechos de seus carros.' },
      { v: 13, en: 'He will take your daughters to be perfumers, to be cooks, and to be bakers.', pt: 'Tomará as vossas filhas para perfumistas, cozinheiras e padeiras.' },
      { v: 14, en: 'He will take your fields, your vineyards, and your olive groves, even their best, and give them to his servants.', pt: 'Tomará o melhor das vossas terras, das vossas vinhas e dos vossos elivais, e o dará aos seus servos.' },
      { v: 15, en: 'He will take one tenth of your seed, and of your vineyards, and give it to his officers, and to his servants.', pt: 'Tomará e dízimo das vossas sementes e das vossas vinhas, para dar aos seus oficiais e aos seus servos.' },
      { v: 16, en: 'He will take your male servants, your female servants, your best young men, and your donkeys, and assign them to his own work.', pt: 'Também os vossos servos e as vossas servas, e os vossos melhores mancebos, e os vossos jumentos tomará, e os empregará no seu trabalho.' },
      { v: 17, en: 'He will take one tenth of your flocks; and you will be his servants.', pt: 'Tomará o dízimo do vosso rebanho; e vós lhe servireis de escravos.' },
      { v: 18, en: 'You will cry out in that day because of your king whom you will have chosen for yourselves; and Yahweh will not answer you in that day.”', pt: 'Então naquele dia clamareis por causa de vosso rei, que vós mesmos houverdes escolhido; mas o Senhor não vos ouvira.' },
      { v: 19, en: 'But the people refused to listen to the voice of Samuel; and they said, “No; but we will have a king over us,', pt: 'O povo, porém, não quis ouvir a voz de Samuel; e disseram: Não, mas haverá sobre nós um rei,' },
      { v: 20, en: 'that we also may be like all the nations, and that our king may judge us, and go out before us, and fight our battles.”', pt: 'para que nós também sejamos como todas as outras nações, e para que o nosso rei nos julgue, e saia adiante de nós, e peleje as nossas batalhas.' },
      { v: 21, en: 'Samuel heard all the words of the people, and he rehearsed them in the ears of Yahweh.', pt: 'Ouviu, pois, Samuel todas as palavras do povo, e as repetiu aos ouvidos do Senhor.' },
      { v: 22, en: 'Yahweh said to Samuel, “Listen to their voice, and make them a king.” Samuel said to the men of Israel, “Everyone go to your own city.”', pt: 'Disse o Senhor a Samuel: Dá ouvidos à sua voz, e constitui-lhes rei. Então Samuel disse aos homens de Israel: Volte cada um para a sua cidade.' },
    ],
    9: [
      { v: 1, en: 'Now there was a man of Benjamin, whose name was Kish, the son of Abiel, the son of Zeror, the son of Becorath, the son of Aphiah, the son of a Benjamite, a mighty man of valor.', pt: 'Ora, havia um homem de Benjamim, cujo nome era Quis, filho de Abiel, filho de Zeror, filho de Becorate, filho de Afias, filho dum benjamita; era varão forte e valoroso.' },
      { v: 2, en: 'He had a son, whose name was Saul, an impressive young man; and there was not among the children of Israel a better person than he. From his shoulders and upward he was taller than any of the people.', pt: 'Tinha este um filho, chamado Saul, jovem e tão belo que entre os filhos de Israel não havia outro homem mais belo de que ele; desde os ombros para cima sebressaía em altura a todo o povo.' },
      { v: 3, en: 'The donkeys of Kish, Saul’s father, were lost. Kish said to Saul his son, “Take now one of the servants with you, and arise, go look for the donkeys.”', pt: 'Tinham-se perdido as jumentas de Quis, pai de Saul; pelo que disse Quis a Saul, seu filho: Toma agora contigo um dos moços, levanta-te e vai procurar as jumentas.' },
      { v: 4, en: 'He passed through the hill country of Ephraim, and passed through the land of Shalishah, but they didn’t find them. Then they passed through the land of Shaalim, and there they weren’t there. Then he passed through the land of the Benjamites, but they didn’t find them.', pt: 'Passaram, pois, pela região montanhosa de Efraim, como também pela terra e Salisa, mas não as acharam; depois passaram pela terra de Saalim, porém tampouco estavam ali; passando ainda pela terra de Benjamim, não as acharam.' },
      { v: 5, en: 'When they had come to the land of Zuph, Saul said to his servant who was with him, “Come, and let us return, lest my father stop caring about the donkeys, and be anxious for us.”', pt: 'Vindo eles, então, à terra de Zufe, Saul disse para o moço que ia com ele: Vem! Voltemos, para que não suceda que meu pai deixe de inquietar-se pelas jumentas e se aflija por causa de nós.' },
      { v: 6, en: 'The servant said to him, “Behold now, there is in this city a man of God, and he is a man who is held in honor. All that he says surely happens. Now let us go there. Perhaps he can tell us which way to go.”', pt: 'Mas ele lhe disse: Eis que há nesta cidade um homem de Deus, e ele é muito considerado; tudo quanto diz, sucede infalivelmente. Vamos, pois, até lá; porventura nos mostrará o caminho que devemos seguir.' },
      { v: 7, en: 'Then Saul said to his servant, “But, behold, if we go, what should we bring the man? For the bread is spent in our sacks, and there is not a present to bring to the man of God. What do we have?”', pt: 'Então Saul disse ao seu moço: Porém se lá formos, que levaremos ao homem? Pois o pão de nossos alforjes se acabou, e presente nenhum temos para levar ao homem de Deus; que temos?' },
      { v: 8, en: 'The servant answered Saul again, and said, “Behold, I have in my hand the fourth part of a shekel of silver. I will give that to the man of God, to tell us our way.”', pt: 'O moço tornou a responder a Saul, e disse: Eis que ainda tenho em mão um quarto dum siclo de prata, o qual darei ao homem de Deus, para que nos mostre o caminho.' },
      { v: 9, en: '(In earlier times in Israel, when a man went to inquire of God, he said, “Come, and let us go to the seer”; for he who is now called a prophet was before called a seer.)', pt: '(Antigamente em Israel, indo alguém consultar a Deus, dizia assim: Vinde, vamos ao vidente; porque ao profeta de hoje, outrora se chamava vidente.)' },
      { v: 10, en: 'Then Saul said to his servant, “Well said. Come, let us go.” So they went to the city where the man of God was.', pt: 'Então disse Saul ao moço: Dizes bem; vem, pois, vamos! E foram-se à cidade onde estava e homem de Deus.' },
      { v: 11, en: 'As they went up the ascent to the city, they found young maidens going out to draw water, and said to them, “Is the seer here?”', pt: 'Quando eles iam subindo à cidade, encontraram umas moças que saíam para tirar água; e perguntaram-lhes: Está aqui o vidente?' },
      { v: 12, en: 'They answered them, and said, “He is. Behold, he is before you. Hurry now, for he has come today into the city; for the people have a sacrifice today in the high place.', pt: 'Ao que elas lhes responderam: Sim, eis aí o tens diante de ti; apressa-te, porque hoje veio à cidade, porquanto o povo tem hoje sacrifício no alto.' },
      { v: 13, en: 'As soon as you have come into the city, you will immediately find him, before he goes up to the high place to eat; for the people will not eat until he come, because he blesses the sacrifice. Afterwards those who are invited eat. Now therefore go up; for at this time you will find him.”', pt: 'Entrando vós na cidade, logo o achareis, antes que ele suba ao alto para comer; pois o povo não comerá até que ele venha, porque ele é o que abençoa a sacrifício, e depois os convidados comem. Subi agora, porque a esta hora o achareis.' },
      { v: 14, en: 'They went up to the city. As they came within the city, behold, Samuel came out toward them, to go up to the high place.', pt: 'Subiram, pois, à cidade; e, ao entrarem, eis que Samuel os encontrou, quando saía para subir ao alto.' },
      { v: 15, en: 'Now Yahweh had revealed to Samuel a day before Saul came, saying,', pt: 'Ora, o Senhor revelara isto aos ouvidos de Samuel, um dia antes de Saul chegar, dizendo:' },
      { v: 16, en: '“Tomorrow about this time I will send you a man out of the land of Benjamin, and you shall anoint him to be prince over my people Israel. He will save my people out of the hand of the Philistines; for I have looked upon my people, because their cry has come to me.”', pt: 'Amanhã a estas horas te enviarei um homem da terra de Benjamim, o qual ungirás por príncipe sobre o meu povo de Israel; e ele livrará o meu povo da mão dos filisteus; pois olhei para o meu povo, porque o seu clamor chegou a mim.' },
      { v: 17, en: 'When Samuel saw Saul, Yahweh said to him, “Behold, the man of whom I spoke to you! He will have authority over my people.”', pt: 'E quando Samuel viu a Saul, o Senhor e disse: Eis aqui o homem de quem eu te falei. Este dominará sobre o meu povo.' },
      { v: 18, en: 'Then Saul approached Samuel in the gateway, and said, “Please tell me where the seer’s house is.”', pt: 'Então Saul se chegou a Samuel na porta, e disse: Mostra-me, peço-te, onde é a casa do vidente.' },
      { v: 19, en: 'Samuel answered Saul, and said, “I am the seer. Go up before me to the high place, for you are to eat with me today. In the morning I will let you go, and will tell you all that is in your heart.', pt: 'Respondeu Samuel a Saul: Eu sou o vidente; sobe diante de mim ao alto, porque comereis hoje comigo; pela manhã te despedirei, e tudo quanto está no teu coração to declararei.' },
      { v: 20, en: 'As for your donkeys who were lost three days ago, don’t set your mind on them; for they have been found. For whom is all that is desirable in Israel? Is it not for you, and for all your father’s house?”', pt: 'Também quanto às jumentas que há três dias se te perderam, não te preocupes com elas, porque já foram achadas. Mas para quem é tudo o que é desejável em Israel? porventura não é para ti, e para toda a casa de teu pai?' },
      { v: 21, en: 'Saul answered, “Am I not a Benjamite, of the smallest of the tribes of Israel? And my family the least of all the families of the tribe of Benjamin? Why then do you speak to me like this?”', pt: 'Então respondeu Saul: Acaso não sou eu benjamita, da menor das tribos de Israel? E não é a minha família a menor de todas as famílias da tribo de Benjamim? Por que, pois, me falas desta maneira?' },
      { v: 22, en: 'Samuel took Saul and his servant, and brought them into the guest room, and made them sit in the best place among those who were invited, who were about thirty persons.', pt: 'Samuel, porém, tomando a Saul e ao seu moço, levou-os à câmara, e deu-lhes o primeiro lugar entre os convidados, que eram cerca de trinta homens.' },
      { v: 23, en: 'Samuel said to the cook, “Bring the portion which I gave you, of which I said to you, ‘Set it aside.’”', pt: 'Depois disse Samuel ao cozinheiro: Traze a porção que te dei, da qual te disse: põe-na à parte contigo.' },
      { v: 24, en: 'The cook took up the thigh, and that which was on it, and set it before Saul. Samuel said, “Behold, that which has been reserved! Set it before yourself and eat; because for the appointed time has it been kept for you, for I said, ‘I have invited the people.’” So Saul ate with Samuel that day.', pt: 'Levantou, pois, o cozinheiro a espádua, com o que havia nela, e pô-la diante de Saul. E disse Samuel: Eis que o que foi reservado está diante de ti. Come; porque te foi guardado para esta ocasião, para que o comesses com os convidados. Assim comeu Saul naquele dia com Samuel.' },
      { v: 25, en: 'When they had come down from the high place into the city, he talked with Saul on the housetop.', pt: 'Então desceram do alto para a cidade, e falou Samuel com Saul, no eirado.' },
      { v: 26, en: 'They arose early; and about daybreak, Samuel called to Saul on the housetop, saying, “Get up, that I may send you away.” Saul arose, and they both went outside, he and Samuel, together.', pt: 'E se levantaram de madrugada, quase ao subir da alva, pois Samuel chamou a Saul, que estava no eirado, dizendo: Levanta-te para eu te despedir. Levantou-se, pois, Saul, e sairam ambos, ele e Samuel.' },
      { v: 27, en: 'As they were going down at the end of the city, Samuel said to Saul, “Tell the servant to go on ahead of us.” He went ahead, then Samuel said, “But stand still first, that I may cause you to hear God’s message.”', pt: 'Quando desciam para a extremidade da cidade, Samuel disse a Saul: Dize ao moço que passe adiante de nós (e ele passou); tu, porém, espera aqui, e te farei ouvir a palavra de Deus.' },
    ],
    10: [
      { v: 1, en: 'Then Samuel took the vial of oil, and poured it on his head, and kissed him, and said, “Hasn’t Yahweh anointed you to be prince over his inheritance?', pt: 'Então Samuel tomou um vaso de azeite, e o derramou sobre a cabeça de Saul, e o beijou, e disse: Porventura não te ungiu o Senhor para ser príncipe sobre a sua herança?' },
      { v: 2, en: 'When you have departed from me today, then you will find two men by Rachel’s tomb, on the border of Benjamin at Zelzah. They will tell you, ‘The donkeys which you went to look for have been found; and behold, your father has stopped caring about the donkeys, and is anxious for you, saying, “What shall I do for my son?”’', pt: 'Quando te apartares hoje de mim, encontrarás dois homens junto ao sepulcro de Raquel, no termo de Benjamim, em Zelza, os quais te dirão: Acharam-se as jumentas que foste buscar, e eis que já o teu pai deixou de pensar nas jumentas, e anda aflito por causa de ti, dizendo: Que farei eu por meu filho?' },
      { v: 3, en: '“Then you will go on forward from there, and you will come to the oak of Tabor. Three men will meet you there going up to God to Bethel, one carrying three young goats, and another carrying three loaves of bread, and another carrying a bottle of wine.', pt: 'Então dali passarás mais adiante, e chegarás ao carvalho de Tabor; ali te encontrarão três homens, que vão subindo a Deus, a Betel, levando um três cabritos, outro três formas de pão, e o outro um odre de vinho.' },
      { v: 4, en: 'They will greet you, and give you two loaves of bread, which you shall receive from their hand.', pt: 'Eles te saudarão, e te darão dois pães, que receberás das mãos deles.' },
      { v: 5, en: '“After that you will come to the hill of God, where the garrison of the Philistines is; and it will happen, when you have come there to the city, that you will meet a band of prophets coming down from the high place with a lute, a tambourine, a pipe, and a harp before them; and they will be prophesying.', pt: 'Depois chegarás ao outeiro de Deus, onde está a guarnição dos filisteus; ao entrares ali na cidade, encontrarás um grupo de profetas descendo do alto, precedido de saltérios, tambores, flautas e harpas, e eles profetizando.' },
      { v: 6, en: 'Then Yahweh’s Spirit will come mightily on you, and you will prophesy with them, and will be turned into another man.', pt: 'E o Espírito do Senhor se apoderará de ti, e profetizarás com eles, e serás transformado em outro homem.' },
      { v: 7, en: 'Let it be, when these signs have come to you, that you do what is appropriate for the occasion; for God is with you.', pt: 'Quando estes sinais te vierem, faze o que achar a tua mão para fazer, pois Deus é contigo.' },
      { v: 8, en: '“Go down ahead of me to Gilgal; and behold, I will come down to you, to offer burnt offerings, and to sacrifice sacrifices of peace offerings. Wait seven days, until I come to you, and show you what you are to do.”', pt: 'Tu, porém, descerás adiante de mim a Gilgal, e eis que eu descerei a ter contigo, para oferecer holocaustos e sacrifícios de ofertas pacíficas. Esperarás sete dias, até que eu vá ter contigo e te declare o que hás de fazer.' },
      { v: 9, en: 'It was so, that when he had turned his back to go from Samuel, God gave him another heart; and all those signs happened that day.', pt: 'Ao virar Saul as costas para se apartar de Samuel, Deus lhe mudou o coração em outro; e todos esses sinais aconteceram naquele mesmo dia.' },
      { v: 10, en: 'When they came there to the hill, behold, a band of prophets met him; and the Spirit of God came mightily on him, and he prophesied among them.', pt: 'Quando eles iam chegando ao outeiro, eis que um grupo de profetas lhes saiu ao encontro; e o Espírito de Deus se apoderou de Saul, e ele profetizou no meio deles.' },
      { v: 11, en: 'When all who knew him before saw that, behold, he prophesied with the prophets, then the people said to one another, “What is this that has come to the son of Kish? Is Saul also among the prophets?”', pt: 'Todos os que o tinham conhecido antes, ao verem que ele profetizava com os profetas, diziam uns aos outros: Que é que sucedeu ao filho de Quis? Está também Saul entre os profetas?' },
      { v: 12, en: 'One of the same place answered, “Who is their father?” Therefore it became a proverb, “Is Saul also among the prophets?”', pt: 'Então um homem dali respondeu, e disse: Pois quem é o pai deles? Pelo que se tornou em provérbio: Está também Saul entre os profetas?' },
      { v: 13, en: 'When he had finished prophesying, he came to the high place.', pt: 'Tendo ele acabado de profetizar, foi ao alto.' },
      { v: 14, en: 'Saul’s uncle said to him and to his servant, “Where did you go?” He said, “To seek the donkeys. When we saw that they were not found, we came to Samuel.”', pt: 'Depois o tio de Saul perguntou-lhe, a ele e ao seu moço: Aonde fostes?: Respondeu ele: Procurar as jumentas; e, não as tendo encontrado, fomos ter com Samuel.' },
      { v: 15, en: 'Saul’s uncle said, “Please tell me what Samuel said to you.”', pt: 'Disse mais o tio de Saul: Declara-me, peço-te, o que vos disse Samuel.' },
      { v: 16, en: 'Saul said to his uncle, “He told us plainly that the donkeys were found.” But concerning the matter of the kingdom, of which Samuel spoke, he didn’t tell him.', pt: 'Ao que respondeu Saul a seu tio: Declarou-nos, seguramente, que as jumentas tinham sido encontradas. Mas quanto ao assunto do reino, de que Samuel falara, nada lhe declarou.' },
      { v: 17, en: 'Samuel called the people together to Yahweh to Mizpah;', pt: 'Então Samuel convocou o povo ao Senhor em Mizpá;' },
      { v: 18, en: 'and he said to the children of Israel, “Yahweh, the God of Israel, says ‘I brought Israel up out of Egypt, and I delivered you out of the hand of the Egyptians, and out of the hand of all the kingdoms that oppressed you.’', pt: 'e disse aos filhos de Israel: Assim diz o Senhor Deus de Israel: Eu fiz subir a Israel do Egito, e vos livrei da mão dos egípcios e da mão de todos os reinos que vos oprimiam.' },
      { v: 19, en: 'But you have today rejected your God, who himself saves you out of all your calamities and your distresses; and you have said to him, ‘No! Set a king over us.’ Now therefore present yourselves before Yahweh by your tribes, and by your thousands.”', pt: 'Mas vós hoje rejeitastes a vosso Deus, àquele que vos livrou de todos os vossos males e angústias, e lhe dissestes: Põe um rei sobre nós. Agora, pois, ponde-vos perante o Senhor, segundo as vossas tribos e segundo os vossos milhares.' },
      { v: 20, en: 'So Samuel brought all the tribes of Israel near, and the tribe of Benjamin was chosen.', pt: 'Tendo, pois, Samuel feito chegar todas as tribos de Israel, foi tomada por sorte a tribo de Benjamim.' },
      { v: 21, en: 'He brought the tribe of Benjamin near by their families; and the family of the Matrites was chosen. Then Saul the son of Kish was chosen; but when they looked for him, he could not be found.', pt: 'E, quando fez chegar a tribo de Benjamim segundo as suas famílias, foi tomada a família de Matri, e dela foi tomado Saul, filho de Quis; e o procuraram, mas não foi encontrado.' },
      { v: 22, en: 'Therefore they asked of Yahweh further, “Is there yet a man to come here?” Yahweh answered, “Behold, he has hidden himself among the baggage.”', pt: 'Pelo que tornaram a perguntar ao Senhor: Não veio o homem ainda para cá? E respondeu o Senhor: Eis que se escondeu por entre a bagagem:' },
      { v: 23, en: 'They ran and got him there. When he stood among the people, he was higher than any of the people from his shoulders and upward.', pt: 'Correram, pois, e o trouxeram dali; e estando ele no meio do povo, sobressaía em altura a todo o povo desde os ombros para cima.' },
      { v: 24, en: 'Samuel said to all the people, “Do you see him whom Yahweh has chosen, that there is no one like him among all the people?” All the people shouted, and said, “Long live the king!”', pt: 'Então disse Samuel a todo o povo: Vedes já a quem o Senhor escolheu: Não há entre o povo nenhum semelhante a ele. Então todo o povo o aclamou, dizendo: Viva o rei;' },
      { v: 25, en: 'Then Samuel told the people the regulations of the kingdom, and wrote it in a book, and laid it up before Yahweh. Samuel sent all the people away, every man to his house.', pt: 'Também declarou Samuel ao povo a lei do reino, e a escreveu num livro, e pô-lo perante o Senhor. Então Samuel despediu todo o povo, cada um para sua casa.' },
      { v: 26, en: 'Saul also went to his house to Gibeah; and the army went with him, whose hearts God had touched.', pt: 'E foi também Saul para sua casa em Gibeá; e foram com ele homens de valor, aqueles cujo coração Deus tocara.' },
      { v: 27, en: 'But certain worthless fellows said, “How could this man save us?” They despised him, and brought him no present. But he held his peace.', pt: 'Mas alguns homens ímpios disseram: Como pode este homem nos livrar? E o desprezaram, e não lhe trouxeram presentes; porém ele se fez como surdo.' },
    ],
    11: [
      { v: 1, en: 'Then Nahash the Ammonite came up, and encamped against Jabesh Gilead: and all the men of Jabesh said to Nahash, “Make a covenant with us, and we will serve you.”', pt: 'Então subiu Naás, o amonita, e sitiou a Jabes-Gileade. E disseram todos os homens de Jabes a Naás: Faze aliança conosco, e te serviremos.' },
      { v: 2, en: 'Nahash the Ammonite said to them, “On this condition I will make it with you, that all your right eyes be gouged out. I will make this dishonor all Israel.”', pt: 'Respondeu-lhes, porém, Naás, o amonita: Com esta condição farei aliança convosco: que a todos vos arranque o olho direito; assim porei opróbrio sobre todo o Israel.' },
      { v: 3, en: 'The elders of Jabesh said to him, “Give us seven days, that we may send messengers to all the borders of Israel; and then, if there is no one to save us, we will come out to you.”', pt: 'Ao que os anciãos de Jabes lhe disseram: Concede-nos sete dias, para que enviemos mensageiros por todo o território de Israel; e, não havendo ninguém que nos livre, entregar-nos-emos a ti.' },
      { v: 4, en: 'Then the messengers came to Gibeah of Saul, and spoke these words in the ears of the people, then all the people lifted up their voice, and wept.', pt: 'Então, vindo os mensageiros a Gibeá de Saul, falaram estas palavras aos ouvidos do povo. Pelo que todo o povo levantou a voz e chorou.' },
      { v: 5, en: 'Behold, Saul came following the oxen out of the field; and Saul said, “What ails the people that they weep?” They told him the words of the men of Jabesh.', pt: 'E eis que Saul vinha do campo, atrás dos bois; e disse Saul: Que tem o povo, que chega? E contaram-lhe as palavras dos homens de Jabes.' },
      { v: 6, en: 'God’s Spirit came mightily on Saul when he heard those words, and his anger burned hot.', pt: 'Então o Espírito de Deus se apoderou de Saul, ao ouvir ele estas palavras; e acendeu-se sobremaneira a sua ira.' },
      { v: 7, en: 'He took a yoke of oxen, and cut them in pieces, and sent them throughout all the borders of Israel by the hand of messengers, saying, “Whoever doesn’t come out after Saul and after Samuel, so shall it be done to his oxen.” The dread of Yahweh fell on the people, and they came out as one man.', pt: 'Tomou ele uma junta de bois, cortou-os em pedaços, e os enviou por todo o território de Israel por mãos de mensageiros, dizendo: Qualquer que não sair após Saul e após Samuel, assim se fará aos seus bois. Então caiu o temor do Senhor sobre o povo, e acudiram como um só homem.' },
      { v: 8, en: 'He counted them in Bezek; and the children of Israel were three hundred thousand, and the men of Judah thirty thousand.', pt: 'Saul passou-lhes revista em Bezeque; e havia dos homens de Israel trezentos mil, e dos homens de Judá trinta mil.' },
      { v: 9, en: 'They said to the messengers who came, “Tell the men of Jabesh Gilead, ‘Tomorrow, by the time the sun is hot, you will be rescued.’” The messengers came and told the men of Jabesh; and they were glad.', pt: 'Então disseram aos mensageiros que tinham vindo: Assim direis aos homens de Jabes-Gileade: Amanhã, em aquentando o sol, vos virá livramento. Vindo, pois, os mensageiros, anunciaram-no aos homens de Jabes, os quais se alegraram.' },
      { v: 10, en: 'Therefore the men of Jabesh said, “Tomorrow we will come out to you, and you shall do with us all that seems good to you.”', pt: 'E os homens de Jabes disseram aos amonitas: Amanhã nos entregaremos a vós; então nos fareis conforme tudo o que bem vos parecer.' },
      { v: 11, en: 'On the next day, Saul put the people in three companies; and they came into the middle of the camp in the morning watch, and struck the Ammonites until the heat of the day. Those who remained were scattered, so that no two of them were left together.', pt: 'Ao outro dia Saul dividiu o povo em três companhias; e pela vigília da manhã vieram ao meio do arraial, e feriram aos amonitas até que o dia aquentou; e sucedeu que os restantes se espalharam de modo a não ficarem dois juntos.' },
      { v: 12, en: 'The people said to Samuel, “Who is he who said, ‘Shall Saul reign over us?’ Bring those men, that we may put them to death!”', pt: 'Então disse o povo a Samuel: Quais são os que diziam: Reinará porventura Saul sobre nós? Dai cá esses homens, para que os matemos.' },
      { v: 13, en: 'Saul said, “No man shall be put to death today; for today Yahweh has rescued Israel.”', pt: 'Saul, porém, disse: Hoje não se há de matar ninguém, porque neste dia o senhor operou um livramento em Israel:' },
      { v: 14, en: 'Then Samuel said to the people, “Come, and let us go to Gilgal, and renew the kingdom there.”', pt: 'Depois disse Samuel ao povo: Vinde, vamos a Gilgal, e renovemos ali o reino.' },
      { v: 15, en: 'All the people went to Gilgal; and there they made Saul king before Yahweh in Gilgal. There they offered sacrifices of peace offerings before Yahweh; and there Saul and all the men of Israel rejoiced greatly.', pt: 'Foram, pois, para Gilgal, onde constituíram rei a Saul perante o Senhor, e imolaram sacrifícios de ofertas pacíficas perante o Senhor; e ali Saul se alegrou muito com todos os homens de Israel.' },
    ],
    12: [
      { v: 1, en: 'Samuel said to all Israel, “Behold, I have listened to your voice in all that you said to me, and have made a king over you.', pt: 'Então disse Samuel a todo o Israel: Eis que vos dei ouvidos em tudo quanto me dissestes, e constituí sobre vós um rei.' },
      { v: 2, en: 'Now, behold, the king walks before you. I am old and gray-headed. Behold, my sons are with you. I have walked before you from my youth to this day.', pt: 'Agora, eis que o rei vai adiante de vós; quanto a mim, já sou velho e encanecido, e meus filhos estão convosco: eu tenho andado adiante de vós desde a minha mocidade até o dia de hoje.' },
      { v: 3, en: 'Here I am. Witness against me before Yahweh, and before his anointed. Whose ox have I taken? Whose donkey have I taken? Whom have I defrauded? Whom have I oppressed? Of whose hand have I taken a ransom to make me blind my eyes? I will restore it to you.”', pt: 'Eis-me aqui! testificai contra mim perante o Senhor, e perante o seu ungido. De quem tomei o boi? ou de quem tomei o jumento? ou a quem defraudei? ou a quem tenho oprimido? ou da mão de quem tenho recebido peita para encobrir com ela os meus olhos? E eu vo-lo restituirei.' },
      { v: 4, en: 'They said, “You have not defrauded us, nor oppressed us, neither have you taken anything from anyone’s hand.”', pt: 'Responderam eles: Em nada nos defraudaste, nem nos oprimiste, nem tomaste coisa alguma da mão de ninguém.' },
      { v: 5, en: 'He said to them, “Yahweh is witness against you, and his anointed is witness today, that you have not found anything in my hand.” They said, “He is witness.”', pt: 'Ele lhes disse: O Senhor é testemunha contra vós, e o seu ungido é hoje testemunha de que nada tendes achado na minha mão. Ao que respondeu o povo: Ele é testemunha.' },
      { v: 6, en: 'Samuel said to the people, “It is Yahweh who appointed Moses and Aaron, and that brought your fathers up out of the land of Egypt.', pt: 'Então disse Samuel ao povo: O Senhor é o que escolheu a Moisés e a Arão, e tirou a vossos pais da terra do Egito.' },
      { v: 7, en: 'Now therefore stand still, that I may plead with you before Yahweh concerning all the righteous acts of Yahweh, which he did to you and to your fathers.', pt: 'Agora ponde-vos aqui, para que eu pleiteie convosco perante o Senhor, no tocante a todos os atos de justiça do Senhor, que ele fez a vós e a vossos pais.' },
      { v: 8, en: '“When Jacob had come into Egypt, and your fathers cried to Yahweh, then Yahweh sent Moses and Aaron, who brought your fathers out of Egypt, and made them to dwell in this place.', pt: 'Quando Jacó entrou no Egito, e vossos pais clamaram ao Senhor, então o Senhor enviou Moisés e Arão, que tiraram vossos pais do Egito, e os fizeram habitar neste lugar.' },
      { v: 9, en: '“But they forgot Yahweh their God; and he sold them into the hand of Sisera, captain of the army of Hazor, and into the hand of the Philistines, and into the hand of the king of Moab; and they fought against them.', pt: 'Esqueceram-se, porém, do Senhor seu Deus; e ele os entregou na mão de Sísera, chefe do exército de Hazor, e na mão dos filisteus, e na mão do rei de Moabe, os quais pelejaram contra eles.' },
      { v: 10, en: 'They cried to Yahweh, and said, ‘We have sinned, because we have forsaken Yahweh, and have served the Baals and the Ashtaroth: but now deliver us out of the hand of our enemies, and we will serve you.’', pt: 'Clamaram, pois, ao Senhor, e disseram: Pecamos, porque deixamos ao Senhor, e servimos aos baalins e astarotes; agora, porém, livra-nos da mão de nossos inimigos, e te serviremos:' },
      { v: 11, en: 'Yahweh sent Jerubbaal, Bedan, Jephthah, and Samuel, and delivered you out of the hand of your enemies on every side; and you lived in safety.', pt: 'Então o Senhor enviou Jerubaal, e Baraque, e Jefté, e Samuel; e vos livrou da mão de vossos inimigos em redor, e habitastes em segurança.' },
      { v: 12, en: '“When you saw that Nahash the king of the children of Ammon came against you, you said to me, ‘No, but a king shall reign over us;’ when Yahweh your God was your king.', pt: 'Quando vistes que Naás, rei dos filhos de Amom, vinha contra vós, dissestes-me: Não, mas reinará sobre nós um rei; entretanto, o Senhor vosso Deus era o vosso Rei.' },
      { v: 13, en: 'Now therefore see the king whom you have chosen, and whom you have asked for. Behold, Yahweh has set a king over you.', pt: 'Agora, eis o rei que escolhestes e que pedistes; eis que o Senhor tem posto sobre vós um rei.' },
      { v: 14, en: 'If you will fear Yahweh, and serve him, and listen to his voice, and not rebel against the commandment of Yahweh, then both you and also the king who reigns over you are followers of Yahweh your God.', pt: 'Se temerdes ao Senhor, e o servirdes, e derdes ouvidos à sua voz, e não fordes rebeldes às suas ordens, e se tanto vós como o rei que reina sobre vós seguirdes o Senhor vosso Deus, bem está;' },
      { v: 15, en: 'But if you will not listen to Yahweh’s voice, but rebel against the commandment of Yahweh, then Yahweh’s hand will be against you, as it was against your fathers.', pt: 'mas se não derdes ouvidos à voz do Senhor, e fordes rebeldes às suas ordens, a mão do Senhor será contra vós, como foi contra vossos pais:' },
      { v: 16, en: '“Now therefore stand still and see this great thing, which Yahweh will do before your eyes.', pt: 'Portanto ficai agora aqui, e vede esta grande coisa que o Senhor vai fazer diante dos vossos olhos.' },
      { v: 17, en: 'Isn’t it wheat harvest today? I will call to Yahweh, that he may send thunder and rain; and you will know and see that your wickedness is great, which you have done in Yahweh’s sight, in asking for a king.”', pt: 'Não é hoje a sega do trigo? clamarei, pois, ao Senhor, para que ele envie trovões e chuva; e sabereis e vereis que é grande a vossa maldade, que fizestes perante o Senhor, pedindo para vós um rei.' },
      { v: 18, en: 'So Samuel called to Yahweh; and Yahweh sent thunder and rain that day. Then all the people greatly feared Yahweh and Samuel.', pt: 'Então invocou Samuel ao Senhor, e o Senhor enviou naquele dia trovões e chuva; pelo que todo o povo temeu sobremaneira ao Senhor e a Samuel.' },
      { v: 19, en: 'All the people said to Samuel, “Pray for your servants to Yahweh your God, that we not die; for we have added to all our sins this evil, to ask for a king.”', pt: 'Disse todo o povo a Samuel: Roga pelos teus servos ao Senhor teu Deus, para que não morramos; porque a todos os nossos pecados temos acrescentado este mal, de pedirmos para nós um rei.' },
      { v: 20, en: 'Samuel said to the people, “Don’t be afraid. You have indeed done all this evil; yet don’t turn away from following Yahweh, but serve Yahweh with all your heart.', pt: 'Então disse Samuel ao povo: Não temais; vós fizestes todo este mal; porém não vos desvieis de seguir ao Senhor, mas servi-o de todo o vosso coração.' },
      { v: 21, en: 'Don’t turn away to go after vain things which can’t profit or deliver, for they are vain.', pt: 'Não vos desvieis; porquanto seguiríeis coisas vãs, que nada aproveitam, e tampouco vos livrarão, porque são vãs.' },
      { v: 22, en: 'For Yahweh will not forsake his people for his great name’s sake, because it has pleased Yahweh to make you a people for himself.', pt: 'Pois o Senhor, por causa do seu grande nome, não desamparará o seu povo; porque aprouve ao Senhor fazer de vós o seu povo.' },
      { v: 23, en: 'Moreover as for me, far be it from me that I should sin against Yahweh in ceasing to pray for you: but I will instruct you in the good and the right way.', pt: 'E quanto a mim, longe de mim esteja o pecar contra o Senhor, deixando de orar por vos; eu vos ensinarei o caminho bom e direito.' },
      { v: 24, en: 'Only fear Yahweh, and serve him in truth with all your heart; for consider what great things he has done for you.', pt: 'Tão-somente temei ao Senhor, e servi-o fielmente de todo o vosso coração; pois vede quão grandiosas coisas vos fez.' },
      { v: 25, en: 'But if you keep doing evil, you will be consumed, both you and your king.”', pt: 'Se, porém, perseverardes em fazer o mal, perecereis, assim vós como o vosso rei.' },
    ],
    13: [
      { v: 1, en: 'Saul was thirty years old when he became king, and he reigned over Israel forty-two years.', pt: 'Saul tinha ...anos de idade quando começou a reinar; e tendo reinado dois anos sobre Israel,' },
      { v: 2, en: 'Saul chose for himself three thousand men of Israel, of which two thousand were with Saul in Michmash and in the Mount of Bethel, and one thousand were with Jonathan in Gibeah of Benjamin. He sent the rest of the people to their own tents.', pt: 'escolheu para si três mil homens de Israel; dois mil estavam com Saul em Micmás e no monte de Betel, e mil estavam com Jônatas em Gibeá de Benjamim. Quanto ao resto do povo, mandou-o cada um para sua tenda.' },
      { v: 3, en: 'Jonathan struck the garrison of the Philistines that was in Geba, and the Philistines heard of it. Saul blew the trumpet throughout all the land, saying, “Let the Hebrews hear!”', pt: 'Ora, Jônatas feriu a guarnição dos filisteus que estava em Geba, o que os filisteus ouviram; pelo que Saul tocou a trombeta por toda a terra, dizendo: Ouçam os hebreus.' },
      { v: 4, en: 'All Israel heard that Saul had struck the garrison of the Philistines, and also that Israel was considered an abomination to the Philistines. The people were gathered together after Saul to Gilgal.', pt: 'Então todo o Israel ouviu dizer que Saul ferira a guarnição dos filisteus, e que Israel se fizera abominável aos filisteus. E o povo foi convocado após Saul em Gilgal.' },
      { v: 5, en: 'The Philistines assembled themselves together to fight with Israel, thirty thousand chariots, and six thousand horsemen, and people as the sand which is on the seashore in multitude. They came up and encamped in Michmash, eastward of Beth Aven.', pt: 'E os filisteus se ajuntaram para pelejar contra Israel, com trinta mil carros, seis mil cavaleiros, e povo em multidão como a areia que está à beira do mar subiram e se acamparam em Micmás, ao oriente de Bete-Aven.' },
      { v: 6, en: 'When the men of Israel saw that they were in trouble (for the people were distressed), then the people hid themselves in caves, in thickets, in rocks, in tombs, and in pits.', pt: 'Vendo, pois, os homens de Israel que estavam em aperto (porque o povo se achava angustiado), esconderam-se nas cavernas, nos espinhais, nos penhascos, nos esconderijos subterrâneos e nas cisternas.' },
      { v: 7, en: 'Now some of the Hebrews had gone over the Jordan to the land of Gad and Gilead; but as for Saul, he was yet in Gilgal, and all the people followed him trembling.', pt: 'Ora, alguns dos hebreus passaram o Jordão para a terra de Gade e Gileade; mas Saul ficou ainda em Gilgal, e todo o povo o seguia tremendo.' },
      { v: 8, en: 'He stayed seven days, according to the time set by Samuel; but Samuel didn’t come to Gilgal, and the people were scattering from him.', pt: 'Esperou, pois, sete dias, até o tempo que Samuel determinara; não vindo, porém, Samuel a Gilgal, o povo, deixando a Saul, se dispersava.' },
      { v: 9, en: 'Saul said, “Bring the burnt offering to me here, and the peace offerings.” He offered the burnt offering.', pt: 'Então disse Saul: Trazei-me aqui um holocausto, e ofertas pacíficas. E ofereceu o holocausto.' },
      { v: 10, en: 'It came to pass that as soon as he had finished offering the burnt offering, behold, Samuel came; and Saul went out to meet him, that he might greet him.', pt: 'Mal tinha ele acabado de oferecer e holocausto, eis que Samuel chegou; e Saul lhe saiu ao encontro, para o saudar.' },
      { v: 11, en: 'Samuel said, “What have you done?” Saul said, “Because I saw that the people were scattered from me, and that you didn’t come within the days appointed, and that the Philistines assembled themselves together at Michmash;', pt: 'Então perguntou Samuel: Que fizeste? Respondeu Saul: Porquanto via que o povo, deixando-me, se dispersava, e que tu nao vinhas no tempo determinado, e que os filisteus já se tinham ajuntado em Micmás,' },
      { v: 12, en: 'therefore I said, ‘Now the Philistines will come down on me to Gilgal, and I haven’t entreated the favor of Yahweh.’ I forced myself therefore, and offered the burnt offering.”', pt: 'eu disse: Agora descerão os filisteus sobre mim a Gilgal, e ainda não aplaquei o Senhor. Assim me constrangi e ofereci o holocausto.' },
      { v: 13, en: 'Samuel said to Saul, “You have done foolishly. You have not kept the commandment of Yahweh your God, which he commanded you; for now Yahweh would have established your kingdom on Israel forever.', pt: 'Então disse Samuel a Saul: Procedeste nesciamente; não guardaste o mandamento que o Senhor teu Deus te ordenou. O Senhor teria confirmado o teu reino sobre Israel para sempre;' },
      { v: 14, en: 'But now your kingdom will not continue. Yahweh has sought for himself a man after his own heart, and Yahweh has appointed him to be prince over his people, because you have not kept that which Yahweh commanded you.”', pt: 'agora, porém, não subsistirá o teu reino; já tem o Senhor buscado para si um homem segundo o seu coração, e já o tem destinado para ser príncipe sobre o seu povo, porquanto não guardaste o que o Senhor te ordenou.' },
      { v: 15, en: 'Samuel arose, and went from Gilgal to Gibeah of Benjamin. Saul counted the people who were present with him, about six hundred men.', pt: 'Então Samuel se levantou, e subiu de Gilgal a Gibeá de Benjamim. Saul contou o povo que se achava com ele, cerca de seiscentos homens.' },
      { v: 16, en: 'Saul, and Jonathan his son, and the people who were present with them, stayed in Geba of Benjamin; but the Philistines encamped in Michmash.', pt: 'E Saul, seu filho Jônatas e o povo que se achava com eles, ficaram em Gibeá de Benjamim, mas os filisteus se tinham acampado em Micmás.' },
      { v: 17, en: 'The raiders came out of the camp of the Philistines in three companies: one company turned to the way that leads to Ophrah, to the land of Shual;', pt: 'Nisso os saqueadores saíram do arraial dos filisteus em três companhias: uma das companhias tomou o caminho de Ofra para a terra de Sual,' },
      { v: 18, en: 'another company turned the way to Beth Horon; and another company turned the way of the border that looks down on the valley of Zeboim toward the wilderness.', pt: 'outra tomou o caminho de Bete-Horom, e a outra tomou o caminho do termo que dá para o vale de Zebuim, na direção do deserto.' },
      { v: 19, en: 'Now there was no blacksmith found throughout all the land of Israel; for the Philistines said, “Lest the Hebrews make themselves swords or spears”;', pt: 'Ora, em toda a terra de Israel não se achava um só ferreiro; porque os filisteus tinham dito: Não façam os hebreus para si nem espada nem lança.' },
      { v: 20, en: 'but all the Israelites went down to the Philistines, each man to sharpen his own plowshare, mattock, ax, and sickle.', pt: 'Pelo que todos os israelitas tinham que descer aos filisteus para afiar cada um a sua relha, a sua enxada, o seu machado e o seu sacho.' },
      { v: 21, en: 'The price was one payim each to sharpen mattocks, plowshares, pitchforks, axes, and goads.', pt: 'Tinham porém limas para os sachos, para as enxadas, para as forquilhas e para os machados, e para consertar as aguilhadas.' },
      { v: 22, en: 'So it came to pass in the day of battle, that neither sword nor spear was found in the hand of any of the people who were with Saul and Jonathan; but Saul and Jonathan his son had them.', pt: 'Assim, no dia da peleja, não se achou nem espada nem lança na mão de todo o povo que estava com Saul e com Jônatas; acharam-se, porém, com Saul e com Jônatas seu filho.' },
      { v: 23, en: 'The garrison of the Philistines went out to the pass of Michmash.', pt: 'E saiu a guarnição dos filisteus para o desfiladeiro de Micmás.' },
    ],
    14: [
      { v: 1, en: 'Now it fell on a day, that Jonathan the son of Saul said to the young man who bore his armor, “Come, and let us go over to the Philistines’ garrison, that is on the other side.” But he didn’t tell his father.', pt: 'Sucedeu, pois, um dia, que Jônatas, filho de Saul, disse ao seu escudeiro: Vem, passemos à guarnição dos filisteus, que está do outro lado. Mas não o fez saber a seu pai.' },
      { v: 2, en: 'Saul stayed in the uttermost part of Gibeah under the pomegranate tree which is in Migron: and the people who were with him were about six hundred men;', pt: 'Ora Saul estava na extremidade de Gibeá, debaixo da romeira que havia em Migrom; e o povo que estava com ele era cerca de seiscentos homens;' },
      { v: 3, en: 'including Ahijah, the son of Ahitub, Ichabod’s brother, the son of Phinehas, the son of Eli, the priest of Yahweh in Shiloh, wearing an ephod. The people didn’t know that Jonathan was gone.', pt: 'e Aíja, filho de Aitube, irmão de Icabô, filho de Finéias, filho de Eli, sacerdote do Senhor em Siló, trazia o éfode. E o povo não sabia que Jônatas tinha ido.' },
      { v: 4, en: 'Between the passes, by which Jonathan sought to go over to the Philistines’ garrison, there was a rocky crag on the one side, and a rocky crag on the other side: and the name of the one was Bozez, and the name of the other Seneh.', pt: 'Ora, entre os desfiladeiros pelos quais Jônatas procurava chegar à guarnição dos filisteus, havia um penhasco de um e de outro lado; o nome de um era Bozez, e o nome do outro Sené.' },
      { v: 5, en: 'The one crag rose up on the north in front of Michmash, and the other on the south in front of Geba.', pt: 'Um deles estava para o norte defronte de Micmás, e o outro para o sul defronte de Gibeá.' },
      { v: 6, en: 'Jonathan said to the young man who bore his armor, “Come, let us go over to the garrison of these uncircumcised. It may be that Yahweh will work for us; for there is no restraint on Yahweh to save by many or by few.”', pt: 'Disse, pois, Jônatas ao seu escudeiro: Vem, passemos à guarnição destes incircuncisos; porventura operará o Senhor por nós, porque para o Senhor nenhum impedimento há de livrar com muitos ou com poucos.' },
      { v: 7, en: 'His armor bearer said to him, “Do all that is in your heart. Turn and, behold, I am with you according to your heart.”', pt: 'Ao que o seu escudeiro lhe respondeu: Faze tudo o que te aprouver; segue, eis-me aqcaustos e sacrifícios ao Senhor.' },
      { v: 8, en: 'Then Jonathan said, “Behold, we will pass over to the men, and we will reveal ourselves to them.', pt: 'Disse Jônatas: Eis que passaremos àqueles homens, e nos descobriremos a eles.' },
      { v: 9, en: 'If they say thus to us, ‘Wait until we come to you!’ then we will stand still in our place, and will not go up to them.', pt: 'Se nos disserem: Parai até que cheguemos a vós; então ficaremos no nosso lugar, e não subiremos a eles.' },
      { v: 10, en: 'But if they say this, ‘Come up to us!’ then we will go up; for Yahweh has delivered them into our hand. This shall be the sign to us.”', pt: 'Se, porém, disserem: Subi a nós; então subiremos, pois o Senhor os entregou em nossas mãos; isso nos será por sinal.' },
      { v: 11, en: 'Both of them revealed themselves to the garrison of the Philistines: and the Philistines said, “Behold, the Hebrews are coming out of the holes where they had hidden themselves!”', pt: 'Então ambos se descobriram à guarnição dos filisteus, e os filisteus disseram: Eis que já os hebreus estão saindo das cavernas em que se tinham escondido.' },
      { v: 12, en: 'The men of the garrison answered Jonathan and his armor bearer, and said, “Come up to us, and we will show you something!” Jonathan said to his armor bearer, “Come up after me; for Yahweh has delivered them into the hand of Israel.”', pt: 'E os homens da guarnição disseram a Jônatas e ao seu escudeiro: Subi a nós, e vos ensinaremos uma coisa. Disse, pois, Jônatas ao seu escudeiro: Sobe atrás de mim, porque o Senhor os entregou na mão de Israel.' },
      { v: 13, en: 'Jonathan climbed up on his hands and on his feet, and his armor bearer after him: and they fell before Jonathan; and his armor bearer killed them after him.', pt: 'Então trepou Jônatas de gatinhas, e o seu escudeiro atrás dele; e os filisteus caíam diante de Jônatas, e o seu escudeiro os matava atrás dele.' },
      { v: 14, en: 'That first slaughter, which Jonathan and his armor bearer made, was about twenty men, within as it were half a furrow’s length in an acre of land.', pt: 'Esta primeira derrota, em que Jônatas e o seu escudeiro mataram uns vinte homens, deu-se dentro de meia jeira de terra.' },
      { v: 15, en: 'There was a trembling in the camp, in the field, and among all the people; the garrison, and the raiders, also trembled; and the earth quaked, so there was an exceedingly great trembling.', pt: 'Pelo que houve tremor no arraial, no campo e em todo o povo; também a própria guarnição e os saqueadores tremeram; e até a terra estremeceu; de modo que houve grande pânico.' },
      { v: 16, en: 'The watchmen of Saul in Gibeah of Benjamin looked; and behold, the multitude melted away and scattered.', pt: 'Olharam, pois, as sentinelas de Saul e Gibeá de Benjamim, e eis que a multidão se derretia, fugindo para cá e para lá.' },
      { v: 17, en: 'Then Saul said to the people who were with him, “Count now, and see who is missing from us.” When they had counted, behold, Jonathan and his armor bearer were not there.', pt: 'Disse então Saul ao povo que estava com ele: Ora, contai e vede quem é que saiu dentre nós: E contaram, e eis que nem Jônatas nem o seu escudeiro estava ali.' },
      { v: 18, en: 'Saul said to Ahijah, “Bring God’s ark here.” For God’s ark was with the children of Israel at that time.', pt: 'Então Saul disse a Aíja: Traze aqui a arca de Deus. Pois naquele dia estava a arca de Deus com os filhos de Israel.' },
      { v: 19, en: 'While Saul talked to the priest, the tumult that was in the camp of the Philistines went on and increased; and Saul said to the priest, “Withdraw your hand!”', pt: 'E sucedeu que, estando Saul ainda falando com o sacerdote, o alvoroço que havia no arraial dos filisteus ia crescendo muito; pelo que disse Saul ao sacerdote: Retira a tua mão.' },
      { v: 20, en: 'Saul and all the people who were with him were gathered together, and came to the battle; and behold, they were all striking each other with their swords in very great confusion.', pt: 'Então Saul e todo o povo que estava com ele se reuniram e foram à peleja; e eis que dentre os filisteus a espada de um era contra o outro, e houve mui grande derrota.' },
      { v: 21, en: 'Now the Hebrews who were with the Philistines before, and who went up with them into the camp, from all around, even they also turned to be with the Israelites who were with Saul and Jonathan.', pt: 'Os hebreus que estavam dantes com os filisteus, e tinham subido com eles ao arraial, também se ajuntaram aos israelitas que estavam com Saul e Jônatas.' },
      { v: 22, en: 'Likewise all the men of Israel who had hidden themselves in the hill country of Ephraim, when they heard that the Philistines fled, even they also followed hard after them in the battle.', pt: 'E todos os homens de Israel que se haviam escondido na região montanhosa de Efraim, ouvindo que os filisteus fugiam, também os perseguiram de perto na peleja.' },
      { v: 23, en: 'So Yahweh saved Israel that day; and the battle passed over by Beth Aven.', pt: 'Assim o Senhor livrou a Israel naquele dia, e a batalha passou além de Bete-Aven.' },
      { v: 24, en: 'The men of Israel were distressed that day; for Saul had adjured the people, saying, “Cursed is the man who eats any food until it is evening, and I am avenged of my enemies.” So none of the people tasted food.', pt: 'Ora, os homens de Israel estavam já exaustos naquele dia, porquanto Saul conjurara o povo, dizendo: Maldito o homem que comer pão antes da tarde, antes que eu me vingue de meus inimigos. Pelo que todo o povo se absteve de comer.' },
      { v: 25, en: 'All the people came into the forest; and there was honey on the ground.', pt: 'Mas todo o povo chegou a um bosque, onde havia mel à flor da terra.' },
      { v: 26, en: 'When the people had come to the forest, behold, honey was dripping, but no one put his hand to his mouth; for the people feared the oath.', pt: 'Chegando, pois, o povo ao bosque, viu correr o mel; todavia ninguém chegou a mão à boca, porque o povo temia a conjuração.' },
      { v: 27, en: 'But Jonathan didn’t hear when his father commanded the people with the oath. Therefore he put out the end of the rod that was in his hand, and dipped it in the honeycomb, and put his hand to his mouth; and his eyes brightened.', pt: 'Jônatas, porém, não tinha ouvido quando seu pai conjurara o povo; pelo que estendeu a ponta da vara que tinha na mão, e a molhou no favo de mel; e, ao chegar a mão à boca, aclararam-se-lhe os olhos.' },
      { v: 28, en: 'Then one of the people answered, and said, “Your father directly commanded the people with an oath, saying, ‘Cursed is the man who eats food today.’” The people were faint.', pt: 'Então disse um do povo: Teu pai solenemente conjurou o povo, dizendo: Maldito o homem que comer pão hoje. E o povo ainda desfalecia.' },
      { v: 29, en: 'Then Jonathan said, “My father has troubled the land. Please look how my eyes have brightened, because I tasted a little of this honey.', pt: 'Pelo que disse Jônatas: Meu pai tem turbado a terra; ora vede como se me aclararam os olhos por ter provado um pouco deste mel.' },
      { v: 30, en: 'How much more, if perhaps the people had eaten freely today of the plunder of their enemies which they found? For now has there been no great slaughter among the Philistines.”', pt: 'Quanto maior não teria sido a derrota dos filisteus se o povo hoje tivesse comido livremente do despojo, que achou de seus inimigos?' },
      { v: 31, en: 'They struck the Philistines that day from Michmash to Aijalon. The people were very faint;', pt: 'Feriram, contudo, naquele dia aos filisteus, desde Micmás até Aijalom. E o povo desfaleceu em extremo;' },
      { v: 32, en: 'and the people pounced on the plunder, and took sheep, cattle, and calves, and killed them on the ground; and the people ate them with the blood.', pt: 'então o povo se lançou ao despojo, e tomou ovelhas, bois e bezerros e, degolando-os no chão, comeu-os com o sangue.' },
      { v: 33, en: 'Then they told Saul, saying, “Behold, the people are sinning against Yahweh, in that they eat meat with the blood.” He said, “You have dealt treacherously. Roll a large stone to me today!”', pt: 'E o anunciaram a Saul, dizendo: Eis que o povo está pecando contra o Senhor, comendo carne com o sangue. Respondeu Saul: Procedestes deslealmente. Trazei-me aqui já uma grande pedra.' },
      { v: 34, en: 'Saul said, “Disperse yourselves among the people, and tell them, ‘Every man bring me here his ox, and every man his sheep, and kill them here, and eat; and don’t sin against Yahweh in eating meat with the blood.’” All the people brought every man his ox with him that night, and killed them there.', pt: 'Disse mais Saul: Dispersai-vos entre e povo, e dizei-lhes: Trazei-me aqui cada um o seu boi, e cada um a sua ovelha e degolai-os aqui, e comei; e não pequeis contra e Senhor, comendo com sangue. Então todo o povo trouxe de noite, cada um o seu boi, e os degolaram ali.' },
      { v: 35, en: 'Saul built an altar to Yahweh. This was the first altar that he built to Yahweh.', pt: 'Então edificou Saul um altar ao Senhor; este foi o primeiro altar que ele edificou ao Senhor.' },
      { v: 36, en: 'Saul said, “Let us go down after the Philistines by night, and take plunder among them until the morning light, and let us not leave a man of them.” They said, “Do whatever seems good to you.” Then the priest said, “Let us draw near here to God.”', pt: 'Depois disse Saul: Desçamos de noite atrás dos filisteus, e despojemo-los, até e amanhecer, e não deixemos deles um só homem. E o povo disse: Faze tudo o que parecer bem aos teus olhos. Disse, porém, o sacerdote: Cheguemo-nos aqui a Deus.' },
      { v: 37, en: 'Saul asked counsel of God, “Shall I go down after the Philistines? Will you deliver them into the hand of Israel?” But he didn’t answer him that day.', pt: 'Então consultou Saul a Deus, dizendo: Descerei atrás dos filisteus? entregá-los-ás na mão de Israel? Deus, porém, não lhe respondeu naquele dia.' },
      { v: 38, en: 'Saul said, “Draw near here, all you chiefs of the people; and know and see in which this sin has been today.', pt: 'Disse, pois, Saul: Chegai-vos para cá, todos os chefes do povo; informai-vos, e vede em que se cometeu hoje este pecado;' },
      { v: 39, en: 'For, as Yahweh lives, who saves Israel, though it is in Jonathan my son, he shall surely die.” But there was not a man among all the people who answered him.', pt: 'porque, como vive o Senhor que salva a Israel, ainda que seja em meu filha Jônatas, ele será morto. Mas de todo o povo ninguém lhe respondeu.' },
      { v: 40, en: 'Then he said to all Israel, “You be on one side, and I and Jonathan my son will be on the other side.” The people said to Saul, “Do what seems good to you.”', pt: 'Disse mais a todo o Israel: Vós estareis dum lado, e eu e meu filho Jônatas estaremos do outro. Então disse o povo a Saul: Faze o que parecer bem aos teus olhos.' },
      { v: 41, en: 'Therefore Saul said to Yahweh, the God of Israel, “Show the right.” Jonathan and Saul were chosen, but the people escaped.', pt: 'Falou, pois, Saul ao Senhor Deus de Israel: Mostra o que é justo. E Jônatas e Saul foram tomados por sorte, e o povo saiu livre.' },
      { v: 42, en: 'Saul said, “Cast lots between me and Jonathan my son.” Jonathan was selected.', pt: 'Então disse Saul: Lançai a sorte entre mim e Jônatas, meu filho. E foi tomado Jônatas.' },
      { v: 43, en: 'Then Saul said to Jonathan, “Tell me what you have done!” Jonathan told him, and said, “I certainly did taste a little honey with the end of the rod that was in my hand; and behold, I must die.”', pt: 'Disse então Saul a Jônatas: Declara-me o que fizeste. E Jônatas lho declarou, dizendo: Provei, na verdade, um pouco de mel com a ponta da vara que tinha na mão; eis-me pronto a morrer.' },
      { v: 44, en: 'Saul said, “God do so and more also; for you shall surely die, Jonathan.”', pt: 'Ao que disse Saul: Assim me faça Deus, e outro tanto, se tu, certamente, não morreres, Jônatas.' },
      { v: 45, en: 'The people said to Saul, “Shall Jonathan die, who has worked this great salvation in Israel? Far from it! As Yahweh lives, there shall not one hair of his head fall to the ground; for he has worked with God today!” So the people rescued Jonathan, that he didn’t die.', pt: 'Mas o povo disse a Saul: Morrerá, porventura, Jônatas, que operou esta grande salvação em Israel? Tal não suceda! como vive o Senhor, não lhe há de cair no chão um só cabelo da sua cabeça! pois com Deus fez isso hoje. Assim o povo livrou Jônatas, para que não morresse.' },
      { v: 46, en: 'Then Saul went up from following the Philistines; and the Philistines went to their own place.', pt: 'Então Saul deixou de perseguir os filisteus, e estes foram para o seu lugar.' },
      { v: 47, en: 'Now when Saul had taken the kingdom over Israel, he fought against all his enemies on every side, against Moab, and against the children of Ammon, and against Edom, and against the kings of Zobah, and against the Philistines. Wherever he turned himself, he defeated them.', pt: 'Tendo Saul tomado o reino sobre Israel, pelejou contra todos os seus inimigos em redor: contra Moabe, contra os filhos de Amom, contra Edom, contra os reis de Zobá e contra os filisteus; e, para onde quer que se voltava, saía vitorioso.' },
      { v: 48, en: 'He did valiantly, and struck the Amalekites, and delivered Israel out of the hands of those who plundered them.', pt: 'Houve-se valorosamente, derrotando os amalequitas, e libertando Israel da mão dos que o saqueavam.' },
      { v: 49, en: 'Now the sons of Saul were Jonathan, Ishvi, and Malchishua; and the names of his two daughters were these: the name of the firstborn Merab, and the name of the younger Michal.', pt: 'Ora, os filhos de Saul eram Jônatas, Isvi e Malquisua; os nomes de suas duas filhas eram estes: o da mais velha Merabe, e o da mais nova Mical.' },
      { v: 50, en: 'The name of Saul’s wife was Ahinoam the daughter of Ahimaaz. The name of the captain of his army was Abner the son of Ner, Saul’s uncle.', pt: 'O nome da mulher de Saul era Ainoã, filha de Aimaaz; e o nome do chefe do seu exército, Abner, filho de Ner, tio de Saul.' },
      { v: 51, en: 'Kish was the father of Saul; and Ner the father of Abner was the son of Abiel.', pt: 'Quis, pai de Saul, e Ner, pai de Abner, eram filhos de Abiel.' },
      { v: 52, en: 'There was severe war against the Philistines all the days of Saul; and when Saul saw any mighty man, or any valiant man, he took him into his service.', pt: 'E houve forte guerra contra os filisteus, por todos os dias de Saul; e sempre que Saul via algum homem poderoso e valente, o agregava a si.' },
    ],
    15: [
      { v: 1, en: 'Samuel said to Saul, “Yahweh sent me to anoint you to be king over his people, over Israel. Now therefore listen to the voice of Yahweh’s words.', pt: 'Disse Samuel a Saul: Enviou-me o Senhor a ungir-te rei sobre o seu povo, sobre Israel; ouve, pois, agora as palavras do Senhor.' },
      { v: 2, en: 'Yahweh of Armies says, ‘I remember what Amalek did to Israel, how he set himself against him on the way, when he came up out of Egypt.', pt: 'Assim diz o Senhor dos exércitos: Castigarei a Amaleque por aquilo que fez a Israel quando se lhe opôs no caminho, ae subir ele do Egito.' },
      { v: 3, en: 'Now go and strike Amalek, and utterly destroy all that they have, and don’t spare them; but kill both man and woman, infant and nursing baby, ox and sheep, camel and donkey.’”', pt: 'Vai, pois, agora e fere a Amaleque, e o destrói totalmente com tudo o que tiver; não o poupes, porém matarás homens e mulheres, meninos e crianças de peito, bois e ovelhas, camelos e jumentos.' },
      { v: 4, en: 'Saul summoned the people, and counted them in Telaim, two hundred thousand footmen, and ten thousand men of Judah.', pt: 'Então Saul convocou o povo, e os contou em Telaim, duzentos mil homens de infantaria, e mais dez mil dos de Judá.' },
      { v: 5, en: 'Saul came to the city of Amalek, and set an ambush in the valley.', pt: 'Chegando, pois, Saul à cidade de Amaleque, pôs uma emboscada no vale.' },
      { v: 6, en: 'Saul said to the Kenites, “Go, depart, go down from among the Amalekites, lest I destroy you with them; for you showed kindness to all the children of Israel, when they came up out of Egypt.” So the Kenites departed from among the Amalekites.', pt: 'E disse Saul aos queneus: Ide, retirai-vos, saí do meio dos amalequitas, para que eu não vos destrua juntamente com eles; porque vós usastes de misericórdia com todos os filhos de Israel, quando subiram do Egito. Retiraram-se, pois, os queneus do meio dos amalequitas.' },
      { v: 7, en: 'Saul struck the Amalekites, from Havilah as you go to Shur, that is before Egypt.', pt: 'Depois Saul feriu os amalequitas desde Havilá até chegar a Sur, que está defronte do Egito.' },
      { v: 8, en: 'He took Agag the king of the Amalekites alive, and utterly destroyed all the people with the edge of the sword.', pt: 'E tomou vivo a Agague, rei dos amalequitas, porém a todo o povo destruiu ao fio da espada.' },
      { v: 9, en: 'But Saul and the people spared Agag, and the best of the sheep, of the cattle, and of the fat calves, and the lambs, and all that was good, and were not willing to utterly destroy them; but everything that was vile and refuse, that they destroyed utterly.', pt: 'Mas Saul e o povo pouparam a Agague, como também ao melhor das ovelhas, dos bois, e dos animais engordados, e aos cordeiros, e a tudo o que era bom, e não os quiseram destruir totalmente; porém a tudo o que era vil e desprezível destruíram totalmente.' },
      { v: 10, en: 'Then Yahweh’s word came to Samuel, saying,', pt: 'Então veio a palavra do Senhor a Samuel, dizendo:' },
      { v: 11, en: '“It grieves me that I have set up Saul to be king; for he has turned back from following me, and has not performed my commandments.” Samuel was angry; and he cried to Yahweh all night.', pt: 'Arrependo-me de haver posto a Saul como rei; porquanto deixou de me seguir, e não cumpriu as minhas palavras. Então Samuel se contristou, e clamou ao Senhor a noite toda.' },
      { v: 12, en: 'Samuel rose early to meet Saul in the morning; and Samuel was told, saying, “Saul came to Carmel, and behold, he set up a monument for himself, and turned, and passed on, and went down to Gilgal.”', pt: 'E Samuel madrugou para encontrar-se com Saul pela manhã; e foi dito a Samuel: Já chegou Saul ao Carmelo, e eis que levantou para si numa coluna e, voltando, passou e desceu a Gilgal.' },
      { v: 13, en: 'Samuel came to Saul; and Saul said to him, “You are blessed by Yahweh! I have performed the commandment of Yahweh.”', pt: 'Veio, pois, Samuel ter com Saul, e Saul lhe disse: Bendito sejas do Senhor; já cumpri a palavra do Senhor.' },
      { v: 14, en: 'Samuel said, “Then what does this bleating of the sheep in my ears, and the lowing of the cattle which I hear mean?”', pt: 'Então perguntou Samuel: Que quer dizer, pois, este balido de ovelhas que chega aos meus ouvidos, e o mugido de bois que ouço?' },
      { v: 15, en: 'Saul said, “They have brought them from the Amalekites; for the people spared the best of the sheep and of the cattle, to sacrifice to Yahweh your God. We have utterly destroyed the rest.”', pt: 'Ao que respondeu Saul: De Amaleque os trouxeram, porque o povo guardou o melhor das ovelhas e dos bois, para os oferecer ao Senhor teu Deus; o resto, porém, destruímo-lo totalmente.' },
      { v: 16, en: 'Then Samuel said to Saul, “Stay, and I will tell you what Yahweh said to me last night.” He said to him, “Say on.”', pt: 'Então disse Samuel a Saul: Espera, e te declararei o que o Senhor me disse esta noite. Respondeu-lhe Saul: Fala.' },
      { v: 17, en: 'Samuel said, “Though you were little in your own sight, weren’t you made the head of the tribes of Israel? Yahweh anointed you king over Israel;', pt: 'Prosseguiu, pois, Samuel: Embora pequeno aos teus próprios olhos, porventura não foste feito o cabeça das tribos de Israel? O Senhor te ungiu rei sobre Israel;' },
      { v: 18, en: 'and Yahweh sent you on a journey, and said, ‘Go, and utterly destroy the sinners the Amalekites, and fight against them until they are consumed.’', pt: 'e bem assim te enviou o Senhor a este caminho, e disse: Vai, e destrói totalmente a estes pecadores, os amalequitas, e peleja contra eles, até que sejam aniquilados.' },
      { v: 19, en: 'Why then didn’t you obey Yahweh’s voice, but took the plunder, and did that which was evil in Yahweh’s sight?”', pt: 'Por que, pois, não deste ouvidos à voz do Senhor, antes te lançaste ao despojo, e fizeste o que era mau aos olhos do Senhor?' },
      { v: 20, en: 'Saul said to Samuel, “But I have obeyed Yahweh’s voice, and have gone the way which Yahweh sent me, and have brought Agag the king of Amalek, and have utterly destroyed the Amalekites.', pt: 'Então respondeu Saul a Samuel: Pelo contrário, dei ouvidos à voz do Senhor, e caminhei no caminho pelo qual o Senhor me enviou, e trouxe a Agague, rei de Amaleque, e aos amalequitas destruí totalmente;' },
      { v: 21, en: 'But the people took of the plunder, sheep and cattle, the chief of the devoted things, to sacrifice to Yahweh your God in Gilgal.”', pt: 'mas o povo tomou do despojo ovelhas e bois, o melhor do anátema, para o sacrificar ao Senhor teu Deus em Gilgal.' },
      { v: 22, en: 'Samuel said, “Has Yahweh as great delight in burnt offerings and sacrifices, as in obeying Yahweh’s voice? Behold, to obey is better than sacrifice, and to listen than the fat of rams.', pt: 'Samuel, porém, disse: Tem, porventura, o Senhor tanto prazer em holocaustos e sacrifícios, como em que se obedeça à voz do Senhor? Eis que o obedecer é melhor do que o sacrificar, e o atender, do que a gordura de carneiros' },
      { v: 23, en: 'For rebellion is as the sin of witchcraft, and stubbornness is as idolatry and teraphim. Because you have rejected Yahweh’s word, he has also rejected you from being king.”', pt: 'Porque a rebelião é como o pecado de adivinhação, e a obstinação é como a iniqüidade de idolatria. Porquanto rejeitaste a palavra do Senhor, ele também te rejeitou, a ti, para que não sejas rei.' },
      { v: 24, en: 'Saul said to Samuel, “I have sinned; for I have transgressed the commandment of Yahweh, and your words, because I feared the people, and obeyed their voice.', pt: 'Então disse Saul a Samuel: Pequei, porquanto transgredi a ordem do Senhor e as tuas palavras; porque temi ao povo, e dei ouvidos a sua voz.' },
      { v: 25, en: 'Now therefore, please pardon my sin, and turn again with me, that I may worship Yahweh.”', pt: 'Agora, pois, perdoa o meu pecado, e volta comigo, para que eu adore ao Senhor.' },
      { v: 26, en: 'Samuel said to Saul, “I will not return with you; for you have rejected Yahweh’s word, and Yahweh has rejected you from being king over Israel.”', pt: 'Samuel porém disse a Saul: Não voltarei contigo; porquanto rejeitaste a palavra do Senhor, e o Senhor te rejeitou a ti, para que não sejas rei sobre Israel:' },
      { v: 27, en: 'As Samuel turned around to go away, Saul grabbed the skirt of his robe, and it tore.', pt: 'E, virando-se Samuel para se ir, Saul pegou-lhe pela orla da capa, a qual se rasgou.' },
      { v: 28, en: 'Samuel said to him, “Yahweh has torn the kingdom of Israel from you today, and has given it to a neighbor of yours who is better than you.', pt: 'Então Samuel lhe disse: O Senhor rasgou de ti hoje o reino de Israel, e o deu a um teu próximo, que é melhor do que tu.' },
      { v: 29, en: 'Also the Strength of Israel will not lie nor repent; for he is not a man, that he should repent.”', pt: 'Também aquele que é a Força de Israel não mente nem se arrepende, por quanto não é homem para que se arrependa.' },
      { v: 30, en: 'Then he said, “I have sinned; yet please honor me now before the elders of my people, and before Israel, and come back with me, that I may worship Yahweh your God.”', pt: 'Ao que disse Saul: Pequei; honra-me, porém, agora diante dos anciãos do meu povo, e diante de Israel, e volta comigo, para que eu adore ao Senhor teu Deus.' },
      { v: 31, en: 'So Samuel went back with Saul; and Saul worshiped Yahweh.', pt: 'Então, voltando Samuel, seguiu a Saul, e Saul adorou ao Senhor.' },
      { v: 32, en: 'Then Samuel said, “Bring Agag the king of the Amalekites here to me!” Agag came to him cheerfully. Agag said, “Surely the bitterness of death is past.”', pt: 'Então disse Samuel: Trazei-me aqui a Agague, rei dos amalequitas. E Agague veio a ele animosamente; e disse: Certamente já passou a amargura da morte.' },
      { v: 33, en: 'Samuel said, “As your sword has made women childless, so your mother will be childless among women!” Then Samuel cut Agag in pieces before Yahweh in Gilgal.', pt: 'Disse, porém, Samuel: Assim como a tua espada desfilhou a mulheres, assim ficará desfilhada tua mãe entre as mulheres. E Samuel despedaçou a Agague perante o Senhor em Gilgal.' },
      { v: 34, en: 'Then Samuel went to Ramah; and Saul went up to his house to Gibeah of Saul.', pt: 'Então Samuel se foi a Ramá; e Saul subiu a sua casa, a Gibeá de Saul.' },
      { v: 35, en: 'Samuel came no more to see Saul until the day of his death; for Samuel mourned for Saul: and Yahweh grieved that he had made Saul king over Israel.', pt: 'Ora, Samuel nunca mais viu a Saul até o dia da sua morte, mas Samuel teve dó de Saul. E o Senhor se arrependeu de haver posto a Saul rei sobre Israel.' },
    ],
    16: [
      { v: 1, en: 'Yahweh said to Samuel, “How long will you mourn for Saul, since I have rejected him from being king over Israel? Fill your horn with oil, and go. I will send you to Jesse the Bethlehemite; for I have provided a king for myself among his sons.”', pt: 'Então disse o Senhor a Samuel: Até quando terás dó de Saul, havendo-o eu rejeitado, para que não reine sobre Israel? Enche o teu vaso de azeite, e vem; enviar-te-ei a Jessé o belemita, porque dentre os seus filhos me tenho provido de um rei.' },
      { v: 2, en: 'Samuel said, “How can I go? If Saul hears it, he will kill me.” Yahweh said, “Take a heifer with you, and say, I have come to sacrifice to Yahweh.', pt: 'Disse, porém, Samuel: Como irei eu? pois Saul o ouvirá e me matará. Então disse o Senhor: Leva contigo uma bezerra, e dize: Vim para oferecer sacrifício ao Senhor:' },
      { v: 3, en: 'Call Jesse to the sacrifice, and I will show you what you shall do. You shall anoint to me him whom I name to you.”', pt: 'E convidarás a Jessé para o sacrifício, e eu te farei saber o que hás de fazer; e ungir-me-ás a quem eu te designar.' },
      { v: 4, en: 'Samuel did that which Yahweh spoke, and came to Bethlehem. The elders of the city came to meet him trembling, and said, “Do you come peaceably?”', pt: 'Fez, pois, Samuel o que dissera o Senhor, e veio a Belém; então os anciãos da cidade lhe saíram ao encontro, tremendo, e perguntaram: É de paz a tua vinda?' },
      { v: 5, en: 'He said, “Peaceably; I have come to sacrifice to Yahweh. Sanctify yourselves, and come with me to the sacrifice.” He sanctified Jesse and his sons, and called them to the sacrifice.', pt: 'Respondeu ele: É de paz; vim oferecer sacrifício ao Senhor. Santificai-vos, e vinde comigo ao sacrifício. E santificou ele a Jessé e a seus filhos, e os convidou para o sacrifício.' },
      { v: 6, en: 'When they had come, he looked at Eliab, and said, “Surely Yahweh’s anointed is before him.”', pt: 'E sucedeu que, entrando eles, viu a Eliabe, e disse: Certamente está perante o Senhor o seu ungido.' },
      { v: 7, en: 'But Yahweh said to Samuel, “Don’t look on his face, or on the height of his stature, because I have rejected him; for I don’t see as man sees. For man looks at the outward appearance, but Yahweh looks at the heart.”', pt: 'Mas o Senhor disse a Samuel: Não atentes para a sua aparência, nem para a grandeza da sua estatura, porque eu o rejeitei; porque o Senhor não vê como vê o homem, pois o homem olha para o que está diante dos olhos, porém o Senhor olha para o coraçao.' },
      { v: 8, en: 'Then Jesse called Abinadab, and made him pass before Samuel. He said, “Yahweh has not chosen this one, either.”', pt: 'Depois chamou Jessé a Abinadabe, e o fez passar diante de Samuel, o qual disse: Nem a este escolheu o Senhor.' },
      { v: 9, en: 'Then Jesse made Shammah to pass by. He said, “Yahweh has not chosen this one, either.”', pt: 'Então Jessé fez passar a Samá; Samuel, porém, disse: Tampouco a este escolheu o Senhor.' },
      { v: 10, en: 'Jesse made seven of his sons to pass before Samuel. Samuel said to Jesse, “Yahweh has not chosen these.”', pt: 'Assim fez passar Jessé a sete de seus filhos diante de Samuel; porém Samuel disse a Jessé: O Senhor não escolheu a nenhum destes.' },
      { v: 11, en: 'Samuel said to Jesse, “Are all your children here?” He said, “There remains yet the youngest. Behold, he is keeping the sheep.” Samuel said to Jesse, “Send and get him, for we will not sit down until he comes here.”', pt: 'Disse mais Samuel a Jessé: São estes todos os teus filhos? Respondeu Jessé: Ainda falta o menor, que está apascentando as ovelhas. Disse, pois, Samuel a Jessé: Manda trazê-lo, porquanto não nos sentaremos até que ele venha aqui.' },
      { v: 12, en: 'He sent, and brought him in. Now he was ruddy, with a handsome face and good appearance. Yahweh said, “Arise! Anoint him, for this is he.”', pt: 'Jessé mandou buscá-lo e o fez entrar. Ora, ele era ruivo, de belos olhos e de gentil aspecto. Então disse o Senhor: Levanta-te, e unge-o, porque é este mesmo.' },
      { v: 13, en: 'Then Samuel took the horn of oil, and anointed him in the middle of his brothers. Then Yahweh’s Spirit came mightily on David from that day forward. So Samuel rose up and went to Ramah.', pt: 'Então Samuel tomou o vaso de azeite, e o ungiu no meio de seus irmãos; e daquele dia em diante o Espírito do Senhor se apoderou de Davi. Depois Samuel se levantou, e foi para Ramá.' },
      { v: 14, en: 'Now Yahweh’s Spirit departed from Saul, and an evil spirit from Yahweh troubled him.', pt: 'Ora, o Espírito do Senhor retirou-se de Saul, e o atormentava um espírito maligno da parte do Senhor.' },
      { v: 15, en: 'Saul’s servants said to him, “See now, an evil spirit from God troubles you.', pt: 'Então os criados de Saul lhe disseram: Eis que agora um espírito maligno da parte de Deus te atormenta;' },
      { v: 16, en: 'Let our lord now command your servants who are in front of you to seek out a man who is a skillful player on the harp. Then when the evil spirit from God is on you, he will play with his hand, and you will be well.”', pt: 'dize, pois, Senhor nosso, a teus servos que estão na tua presença, que busquem um homem que saiba tocar harpa; e quando o espírito maligno da parte do Senhor vier sobre ti, ele tocara com a sua mão, e te sentirás melhor.' },
      { v: 17, en: 'Saul said to his servants, “Provide me now a man who can play well, and bring him to me.”', pt: 'Então disse Saul aos seus servos: Buscai-me, pois, um homem que toque bem, e trazei-mo.' },
      { v: 18, en: 'Then one of the young men answered, and said, “Behold, I have seen a son of Jesse the Bethlehemite who is skillful in playing, a mighty man of valor, a man of war, prudent in speech, and a handsome person; and Yahweh is with him.”', pt: 'Respondeu um dos mancebos: Eis que tenho visto um filho de Jessé, o belemita, que sabe tocar bem, e é forte e destemido, homem de guerra, sisudo em palavras, e de gentil aspecto; e o Senhor é com ele.' },
      { v: 19, en: 'Therefore Saul sent messengers to Jesse, and said, “Send me David your son, who is with the sheep.”', pt: 'Pelo que Saul enviou mensageiros a Jessé, dizendo: Envia-me Davi, teu filho, o que está com as ovelhas.' },
      { v: 20, en: 'Jesse took a donkey loaded with bread, and a bottle of wine, and a young goat, and sent them by David his son to Saul.', pt: 'Jessé, pois, tomou um jumento carregado de pão, e um odre de vinho, e um cabrito, e os enviou a Saul pela mão de Davi, seu filho.' },
      { v: 21, en: 'David came to Saul, and stood before him. He loved him greatly; and he became his armor bearer.', pt: 'Assim Davi veio e se apresentou a Saul, que se agradou muito dele e o fez seu escudeiro.' },
      { v: 22, en: 'Saul sent to Jesse, saying, “Please let David stand before me; for he has found favor in my sight.”', pt: 'Então Saul mandou dizer a Jessé: Deixa ficar Davi ao meu serviço, pois achou graça aos meus olhos.' },
      { v: 23, en: 'When the spirit from God was on Saul, David took the harp, and played with his hand; so Saul was refreshed, and was well, and the evil spirit departed from him.', pt: 'E quando o espírito maligno da parte de Deus vinha sobre Saul, Davi tomava a harpa, e a tocava com a sua mão; então Saul sentia alívio, e se achava melhor, e o espírito maligno se retirava dele.' },
    ],
    17: [
      { v: 1, en: 'Now the Philistines gathered together their armies to battle; and they were gathered together at Socoh, which belongs to Judah, and encamped between Socoh and Azekah, in Ephesdammim.', pt: 'Ora, os filisteus ajuntaram as suas forças para a guerra e congregaram-se em Socó, que pertence a Judá, e acamparam entre Socó e Azeca, em Efes-Damim.' },
      { v: 2, en: 'Saul and the men of Israel were gathered together, and encamped in the valley of Elah, and set the battle in array against the Philistines.', pt: 'Saul, porém, e os homens de Israel se ajuntaram e acamparam no vale de Elá, e ordenaram a batalha contra os filisteus.' },
      { v: 3, en: 'The Philistines stood on the mountain on the one side, and Israel stood on the mountain on the other side: and there was a valley between them.', pt: 'Os filisteus estavam num monte de um lado, e os israelitas estavam num monte do outro lado; e entre eles o vale.' },
      { v: 4, en: 'A champion out of the camp of the Philistines named Goliath, of Gath, whose height was six cubits and a span went out.', pt: 'Então saiu do arraial dos filisteus um campeão, cujo nome era Golias, de Gate, que tinha de altura seis côvados e um palmo.' },
      { v: 5, en: 'He had a helmet of brass on his head, and he wore a coat of mail; and the weight of the coat was five thousand shekels of brass.', pt: 'Trazia na cabeça um capacete de bronze, e vestia uma couraça escameada, cujo peso era de cinco mil siclos de bronze.' },
      { v: 6, en: 'He had brass shin armor on his legs, and a brass javelin between his shoulders.', pt: 'Também trazia grevas de bronze nas pernas, e um dardo de bronze entre os ombros.' },
      { v: 7, en: 'The staff of his spear was like a weaver’s beam; and his spear’s head weighed six hundred shekels of iron. His shield bearer went before him.', pt: 'A haste da sua lança era como o órgão de um tear, e a ponta da sua lança pesava seiscentos siclos de ferro; adiante dele ia o seu escudeiro.' },
      { v: 8, en: 'He stood and cried to the armies of Israel, and said to them, “Why have you come out to set your battle in array? Am I not a Philistine, and you servants to Saul? Choose a man for yourselves, and let him come down to me.', pt: 'Ele, pois, de pé, clamava às fileiras de Israel e dizia-lhes: Por que saístes a ordenar a batalha? Não sou eu filisteu, e vós servos de Saul? Escolhei dentre vós um homem que desça a mim.' },
      { v: 9, en: 'If he is able to fight with me and kill me, then will we be your servants; but if I prevail against him and kill him, then you will be our servants and serve us.”', pt: 'Se ele puder pelejar comigo e matar-me, seremos vossos servos; porem, se eu prevalecer contra ele e o matar, então sereis nossos servos, e nos servireis.' },
      { v: 10, en: 'The Philistine said, “I defy the armies of Israel today! Give me a man, that we may fight together!”', pt: 'Disse mais o filisteu: Desafio hoje as fileiras de Israel; dai-me um homem, para que nós dois pelejemos.' },
      { v: 11, en: 'When Saul and all Israel heard those words of the Philistine, they were dismayed, and greatly afraid.', pt: 'Ouvindo, então, Saul e todo o Israel estas palavras do filisteu, desalentaram-se, e temeram muito.' },
      { v: 12, en: 'Now David was the son of that Ephrathite of Bethlehem Judah, whose name was Jesse; and he had eight sons. The man was an elderly old man in the days of Saul.', pt: 'Ora, Davi era filho de um homem efrateu, de Belém de Judá, cujo nome era Jessé, que tinha oito filhos; e nos dias de Saul este homem era já velho e avançado em idade entre os homens.' },
      { v: 13, en: 'The three oldest sons of Jesse had gone after Saul to the battle: and the names of his three sons who went to the battle were Eliab the firstborn, and next to him Abinadab, and the third Shammah.', pt: 'Os três filhos mais velhos de Jessé tinham seguido a Saul à guerra; eram os nomes de seus três filhos que foram à guerra: Eliabe, o primogênito, o segundo Abinadabe, e o terceiro Samá:' },
      { v: 14, en: 'David was the youngest; and the three oldest followed Saul.', pt: 'Davi era o mais moço; os três maiores seguiram a Saul,' },
      { v: 15, en: 'Now David went back and forth from Saul to feed his father’s sheep at Bethlehem.', pt: 'mas Davi ia e voltava de Saul, para apascentar as ovelhas de seu pai em Belem.' },
      { v: 16, en: 'The Philistine came near morning and evening, and presented himself forty days.', pt: 'Chegava-se, pois, o filisteu pela manhã e à tarde; e apresentou-se por quarenta dias.' },
      { v: 17, en: 'Jesse said to David his son, “Now take for your brothers an ephah of this parched grain, and these ten loaves, and carry them quickly to the camp to your brothers;', pt: 'Disse então Jessé a Davi, seu filho: Toma agora para teus irmãos uma refa deste grão tostado e estes dez pães, e corre a levá-los ao arraial, a teus irmãos.' },
      { v: 18, en: 'and bring these ten cheeses to the captain of their thousand, and see how your brothers are doing, and bring back news.”', pt: 'Leva, também, estes dez queijos ao seu comandante de mil; e verás como passam teus irmãos, e trarás notícias deles.' },
      { v: 19, en: 'Now Saul, and they, and all the men of Israel, were in the valley of Elah, fighting with the Philistines.', pt: 'Ora, estavam Saul, e eles, e todos os homens de Israel no vale de Elá, pelejando contra os filisteus.' },
      { v: 20, en: 'David rose up early in the morning, and left the sheep with a keeper, and took and went, as Jesse had commanded him. He came to the place of the wagons, as the army which was going out to the fight shouted for the battle.', pt: 'Davi então se levantou de madrugada e, deixando as ovelhas com um guarda, carregou-se e partiu, como Jessé lhe ordenara; e chegou ao arraial quando o exército estava saindo em ordem de batalha e dava gritos de guerra.' },
      { v: 21, en: 'Israel and the Philistines put the battle in array, army against army.', pt: 'Os israelitas e os filisteus se punham em ordem de batalha, fileira contra fileira.' },
      { v: 22, en: 'David left his baggage in the hand of the keeper of the baggage, and ran to the army, and came and greeted his brothers.', pt: 'E Davi, deixando na mão do guarda da bagagem a carga que trouxera, correu às fileiras; e, chegando, perguntou a seus irmãos se estavam bem.' },
      { v: 23, en: 'As he talked with them, behold, the champion, the Philistine of Gath, Goliath by name, came up out of the ranks of the Philistines, and said the same words; and David heard them.', pt: 'Enquanto ainda falava com eles, eis que veio subindo do exército dos filisteus o campeão, cujo nome era Golias, o filisteu de Gate, e falou conforme aquelas palavras; e Davi as ouviu.' },
      { v: 24, en: 'All the men of Israel, when they saw the man, fled from him, and were terrified.', pt: 'E todos os homens de Israel, vendo aquele homem, fugiam, de diante dele, tomados de pavor.' },
      { v: 25, en: 'The men of Israel said, “Have you seen this man who has come up? He has surely come up to defy Israel. The king will give great riches to the man who kills him, and will give him his daughter, and make his father’s house free in Israel.”', pt: 'Diziam os homens de Israel: Vistes aquele homem que subiu? pois subiu para desafiar a Israel. Ao homem, pos, que o matar, o rei cumulará de grandes riquezas, e lhe dará a sua filha, e fará livre a casa de seu pai em Israel.' },
      { v: 26, en: 'David spoke to the men who stood by him, saying, “What shall be done to the man who kills this Philistine, and takes away the reproach from Israel? For who is this uncircumcised Philistine, that he should defy the armies of the living God?”', pt: 'Então falou Davi aos homens que se achavam perto dele, dizendo: Que se fará ao homem que matar a esse filisteu, e tirar a afronta de sobre Israel? pois quem é esse incircunciso filisteu, para afrontar os exércitos do Deus vivo?' },
      { v: 27, en: 'The people answered him in this way, saying, “So shall it be done to the man who kills him.”', pt: 'E o povo lhe repetiu aquela palavra, dizendo: Assim se fará ao homem que o matar.' },
      { v: 28, en: 'Eliab his oldest brother heard when he spoke to the men; and Eliab’s anger burned against David, and he said, “Why have you come down? With whom have you left those few sheep in the wilderness? I know your pride, and the naughtiness of your heart; for you have come down that you might see the battle.”', pt: 'Eliabe, seu irmão mais velho, ouviu-o quando falava àqueles homens; pelo que se acendeu a sua ira contra Davi, e disse: Por que desceste aqui, e a quem deixaste aquelas poucas ovelhas no deserto? Eu conheço a tua presunção, e a maldade do teu coração; pois desceste para ver a peleja.' },
      { v: 29, en: 'David said, “What have I now done? Is there not a cause?”', pt: 'Respondeu Davi: Que fiz eu agora? porventura não há razão para isso?' },
      { v: 30, en: 'He turned away from him toward another, and spoke like that again; and the people answered him again the same way.', pt: 'E virou-se dele para outro, e repetiu as suas perguntas; e o povo lhe respondeu como da primeira vez.' },
      { v: 31, en: 'When the words were heard which David spoke, they rehearsed them before Saul; and he sent for him.', pt: 'Então, ouvidas as palavras que Davi falara, foram elas referidas a Saul, que mandou chamá-lo.' },
      { v: 32, en: 'David said to Saul, “Let no man’s heart fail because of him. Your servant will go and fight with this Philistine.”', pt: 'E Davi disse a Saul: Não desfaleça o coração de ninguém por causa dele; teu servo irá, e pelejará contra este filisteu.' },
      { v: 33, en: 'Saul said to David, “You are not able to go against this Philistine to fight with him; for you are but a youth, and he a man of war from his youth.”', pt: 'Saul, porém, disse a Davi: Não poderás ir contra esse filisteu para pelejar com ele, pois tu ainda és moço, e ele homem de guerra desde a sua mocidade.' },
      { v: 34, en: 'David said to Saul, “Your servant was keeping his father’s sheep; and when a lion or a bear came, and took a lamb out of the flock,', pt: 'Então disse Davi a Saul: Teu servo apascentava as ovelhas de seu pai, e sempre que vinha um leão, ou um urso, e tomava um cordeiro do rebanho,' },
      { v: 35, en: 'I went out after him, and struck him, and rescued it out of his mouth. When he arose against me, I caught him by his beard, and struck him, and killed him.', pt: 'eu saía após ele, e o matava, e lho arrancava da boca; levantando-se ele contra mim, segurava-o pela queixada, e o feria e matava.' },
      { v: 36, en: 'Your servant struck both the lion and the bear. This uncircumcised Philistine shall be as one of them, since he has defied the armies of the living God.”', pt: 'O teu servo matava tanto ao leão como ao urso; e este incircunciso filisteu será como um deles, porquanto afrontou os exércitos do Deus vivo.' },
      { v: 37, en: 'David said, “Yahweh who delivered me out of the paw of the lion, and out of the paw of the bear, he will deliver me out of the hand of this Philistine.” Saul said to David, “Go! Yahweh will be with you.”', pt: 'Disse mais Davi: O Senhor, que me livrou das garras do leão, e das garras do urso, me livrará da mão deste filisteu. Então disse Saul a Davi: Vai, e o Senhor seja contigo.' },
      { v: 38, en: 'Saul dressed David with his clothing. He put a helmet of brass on his head, and he clad him with a coat of mail.', pt: 'E vestiu a Davi da sua própria armadura, pôs-lhe sobre a cabeça um capacete de bronze, e o vestiu de uma couraça.' },
      { v: 39, en: 'David strapped his sword on his clothing, and he tried to move; for he had not tested it. David said to Saul, “I can’t go with these; for I have not tested them.” Then David took them off.', pt: 'Davi cingiu a espada sobre a armadura e procurou em vão andar, pois não estava acostumado àquilo. Então disse Davi a Saul: Não posso andar com isto, pois não estou acostumado. E Davi tirou aquilo de sobre si.' },
      { v: 40, en: 'He took his staff in his hand, and chose for himself five smooth stones out of the brook, and put them in the pouch of his shepherd’s bag which he had. His sling was in his hand; and he came near to the Philistine.', pt: 'Então tomou na mão o seu cajado, escolheu do ribeiro cinco seixos lisos e pô-los no alforje de pastor que trazia, a saber, no surrão, e, tomando na mão a sua funda, foi-se chegando ao filisteu.' },
      { v: 41, en: 'The Philistine walked and came near to David; and the man who bore the shield went before him.', pt: 'O filisteu também vinha se aproximando de Davi, tendo a: sua frente o seu escudeiro.' },
      { v: 42, en: 'When the Philistine looked around, and saw David, he disdained him; for he was but a youth, and ruddy, and had a good looking face.', pt: 'Quando o filisteu olhou e viu a Davi, desprezou-o, porquanto era mancebo, ruivo, e de gentil aspecto.' },
      { v: 43, en: 'The Philistine said to David, “Am I a dog, that you come to me with sticks?” The Philistine cursed David by his gods.', pt: 'Disse o filisteu a Davi: Sou eu algum cão, para tu vires a mim com paus? E o filisteu, pelos seus deuses, amaldiçoou a Davi.' },
      { v: 44, en: 'The Philistine said to David, “Come to me, and I will give your flesh to the birds of the sky, and to the animals of the field.”', pt: 'Disse mais o filisteu a Davi: Vem a mim, e eu darei a tua carne às aves do céu e às bestas do campo.' },
      { v: 45, en: 'Then David said to the Philistine, “You come to me with a sword, with a spear, and with a javelin; but I come to you in the name of Yahweh of Armies, the God of the armies of Israel, whom you have defied.', pt: 'Davi, porém, lhe respondeu: Tu vens a mim com espada, com lança e com escudo; mas eu venho a ti em nome do Senhor dos exércitos, o Deus dos exércitos de Israel, a quem tens afrontado.' },
      { v: 46, en: 'Today, Yahweh will deliver you into my hand. I will strike you, and take your head from off you. I will give the dead bodies of the army of the Philistines today to the birds of the sky, and to the wild animals of the earth; that all the earth may know that there is a God in Israel,', pt: 'Hoje mesmo o Senhor te entregará na minha mão; ferir-te-ei, e tirar-te-ei a cabeça; os cadáveres do arraial dos filisteus darei hoje mesmo às aves do céu e às feras da terra; para que toda a terra saiba que há Deus em Israel;' },
      { v: 47, en: 'and that all this assembly may know that Yahweh doesn’t save with sword and spear; for the battle is Yahweh’s, and he will give you into our hand.”', pt: 'e para que toda esta assembléia saiba que o Senhor salva, não com espada, nem com lança; pois do Senhor é a batalha, e ele vos entregará em nossas mãos.' },
      { v: 48, en: 'When the Philistine arose, and walked and came near to meet David, David hurried, and ran toward the army to meet the Philistine.', pt: 'Quando o filisteu se levantou e veio chegando para se defrontar com Davi, este se apressou e correu ao combate, a encontrar-se com o filisteu.' },
      { v: 49, en: 'David put his hand in his bag, took a stone, and slung it, and struck the Philistine in his forehead. The stone sank into his forehead, and he fell on his face to the earth.', pt: 'E Davi, metendo a mão no alforje, tirou dali uma pedra e com a funda lha atirou, ferindo o filisteu na testa; a pedra se lhe cravou na testa, e ele caiu com o rosto em terra.' },
      { v: 50, en: 'So David prevailed over the Philistine with a sling and with a stone, and struck the Philistine, and killed him; but there was no sword in the hand of David.', pt: 'Assim Davi prevaleceu contra o filisteu com uma funda e com uma pedra; feriu-o e o matou; e não havia espada na mão de Davi.' },
      { v: 51, en: 'Then David ran, stood over the Philistine, took his sword, drew it out of its sheath, killed him, and cut off his head with it. When the Philistines saw that their champion was dead, they fled.', pt: 'Correu, pois, Davi, pôs-se em pé sobre o filisteu e, tomando a espada dele e tirando-a da bainha, o matou, decepando-lhe com ela a cabeça. Vendo então os filisteus que o seu campeão estava morto, fugiram.' },
      { v: 52, en: 'The men of Israel and of Judah arose and shouted, and pursued the Philistines as far as Gai and to the gates of Ekron. The wounded of the Philistines fell down by the way to Shaaraim, even to Gath and to Ekron.', pt: 'Então os homens de Israel e de Judá se levantaram gritando, e perseguiram os filisteus até a entrada de Gai e até as portas de Ecrom; e caíram os feridos dos filisteus pelo caminho de Saraim até Gate e até Ecrom.' },
      { v: 53, en: 'The children of Israel returned from chasing after the Philistines and they plundered their camp.', pt: 'Depois voltaram os filhos de Israel de perseguirem os filisteus, e despojaram os seus arraiais.' },
      { v: 54, en: 'David took the head of the Philistine, and brought it to Jerusalem; but he put his armor in his tent.', pt: 'Davi tomou a cabeça do filisteu e a trouxe a Jerusalém; porém pôs as armas dele na sua tenda.' },
      { v: 55, en: 'When Saul saw David go out against the Philistine, he said to Abner, the captain of the army, “Abner, whose son is this youth?” Abner said, “As your soul lives, O king, I can’t tell.”', pt: 'Quando Saul viu Davi sair e encontrar-se com o filisteu, perguntou a Abner, o chefe do exército: De quem é filho esse jovem, Abner? Respondeu Abner: Vive a tua alma, ó rei, que não sei.' },
      { v: 56, en: 'The king said, “Inquire whose son the young man is!”', pt: 'Disse então o rei: Pergunta, pois, de quem ele é filho.' },
      { v: 57, en: 'As David returned from the slaughter of the Philistine, Abner took him and brought him before Saul with the head of the Philistine in his hand.', pt: 'Voltando, pois, Davi de ferir o filisteu, Abner o tomou consigo, e o trouxe à presença de Saul, trazendo Davi na mão a cabeça do filisteu.' },
      { v: 58, en: 'Saul said to him, “Whose son are you, you young man?” David answered, “I am the son of your servant Jesse the Bethlehemite.”', pt: 'E perguntou-lhe Saul: De quem és filho, jovem? Respondeu Davi: Filho de teu servo Jessé, belemita.' },
    ],
    18: [
      { v: 1, en: 'When he had finished speaking to Saul, the soul of Jonathan was knit with the soul of David, and Jonathan loved him as his own soul.', pt: 'Ora, acabando Davi de falar com Saul, a alma de Jônatas ligou-se com a alma de Davi; e Jônatas o amou como à sua própria alma.' },
      { v: 2, en: 'Saul took him that day, and would let him go no more home to his father’s house.', pt: 'E desde aquele dia Saul o reteve, não lhe permitindo voltar para a casa de seu pai.' },
      { v: 3, en: 'Then Jonathan and David made a covenant, because he loved him as his own soul.', pt: 'Então Jônatas fez um pacto com Davi, porque o amava como à sua própria vida.' },
      { v: 4, en: 'Jonathan stripped himself of the robe that was on him, and gave it to David, and his clothing, even including his sword, his bow, and his sash.', pt: 'E Jônatas se despojou da capa que vestia, e a deu a Davi, como também a sua armadura, e até mesmo a sua espada, o seu arco e o seu cinto.' },
      { v: 5, en: 'David went out wherever Saul sent him, and behaved himself wisely; and Saul set him over the men of war. It was good in the sight of all the people, and also in the sight of Saul’s servants.', pt: 'E saía Davi aonde quer que Saul o enviasse, e era sempre bem sucedido; e Saul o pôs sobre a gente de guerra, e isso pareceu bem aos olhos de todo o povo, e até aos olhos dos servos de Saul.' },
      { v: 6, en: 'As they came, when David returned from the slaughter of the Philistine, the women came out of all the cities of Israel, singing and dancing, to meet king Saul, with tambourines, with joy, and with instruments of music.', pt: 'Sucedeu porém que, retornando eles, quando Davi voltava de ferir o filisteu, as mulheres de todas as cidades de Israel saíram ao encontro do rei Saul, cantando e dançando alegremente, com tamboris, e com instrumentos de música.' },
      { v: 7, en: 'The women sang to one another as they played, and said, “Saul has slain his thousands, and David his ten thousands.”', pt: 'E as mulheres, dançando, cantavam umas para as outras, dizendo: Saul feriu os seus milhares, porém Davi os seus dez milhares.' },
      { v: 8, en: 'Saul was very angry, and this saying displeased him. He said, “They have ascribed to David ten thousands, and to me they have ascribed only thousands. What can he have more but the kingdom?”', pt: 'Então Saul se indignou muito, pois aquela palavra pareceu mal aos seus olhos, e disse: Dez milhares atribuíram a Davi, e a mim somente milhares; que lhe falta, senão só o reino?' },
      { v: 9, en: 'Saul watched David from that day and forward.', pt: 'Daquele dia em diante, Saul trazia Davi sob suspeita.' },
      { v: 10, en: 'On the next day, an evil spirit from God came mightily on Saul, and he prophesied in the middle of the house. David played with his hand, as he did day by day. Saul had his spear in his hand;', pt: 'No dia seguinte o espírito maligno da parte de Deus se apoderou de Saul, que começou a profetizar no meio da casa; e Davi tocava a harpa, como nos outros dias. Saul tinha na mão uma lança.' },
      { v: 11, en: 'and Saul threw the spear, for he said, “I will pin David even to the wall!” David escaped from his presence twice.', pt: 'E Saul arremessou a lança, dizendo consigo: Encravarei a Davi na parede. Davi, porém, desviou-se dele por duas vezes.' },
      { v: 12, en: 'Saul was afraid of David, because Yahweh was with him, and had departed from Saul.', pt: 'Saul, pois, temia a Davi, porque o Senhor era com Davi e se tinha retirado dele.' },
      { v: 13, en: 'Therefore Saul removed him from his presence, and made him his captain over a thousand; and he went out and came in before the people.', pt: 'Pelo que Saul o afastou de si, e o fez comandante de mil; e ele saía e entrava diante do povo.' },
      { v: 14, en: 'David behaved himself wisely in all his ways; and Yahweh was with him.', pt: 'E Davi era bem sucedido em todos os seus caminhos; e o Senhor era com ele.' },
      { v: 15, en: 'When Saul saw that he behaved himself very wisely, he stood in awe of him.', pt: 'Vendo, então, Saul que ele era tão bem sucedido, tinha receio dele.' },
      { v: 16, en: 'But all Israel and Judah loved David; for he went out and came in before them.', pt: 'Mas todo o Israel e Judá amavam a Davi, porquanto saía e entrava diante deles.' },
      { v: 17, en: 'Saul said to David, “Behold, my elder daughter Merab, I will give her to you as wife. Only be valiant for me, and fight Yahweh’s battles.” For Saul said, “Don’t let my hand be on him, but let the hand of the Philistines be on him.”', pt: 'Pelo que Saul disse a Davi: Eis que Merabe, minha filha mais velha, te darei por mulher, contanto que me sejas filho valoroso, e guerreies as guerras do Senhor. Pois Saul dizia consigo: Não seja contra ele a minha mão, mas sim a dos filisteus.' },
      { v: 18, en: 'David said to Saul, “Who am I, and what is my life, or my father’s family in Israel, that I should be son-in-law to the king?”', pt: 'Mas Davi disse a Saul: Quem sou eu, e qual é a minha vida e a família de meu pai em Israel, para eu vir a ser genro do rei?' },
      { v: 19, en: 'But at the time when Merab, Saul’s daughter, should have been given to David, she was given to Adriel the Meholathite as wife.', pt: 'Sucedeu, porém, que ao tempo em que Merabe, filha de Saul, devia ser dada a Davi, foi dada por mulher a Adriel, meolatita.' },
      { v: 20, en: 'Michal, Saul’s daughter, loved David; and they told Saul, and the thing pleased him.', pt: 'Mas Mical, a outra filha de Saul, amava a Davi; sendo isto anunciado a Saul, pareceu bem aos seus olhos.' },
      { v: 21, en: 'Saul said, I will give her to him, that she may be a snare to him, and that the hand of the Philistines may be against him. Therefore Saul said to David, “You shall today be my son-in-law a second time.”', pt: 'E Saul disse: Eu lha darei, para que ela lhe sirva de laço, e para que a mão dos filisteus venha a ser contra ele. Pelo que Saul disse a Davi: com a outra serás hoje meu genro.' },
      { v: 22, en: 'Saul commanded his servants, “Talk with David secretly, and say, ‘Behold, the king has delight in you, and all his servants love you. Now therefore be the king’s son-in-law.’”', pt: 'Saul, pois, deu ordem aos seus servos: Falai em segredo a Davi, dizendo: Eis que o rei se agrada de ti, e todos os seus servos te querem bem; agora, pois, consente em ser genro do rei.' },
      { v: 23, en: 'Saul’s servants spoke those words in the ears of David. David said, “Does it seem to you a light thing to be the king’s son-in-law, since I am a poor man, and little known?”', pt: 'Assim os servos de Saul falaram todas estas palavras aos ouvidos de Davi. Então disse Davi: Parece-vos pouca coisa ser genro do rei, sendo eu homem pobre e de condição humilde?' },
      { v: 24, en: 'The servants of Saul told him, saying, “David spoke like this.”', pt: 'E os servos de Saul lhe anunciaram isto, dizendo: Assim e assim falou Davi.' },
      { v: 25, en: 'Saul said, “Tell David, ‘The king desires no dowry except one hundred foreskins of the Philistines, to be avenged of the king’s enemies.’” Now Saul thought he would make David fall by the hand of the Philistines.', pt: 'Então disse Saul: Assim direis a Davi: O rei não deseja dote, senão cem prepúcios de filisteus, para que seja vingado dos seus inimigos. Porquanto Saul tentava fazer Davi cair pela mão dos filisteus.' },
      { v: 26, en: 'When his servants told David these words, it pleased David well to be the king’s son-in-law. Before the deadline,', pt: 'Tendo os servos de Saul anunciado estas palavras a Davi, pareceu bem aos seus olhos tornar-se genro do rei. Ora, ainda os dias não se haviam cumprido,' },
      { v: 27, en: 'David arose and went, he and his men, and killed two hundred men of the Philistines. Then David brought their foreskins, and they gave them in full number to the king, that he might be the king’s son-in-law. Then Saul gave him Michal his daughter as wife.', pt: 'quando Davi se levantou, partiu com os seus homens, e matou dentre os filisteus duzentos homens; e Davi trouxe os prepúcios deles, e os entregou, bem contados, ao rei, para que fosse seu genro. Então Saul lhe deu por mulher sua filha Mical.' },
      { v: 28, en: 'Saul saw and knew that Yahweh was with David; and Michal, Saul’s daughter, loved him.', pt: 'Mas quando Saul viu e compreendeu que o Senhor era com Davi e que todo o Israel o amava,' },
      { v: 29, en: 'Saul was even more afraid of David; and Saul was David’s enemy continually.', pt: 'temeu muito mais a Davi; e Saul se tornava cada vez mais seu inimigo.' },
      { v: 30, en: 'Then the princes of the Philistines went out; and as often as they went out, David behaved himself more wisely than all the servants of Saul, so that his name was highly esteemed.', pt: 'Então saíram os chefes dos filisteus à campanha; e sempre que eles saíam, Davi era mais bem sucedido do que todos os servos de Saul, pelo que o seu nome era mui estimado.' },
    ],
    19: [
      { v: 1, en: 'Saul spoke to Jonathan his son, and to all his servants, that they should kill David. But Jonathan, Saul’s son, greatly delighted in David.', pt: 'Falou, pois, Saul a Jônatas, seu filho, e a todos os seus servos, para que matassem a Davi. Porém Jônatas, filho de Saul, estava muito afeiçoado a Davi.' },
      { v: 2, en: 'Jonathan told David, saying, “Saul my father seeks to kill you. Now therefore, please take care of yourself in the morning, and live in a secret place, and hide yourself.', pt: 'Pelo que Jônatas o anunciou a Davi, dizendo: Saul, meu pai, procura matar-te; portanto, guarda-te amanhã pela manhã, fica num lugar oculto e esconde-te;' },
      { v: 3, en: 'I will go out and stand beside my father in the field where you are, and I will talk with my father about you; and if I see anything, I will tell you.”', pt: 'eu sairei e me porei ao lado de meu pai no campo em que estiveres; falarei acerca de ti a meu pai, verei o que há, e to anunciarei.' },
      { v: 4, en: 'Jonathan spoke good of David to Saul his father, and said to him, “Don’t let the king sin against his servant, against David; because he has not sinned against you, and because his works have been very good toward you;', pt: 'Então Jônatas falou bem de Davi a Saul, seu pai, e disse-lhe: Não peque o rei contra seu servo Davi, porque ele não pecou contra ti, e porque os seus feitos para contigo têm sido muito bons.' },
      { v: 5, en: 'for he put his life in his hand, and struck the Philistine, and Yahweh worked a great victory for all Israel. You saw it, and rejoiced. Why then will you sin against innocent blood, to kill David without a cause?”', pt: 'Porque expôs a sua vida e matou o filisteu, e o Senhor fez um grande livramento para todo o Israel. Tu mesmo o viste, e te alegraste; por que, pois, pecarias contra o sangue inocente, matando sem causa a Davi?' },
      { v: 6, en: 'Saul listened to the voice of Jonathan: and Saul swore, “As Yahweh lives, he shall not be put to death.”', pt: 'E Saul deu ouvidos à voz de Jônatas, e jurou: Como vive o Senhor, Davi não morrera.' },
      { v: 7, en: 'Jonathan called David, and Jonathan showed him all those things. Then Jonathan brought David to Saul, and he was in his presence, as before.', pt: 'Jônatas, pois, chamou a Davi, contou-lhe todas estas palavras, e o levou a Saul; e Davi o assistia como dantes.' },
      { v: 8, en: 'There was war again. David went out, and fought with the Philistines, and killed them with a great slaughter; and they fled before him.', pt: 'Depois tornou a haver guerra; e saindo Davi, pelejou contra os filisteus, e os feriu com grande matança, e eles fugiram diante dele.' },
      { v: 9, en: 'An evil spirit from Yahweh was on Saul, as he sat in his house with his spear in his hand; and David was playing with his hand.', pt: 'Então o espírito maligno da parte do Senhor veio sobre Saul, estando ele sentado em sua casa, e tendo na mão a sua lança; e Davi estava tocando a harpa.' },
      { v: 10, en: 'Saul sought to pin David to the wall with the spear; but he slipped away out of Saul’s presence, and he stuck the spear into the wall. David fled, and escaped that night.', pt: 'E Saul procurou encravar a Davi na parede, porém ele se desviou de diante de Saul, que fincou a lança na parede. Então Davi fugiu, e escapou naquela mesma noite.' },
      { v: 11, en: 'Saul sent messengers to David’s house, to watch him, and to kill him in the morning. Michal, David’s wife, told him, saying, “If you don’t save your life tonight, tomorrow you will be killed.”', pt: 'Mas Saul mandou mensageiros à casa de Davi, para que o vigiassem, e o matassem pela manhã; porém Mical, mulher de Davi, o avisou, dizendo: Se não salvares a tua vida esta noite, amanhã te matarão.' },
      { v: 12, en: 'So Michal let David down through the window. He went away, fled, and escaped.', pt: 'Então Mical desceu Davi por uma janela, e ele se foi e, fugindo, escapou.' },
      { v: 13, en: 'Michal took the teraphim, and laid it in the bed, and put a pillow of goats’ hair at its head, and covered it with clothes.', pt: 'Mical tomou uma estátua, deitou-a na cama, pôs-lhe à cabeceira uma pele de cabra, e a cobriu com uma capa.' },
      { v: 14, en: 'When Saul sent messengers to take David, she said, “He is sick.”', pt: 'Quando Saul enviou mensageiros para prenderem a Davi, ela disse: Está doente.' },
      { v: 15, en: 'Saul sent the messengers to see David, saying, “Bring him up to me in the bed, that I may kill him.”', pt: 'Tornou Saul a enviá-los, para que vissem a Davi, dizendo-lhes: Trazei-mo na cama, para que eu o mate.' },
      { v: 16, en: 'When the messengers came in, behold, the teraphim was in the bed, with the pillow of goats’ hair at its head.', pt: 'Vindo, pois, os mensageiros, eis que estava a estátua na cama, e a pele de cabra à sua cabeceira.' },
      { v: 17, en: 'Saul said to Michal, “Why have you deceived me thus, and let my enemy go, so that he is escaped?” Michal answered Saul, “He said to me, ‘Let me go! Why should I kill you?’”', pt: 'Então perguntou Saul a Mical: Por que assim me enganaste, e deixaste o meu inimigo ir e escapar? Respondeu Mical a Saul: Porque ele me disse: Deixa-me ir! Por que hei de matar-te?' },
      { v: 18, en: 'Now David fled and escaped, and came to Samuel at Ramah, and told him all that Saul had done to him. He and Samuel went and lived in Naioth.', pt: 'Assim Davi fugiu e escapou; e indo ter com Samuel, em Ramá, contou-lhe tudo quanto Saul lhe fizera; foram, pois, ele e Samuel, e ficaram em Naiote.' },
      { v: 19, en: 'Saul was told, saying, “Behold, David is at Naioth in Ramah.”', pt: 'E foi dito a Saul: Eis que Davi está em Naiote, em Ramá.' },
      { v: 20, en: 'Saul sent messengers to seize David: and when they saw the company of the prophets prophesying, and Samuel standing as head over them, God’s Spirit came on Saul’s messengers, and they also prophesied.', pt: 'Então enviou Saul mensageiros para prenderem a Davi; quando eles viram a congregação de profetas profetizando, e Samuel a presidi-los, o Espírito de Deus veio sobre os mensageiros de Saul, e também eles profetizaram.' },
      { v: 21, en: 'When Saul was told, he sent other messengers, and they also prophesied. Saul sent messengers again the third time, and they also prophesied.', pt: 'Avisado disso, Saul enviou outros mensageiros, e também estes profetizaram. Ainda terceira vez enviou Saul mensageiros, os quais também profetizaram.' },
      { v: 22, en: 'Then he also went to Ramah, and came to the great well that is in Secu: and he asked, “Where are Samuel and David?” One said, “Behold, they are at Naioth in Ramah.”', pt: 'Então foi ele mesmo a Rama e, chegando ao poço grande que estava em Sécu, perguntou: Onde estão Samuel e Davi? Responderam-lhe: Eis que estão em Naiote, em Ramá.' },
      { v: 23, en: 'He went there to Naioth in Ramah. Then God’s Spirit came on him also, and he went on, and prophesied, until he came to Naioth in Ramah.', pt: 'Foi, pois, para Naiote, em Ramá; e o Espírito de Deus veio também sobre ele, e ele ia caminhando e profetizando, até chegar a Naiote, em Ramá.' },
      { v: 24, en: 'He also stripped off his clothes, and he also prophesied before Samuel, and lay down naked all that day and all that night. Therefore they say, “Is Saul also among the prophets?”', pt: 'E despindo as suas vestes, ele também profetizou diante de Samuel; e esteve nu por terra todo aquele dia e toda aquela noite. Pelo que se diz: Está também Saul entre os profetas?' },
    ],
    20: [
      { v: 1, en: 'David fled from Naioth in Ramah, and came and said before Jonathan, “What have I done? What is my iniquity? What is my sin before your father, that he seeks my life?”', pt: 'Então fugiu Davi de Naiote, em Ramá, veio ter com Jônatas e lhe disse: Que fiz eu? qual é a minha iniqüidade? e qual é o meu pecado diante de teu pai, para que procure tirar-me a vida?' },
      { v: 2, en: 'He said to him, “Far from it; you will not die. Behold, my father does nothing either great or small, but that he discloses it to me. Why would my father hide this thing from me? It is not so.”', pt: 'E ele lhe disse: Longe disso! não hás de morrer. Meu pai não faz coisa alguma, nem grande nem pequena, sem que primeiro ma participe; por que, pois, meu pai me encobriria este negócio? Não é verdade.' },
      { v: 3, en: 'David swore moreover, and said, “Your father knows well that I have found favor in your eyes; and he says, ‘Don’t let Jonathan know this, lest he be grieved:’ but truly as Yahweh lives, and as your soul lives, there is but a step between me and death.”', pt: 'Respondeu-lhe Davi, com juramento: Teu pai bem sabe que achei graça aos teus olhos; pelo que disse: Não saiba isto Jônatas, para que não se magoe. Mas, na verdade, como vive o Senhor, e como vive a tua alma, há apenas um passo entre mim e a morte.' },
      { v: 4, en: 'Then Jonathan said to David, “Whatever your soul desires, I will even do it for you.”', pt: 'Disse Jônatas a Davi: O que desejas tu que eu te faça?' },
      { v: 5, en: 'David said to Jonathan, “Behold, tomorrow is the new moon, and I should not fail to dine with the king; but let me go, that I may hide myself in the field to the third day at evening.', pt: 'Respondeu Davi a Jônatas: Eis que amanhã é a lua nova, e eu deveria sentar-me com o rei para comer; porém deixa-me ir, e esconder-me-ei no campo até a tarde do terceiro dia.' },
      { v: 6, en: 'If your father misses me at all, then say, ‘David earnestly asked leave of me that he might run to Bethlehem his city; for it is the yearly sacrifice there for all the family.’', pt: 'Se teu pai notar a minha ausência, dirás: Davi me pediu muito que o deixasse ir correndo a Belém, sua cidade, porquanto se faz lá o sacrifício anual para toda a parentela.' },
      { v: 7, en: 'If he says, ‘It is well;’ your servant shall have peace: but if he is angry, then know that evil is determined by him.', pt: 'Se ele disser: Está bem; então teu servo tem paz; porém se ele muito se indignar, fica sabendo que ele já está resolvido a praticar o mal.' },
      { v: 8, en: 'Therefore deal kindly with your servant; for you have brought your servant into a covenant of Yahweh with you; but if there is iniquity in me, kill me yourself; for why should you bring me to your father?”', pt: 'Usa, pois, de misericórdia para com o teu servo, porque o fizeste entrar contigo em aliança do Senhor; se, porém, há culpa em mim, mata-me tu mesmo; por que me levarias a teu pai?' },
      { v: 9, en: 'Jonathan said, “Far be it from you; for if I should at all know that evil were determined by my father to come on you, then wouldn’t I tell you that?”', pt: 'Ao que respondeu Jônatas: Longe de ti tal coisa! Se eu soubesse que meu pai estava resolvido a trazer o mal sobre ti, não to descobriria eu?' },
      { v: 10, en: 'Then David said to Jonathan, “Who will tell me if your father answers you roughly?”', pt: 'Perguntou, pois, Davi a Jônatas: Quem me fará saber, se por acaso teu pai te responder asperamente?' },
      { v: 11, en: 'Jonathan said to David, “Come, and let us go out into the field.” They both went out into the field.', pt: 'Então disse Jônatas a Davi: Vem, e saiamos ao campo. E saíram ambos ao campo.' },
      { v: 12, en: 'Jonathan said to David, “By Yahweh, the God of Israel, when I have sounded my father about this time tomorrow, or the third day, behold, if there is good toward David, won’t I then send to you, and disclose it to you?', pt: 'E disse Jônatas a Davi: O Senhor, Deus de Israel, seja testemunha! Sondando eu a meu pai amanhã a estas horas, ou depois de amanhã, se houver coisa favorável para Davi, eu não enviarei a ti e não to farei saber?' },
      { v: 13, en: 'Yahweh do so to Jonathan, and more also, should it please my father to do you evil, if I don’t disclose it to you, and send you away, that you may go in peace. May Yahweh be with you, as he has been with my father.', pt: 'O Senhor faça assim a Jônatas, e outro tanto, se, querendo meu pai fazer-te mal, eu não te fizer saber, e não te deixar partir, para ires em paz; e o Senhor seja contigo, assim como foi com meu pai.' },
      { v: 14, en: 'You shall not only while yet I live show me the loving kindness of Yahweh, that I not die;', pt: 'E não somente usarás para comigo, enquanto viver, da benevolência do Senhor, para que não morra,' },
      { v: 15, en: 'but you shall also not cut off your kindness from my house forever; no, not when Yahweh has cut off every one of the enemies of David from the surface of the earth.”', pt: 'como também não cortarás nunca da minha casa a tua benevolência, nem ainda quando o Senhor tiver desarraigado da terra a cada um dos inimigos de Davi.' },
      { v: 16, en: 'So Jonathan made a covenant with David’s house, saying, “Yahweh will require it at the hand of David’s enemies.”', pt: 'Assim fez Jônatas aliança com a casa de Davi, dizendo: O Senhor se vingue dos inimigos de Davi.' },
      { v: 17, en: 'Jonathan caused David to swear again, for the love that he had to him; for he loved him as he loved his own soul.', pt: 'Então Jônatas fez Davi jurar de novo, porquanto o amava; porque o amava com todo o amor da sua alma.' },
      { v: 18, en: 'Then Jonathan said to him, “Tomorrow is the new moon, and you will be missed, because your seat will be empty.', pt: 'Disse-lhe ainda Jônatas: Amanhã é a lua nova, e notar-se-á a tua ausência, pois o teu lugar estará vazio.' },
      { v: 19, en: 'When you have stayed three days, go down quickly, and come to the place where you hid yourself when this started, and remain by the stone Ezel.', pt: 'Ao terceiro dia descerás apressadamente, e irás àquele lugar onde te escondeste no dia do negócio, e te sentarás junto à pedra de Ezel.' },
      { v: 20, en: 'I will shoot three arrows on its side, as though I shot at a mark.', pt: 'E eu atirarei três flechas para aquela banda, como se atirasse ao alvo.' },
      { v: 21, en: 'Behold, I will send the boy, saying, ‘Go, find the arrows!’ If I tell the boy, ‘Behold, the arrows are on this side of you. Take them;’ then come; for there is peace to you and no danger, as Yahweh lives.', pt: 'Então mandarei o moço, dizendo: Anda, busca as flechas. Se eu expressamente disser ao moço: Olha que as flechas estão para cá de ti, apanha-as; então vem, porque, como vive o Senhor, há paz para ti, e não há nada a temer.' },
      { v: 22, en: 'But if I say this to the boy, ‘Behold, the arrows are beyond you;’ then go your way; for Yahweh has sent you away.', pt: 'Mas se eu disser ao moço assim: Olha que as flechas estão para lá de ti; vai-te embora, porque o Senhor te manda ir.' },
      { v: 23, en: 'Concerning the matter which you and I have spoken of, behold, Yahweh is between you and me forever.”', pt: 'E quanto ao negócio de que eu e tu falamos, o Senhor é testemunha entre mim e ti para sempre.' },
      { v: 24, en: 'So David hid himself in the field. When the new moon had come, the king sat himself down to eat food.', pt: 'Escondeu-se, pois, Davi no campo; e, sendo a lua nova, sentou-se o rei para comer.' },
      { v: 25, en: 'The king sat on his seat, as at other times, even on the seat by the wall; and Jonathan stood up, and Abner sat by Saul’s side, but David’s place was empty.', pt: 'E, sentando-se o rei, como de costume, no seu assento junto à parede, Jônatas sentou-se defronte dele, e Abner sentou-se ao lado de Saul; e o lugar de Davi ficou vazio.' },
      { v: 26, en: 'Nevertheless Saul didn’t say anything that day, for he thought, “Something has happened to him. He is not clean. Surely he is not clean.”', pt: 'Entretanto Saul não disse nada naquele dia, pois dizia consigo: Aconteceu-lhe alguma coisa pela qual não está limpo; certamente não está limpo.' },
      { v: 27, en: 'On the next day after the new moon, the second day, David’s place was empty. Saul said to Jonathan his son, “Why doesn’t the son of Jesse come to eat, either yesterday, or today?”', pt: 'Sucedeu também no dia seguinte, o segundo da lua nova, que o lugar de Davi ficou vazio. Perguntou, pois, Saul a Jônatas, seu filho: Por que o filho de Jessé não veio comer nem ontem nem hoje?' },
      { v: 28, en: 'Jonathan answered Saul, “David earnestly asked permission of me to go to Bethlehem.', pt: 'Respondeu Jônatas a Saul: Davi pediu-me encarecidamente licença para ir a Belém,' },
      { v: 29, en: 'He said, ‘Please let me go, for our family has a sacrifice in the city. My brother has commanded me to be there. Now, if I have found favor in your eyes, please let me go away and see my brothers.’ Therefore he has not come to the king’s table.”', pt: 'dizendo: Peço-te que me deixes ir, porquanto a nossa parentela tem um sacrifício na cidade, e meu irmão ordenou que eu fosse; se, pois, agora tenho achado graça aos teus olhos, peço-te que me deixes ir, para ver a meus irmãos. Por isso não veio à mesa do rei.' },
      { v: 30, en: 'Then Saul’s anger burned against Jonathan, and he said to him, “You son of a perverse rebellious woman, don’t I know that you have chosen the son of Jesse to your own shame, and to the shame of your mother’s nakedness?', pt: 'Então se acendeu a ira de Saul contra Jônatas, e ele lhe disse: Filho da perversa e rebelde! Não sei eu que tens escolhido a filho de Jessé para vergonha tua, e para vergonha de tua mãe?' },
      { v: 31, en: 'For as long as the son of Jesse lives on the earth, you will not be established, nor will your kingdom. Therefore now send and bring him to me, for he shall surely die!”', pt: 'Pois por todo o tempo em que o filho de Jessé viver sobre a terra, nem tu estarás seguro, nem o teu reino; pelo que envia agora, e traze-mo, porque ele há de morrer.' },
      { v: 32, en: 'Jonathan answered Saul his father, and said to him, “Why should he be put to death? What has he done?”', pt: 'Ao que respondeu Jônatas a Saul, seu pai, e lhe disse: Por que há de morrer. que fez ele?' },
      { v: 33, en: 'Saul cast his spear at him to strike him. By this Jonathan knew that his father was determined to put David to death.', pt: 'Então Saul levantou a lança, para o ferir; assim entendeu Jônatas que seu pai tinha determinado matar a Davi.' },
      { v: 34, en: 'So Jonathan arose from the table in fierce anger, and ate no food the second day of the month; for he was grieved for David, because his father had treated him shamefully.', pt: 'Pelo que Jônatas, todo encolerizado, se levantou da mesa, e no segundo dia do mês não comeu; pois se magoava por causa de Davi, porque seu pai o tinha ultrajado.' },
      { v: 35, en: 'In the morning, Jonathan went out into the field at the time appointed with David, and a little boy with him.', pt: 'Jônatas, pois, saiu ao campo, pela manhã, ao tempo que tinha ajustado com Davi, levando consigo um rapazinho.' },
      { v: 36, en: 'He said to his boy, “Run, find now the arrows which I shoot.” As the boy ran, he shot an arrow beyond him.', pt: 'Então disse ao moço: Corre a buscar as flechas que eu atirar. Correu, pois, o moço; e Jônatas atirou uma flecha, que fez passar além dele.' },
      { v: 37, en: 'When the boy had come to the place of the arrow which Jonathan had shot, Jonathan cried after the boy, and said, “Isn’t the arrow beyond you?”', pt: 'Quando o moço chegou ao lugar onde estava a flecha que Jônatas atirara, gritou-lhe este, dizendo: Não está porventura a flecha para lá de ti?' },
      { v: 38, en: 'Jonathan cried after the boy, “Go fast! Hurry! Don’t delay!” Jonathan’s boy gathered up the arrows, and came to his master.', pt: 'E tornou a gritar ao moço: Apressa-te, anda, não te demores! E o servo de Jônatas apanhou as flechas, e as trouxe a seu senhor.' },
      { v: 39, en: 'But the boy didn’t know anything. Only Jonathan and David knew the matter.', pt: 'O moço, porém, nada percebeu; só Jônatas e Davi sabiam do negócio.' },
      { v: 40, en: 'Jonathan gave his weapons to his boy, and said to him, “Go, carry them to the city.”', pt: 'Então Jônatas deu as suas armas ao moço, e lhe disse: Vai, leva-as à cidade.' },
      { v: 41, en: 'As soon as the boy was gone, David arose out of the south, and fell on his face to the ground, and bowed himself three times. They kissed one another, and wept one with another, and David wept the most.', pt: 'Logo que o moço se foi, levantou-se Davi da banda do sul, e lançou-se sobre o seu rosto em terra, e inclinou-se três vezes; e beijaram-se um ao outro, e choraram ambos, mas Davi chorou muito mais.' },
      { v: 42, en: 'Jonathan said to David, “Go in peace, because we have both sworn in Yahweh’s name, saying, ‘Yahweh is between me and you, and between my offspring and your offspring, forever.’” He arose and departed; and Jonathan went into the city.', pt: 'E disse Jônatas a Davi: Vai-te em paz, porquanto nós temos jurado ambos em nome do Senhor, dizendo: O Senhor seja entre mim e ti, e entre a minha descendência e a tua descendência perpetuamente.' },
      { v: 43, en: 'Então Davi se levantou e partiu; e Jônatas entrou na cidade.', pt: 'Então Davi se levantou e partiu; e Jônatas entrou na cidade.' },
    ],
    21: [
      { v: 1, en: 'Then David came to Nob to Ahimelech the priest. Ahimelech came to meet David trembling, and said to him, “Why are you alone, and no man with you?”', pt: 'Então veio Davi a Nobe, ao sacerdote Aimeleque, o qual saiu, tremendo, ao seu encontro, e lhe perguntou: Por que vens só, e ninguém contigo?' },
      { v: 2, en: 'David said to Ahimelech the priest, “The king has commanded me to do something, and has said to me, ‘Let no one know anything about the business about which I send you, and what I have commanded you. I have sent the young men to a certain place.’', pt: 'Respondeu Davi ao sacerdote Aimeleque: O rei me encomendou um negócio, e me disse: Ninguém saiba deste negócio pelo qual eu te enviei, e o qual te ordenei. Quanto aos mancebos, apontei-lhes tal e tal lugar.' },
      { v: 3, en: 'Now therefore what is under your hand? Please give me five loaves of bread in my hand, or whatever is available.”', pt: 'Agora, pois, que tens à mão? Dá-me cinco pães, ou o que se achar.' },
      { v: 4, en: 'The priest answered David, and said, “I have no common bread, but there is holy bread; if only the young men have kept themselves from women.”', pt: 'Ao que, respondendo o sacerdote a Davi, disse: Não tenho pão comum à mão; há, porém, pão sagrado, se ao menos os mancebos se têm abstido das mulheres.' },
      { v: 5, en: 'David answered the priest, and said to him, “Truly, women have been kept from us as usual these three days. When I came out, the vessels of the young men were holy, though it was only a common journey. How much more then today shall their vessels be holy?”', pt: 'E respondeu Davi ao sacerdote, e lhe disse: Sim, em boa fé, as mulheres se nos vedaram há três dias; quando eu saí, os vasos dos mancebos também eram santos, embora fosse para uma viagem comum; quanto mais ainda hoje não serão santos os seus vasos?' },
      { v: 6, en: 'So the priest gave him holy bread; for there was no bread there but the show bread that was taken from before Yahweh, to put hot bread in the day when it was taken away.', pt: 'Então o sacerdote lhe deu o pão sagrado; porquanto não havia ali outro pão senão os pães da proposição, que se haviam tirado de diante do Senhor no dia em que se tiravam para se pôr ali pão quente.' },
      { v: 7, en: 'Now a certain man of the servants of Saul was there that day, detained before Yahweh; and his name was Doeg the Edomite, the best of the herdsmen who belonged to Saul.', pt: 'Ora, achava-se ali naquele dia um dos servos de Saul, detido perante o Senhor; e era seu nome Doegue, edomeu, chefe dos pastores de Saul.' },
      { v: 8, en: 'David said to Ahimelech, “Isn’t there here under your hand spear or sword? For I have neither brought my sword nor my weapons with me, because the king’s business required haste.”', pt: 'E disse Davi a Aimeleque: Não tens aqui à mão uma lança ou uma espada? porque eu não trouxe comigo nem a minha espada nem as minhas armas, pois o negócio do rei era urgente.' },
      { v: 9, en: 'The priest said, “Behold, the sword of Goliath the Philistine, whom you killed in the valley of Elah, is here wrapped in a cloth behind the ephod. If you would like to take that, take it; for there is no other except that here.” David said, “There is none like that. Give it to me.”', pt: 'Respondeu o sacerdote: A espada de Golias, o filisteu, a quem tu feriste no vale de Elá, está aqui envolta num pano, detrás do éfode; se a queres tomar, toma-a, porque não há outra aqui senão ela. E disse Davi: Não há outra igual a essa; dá-ma.' },
      { v: 10, en: 'David arose, and fled that day for fear of Saul, and went to Achish the king of Gath.', pt: 'Levantou-se, pois, Davi e fugiu naquele dia de diante de Saul, e foi ter com Áquis, rei de Gate.' },
      { v: 11, en: 'The servants of Achish said to him, “Isn’t this David the king of the land? Didn’t they sing to one another about him in dances, saying, ‘Saul has slain his thousands, and David his ten thousands?’”', pt: 'Mas os servos de Áquis lhe perguntaram: Este não é Davi, o rei da terra? não foi deste que cantavam nas danças, dizendo: Saul matou os seus milhares, por Davi os seus dez milhares?' },
      { v: 12, en: 'David laid up these words in his heart, and was very afraid of Achish the king of Gath.', pt: 'E Davi considerou estas palavras no seu coração, e teve muito medo de Áquis, rei de Gate.' },
      { v: 13, en: 'He changed his behavior before them, and pretended to be insane in their hands, and scribbled on the doors of the gate, and let his spittle fall down on his beard.', pt: 'Pelo que se contrafez diante dos olhos deles, e fingiu-se doido nas mãos deles, garatujando nas portas, e deixando correr a saliva pela barba.' },
      { v: 14, en: 'Then Achish said to his servants, “Look, you see the man is insane. Why then have you brought him to me?', pt: 'Então disse Áquis aos seus servos: Bem vedes que este homem está louco; por que mo trouxestes a mim?' },
      { v: 15, en: 'Do I lack madmen, that you have brought this fellow to play the madman in my presence? Should this fellow come into my house?”', pt: 'Faltam-me a mim doidos, para que trouxésseis a este para fazer doidices diante de mim? há de entrar este na minha casa?' },
    ],
    22: [
      { v: 1, en: 'David therefore departed from there, and escaped to the cave of Adullam. When his brothers and all his father’s house heard it, they went down there to him.', pt: 'Depois Davi, retirando-se desse lugar, escapou para a caverna de Adulão. Quando os seus irmãos e toda a casa de seu pai souberam disso, desceram ali para ter com ele.' },
      { v: 2, en: 'Everyone who was in distress, everyone who was in debt, and everyone who was discontented, gathered themselves to him; and he became captain over them. There were with him about four hundred men.', pt: 'Ajuntaram-se a ele todos os que se achavam em aperto, todos os endividados, e todos os amargurados de espírito; e ele se fez chefe deles; havia com ele cerca de quatrocentos homens.' },
      { v: 3, en: 'David went from there to Mizpeh of Moab, and he said to the king of Moab, “Please let my father and my mother come out with you, until I know what God will do for me.”', pt: 'Dali passou Davi para Mizpe de Moabe; e disse ao rei de Moabe: Deixa, peço-te, que meu pai e minha mãe fiquem convosco, até que eu saiba o que Deus há de fazer de mim.' },
      { v: 4, en: 'He brought them before the king of Moab; and they lived with him all the time that David was in the stronghold.', pt: 'E os deixou com o rei de Moabe; e ficaram com ele por todo o tempo que Davi esteve no lugar forte.' },
      { v: 5, en: 'The prophet Gad said to David, “Don’t stay in the stronghold. Depart, and go into the land of Judah.” Then David departed, and came into the forest of Hereth.', pt: 'Disse o profeta Gade a Davi: Não fiques no lugar forte; sai, e entra na terra de Judá. Então Davi saiu, e foi para o bosque de Herete.' },
      { v: 6, en: 'Saul heard that David was discovered, with the men who were with him. Now Saul was sitting in Gibeah, under the tamarisk tree in Ramah, with his spear in his hand, and all his servants were standing around him.', pt: 'Ora, ouviu Saul que já havia notícias de Davi e dos homens que estavam com ele. Estava Saul em Gibeá, sentado debaixo da tamargueira, sobre o alto, e tinha na mão a sua lança, e todos os seus servos estavam com ele.' },
      { v: 7, en: 'Saul said to his servants who stood around him, “Hear now, you Benjamites! Will the son of Jesse give everyone of you fields and vineyards? Will he make you all captains of thousands and captains of hundreds,', pt: 'Então disse Saul a seus servos que estavam com ele: Ouvi, agora, benjamitas! Acaso o filho de Jessé vos dará a todos vós terras e vinhas, e far-vos-á a todos chefes de milhares e chefes de centenas,' },
      { v: 8, en: 'that all of you have conspired against me, and there is no one who discloses to me when my son makes a treaty with the son of Jesse, and there is none of you who is sorry for me, or discloses to me that my son has stirred up my servant against me, to lie in wait, as it is today?”', pt: 'para que todos vós tenhais conspirado contra mim, e não haja ninguém que me avise de ter meu filho, feito aliança com o filho de Jessé, e não haja ninguém dentre vós que se doa de mim, e me participe o ter meu filho sublevado meu servo contra mim, para me armar ciladas, como se vê neste dia?' },
      { v: 9, en: 'Then Doeg the Edomite, who stood by the servants of Saul, answered and said, “I saw the son of Jesse coming to Nob, to Ahimelech the son of Ahitub.', pt: 'Então respondeu Doegue, o edomeu, que também estava com os servos de Saul, e disse: Vi o filho de Jessé chegar a Nobe, a Aimeleque, filho de Aitube;' },
      { v: 10, en: 'He inquired of Yahweh for him, gave him food, and gave him the sword of Goliath the Philistine.”', pt: 'o qual consultou por ele ao Senhor, e lhe deu mantimento, e lhe deu também a espada de Golias, o filisteu.' },
      { v: 11, en: 'Then the king sent to call Ahimelech the priest, the son of Ahitub, and all his father’s house, the priests who were in Nob; and they all came to the king.', pt: 'Então o rei mandou chamar a Aimeleque, o sacerdote, filho de Aitube, e a toda a casa de seu pai, isto é, aos sacerdotes que estavam em Nobe; e todos eles vierem ao rei.' },
      { v: 12, en: 'Saul said, “Hear now, you son of Ahitub.” He answered, “Here I am, my lord.”', pt: 'E disse Saul: Ouve, filho de Aitube! E ele lhe disse: Eis-me aqui, senhor meu.' },
      { v: 13, en: 'Saul said to him, “Why have you conspired against me, you and the son of Jesse, in that you have given him bread, and a sword, and have inquired of God for him, that he should rise against me, to lie in wait, as it is today?”', pt: 'Então lhe perguntou Saul: Por que conspirastes contra mim, tu e o filho de Jessé, pois deste lhe pão e espada, e consultaste por ele a Deus, para que ele se levantasse contra mim a armar-me ciladas, como se vê neste dia?' },
      { v: 14, en: 'Then Ahimelech answered the king, and said, “Who among all your servants is so faithful as David, who is the king’s son-in-law, and is taken into your council, and is honorable in your house?', pt: 'Ao que respondeu Aimeleque ao rei dizendo: Quem há, entre todos os teus servos, tão fiel como Davi, o genro do rei, chefe da tua guarda, e honrado na tua casa?' },
      { v: 15, en: 'Have I today begun to inquire of God for him? Be it far from me! Don’t let the king impute anything to his servant, nor to all the house of my father; for your servant knows nothing of all this, less or more.”', pt: 'Porventura é de hoje que comecei a consultar por ele a Deus? Longe de mim tal coisa! Não impute o rei coisa nenhuma a mim seu servo, nem a toda a casa de meu pai, pois o teu servo não soube nada de tudo isso, nem muito nem pouco.' },
      { v: 16, en: 'The king said, “You shall surely die, Ahimelech, you, and all your father’s house.”', pt: 'O rei, porém, disse: Hás de morrer, Aimeleque, tu e toda a casa de teu pai.' },
      { v: 17, en: 'The king said to the guard who stood about him, “Turn, and kill the priests of Yahweh; because their hand also is with David, and because they knew that he fled, and didn’t disclose it to me.” But the servants of the king wouldn’t put out their hand to fall on the priests of Yahweh.', pt: 'E disse o rei aos da sua guarda que estavam com ele: Virai-vos, e matai os sacerdotes do Senhor, porque também a mão deles está com Davi, e porque sabiam que ele fugia e não mo fizeram saber. Mas os servos do rei não quiseram estender as suas mãos para arremeter contra os sacerdotes do Senhor.' },
      { v: 18, en: 'The king said to Doeg, “Turn and attack the priests!” Doeg the Edomite turned, and he attacked the priests, and he killed on that day eighty-five people who wore a linen ephod.', pt: 'Então disse o rei a Doegue: Vira-te e arremete contra os sacerdotes. Virou-se, então, Doegue, o edomeu, e arremeteu contra os sacerdotes, e matou naquele dia oitenta e cinco homens que vestiam éfode de linho.' },
      { v: 19, en: 'He struck Nob, the city of the priests, with the edge of the sword, both men and women, children and nursing babies, and cattle and donkeys and sheep, with the edge of the sword.', pt: 'Também a Nobe, cidade desses sacerdotes, passou a fio de espada; homens e mulheres, meninos e criancinhas de peito, e até os bois, jumentos e ovelhas passou a fio de espada.' },
      { v: 20, en: 'One of the sons of Ahimelech, the son of Ahitub, named Abiathar, escaped, and fled after David.', pt: 'Todavia um dos filhos de Aimeleque, filho de Aitube, que se chamava Abiatar, escapou e fugiu para Davi.' },
      { v: 21, en: 'Abiathar told David that Saul had slain Yahweh’s priests.', pt: 'E Abiatar anunciou a Davi que Saul tinha matado os sacerdotes do Senhor.' },
      { v: 22, en: 'David said to Abiathar, “I knew on that day, when Doeg the Edomite was there, that he would surely tell Saul. I am responsible for the death of all the persons of your father’s house.', pt: 'Então Davi disse a Abiatar: Bem sabia eu naquele dia que, estando ali Doegue, o edomeu, não deixaria de o denunciar a Saul. Eu sou a causa da morte de todos os da casa de teu pai.' },
      { v: 23, en: 'Stay with me. Don’t be afraid, for he who seeks my life seeks your life. For you will be safe with me.”', pt: 'Fica comigo, não temas; porque quem procura a minha morte também procura a tua; comigo estarás em segurança.' },
    ],
    23: [
      { v: 1, en: 'David was told, “Behold, the Philistines are fighting against Keilah, and are robbing the threshing floors.”', pt: 'Ora, foi anunciado a Davi: Eis que os filisteus pelejam contra Queila e saqueiam as eiras.' },
      { v: 2, en: 'Therefore David inquired of Yahweh, saying, “Shall I go and strike these Philistines?” Yahweh said to David, “Go strike the Philistines, and save Keilah.”', pt: 'Pelo que consultou Davi ao Senhor, dizendo: Irei eu, e ferirei a esses filisteus? Respondeu o Senhor a Davi: Vai, fere aos filisteus e salva a Queila.' },
      { v: 3, en: 'David’s men said to him, “Behold, we are afraid here in Judah. How much more then if we go to Keilah against the armies of the Philistines?”', pt: 'Mas os homens de Davi lhe disseram: Eis que tememos aqui em Judá, quanta mais se formos a Queila, contra o exército dos filisteus!' },
      { v: 4, en: 'Then David inquired of Yahweh yet again. Yahweh answered him, and said, “Arise, go down to Keilah; for I will deliver the Philistines into your hand.”', pt: 'Davi, pois, tornou a consultar ao Senhor, e o Senhor lhe respondeu: Levanta-te, desce a Queila, porque eu hei de entregar os filisteus na tua mão.' },
      { v: 5, en: 'David and his men went to Keilah, and fought with the Philistines, and brought away their livestock, and killed them with a great slaughter. So David saved the inhabitants of Keilah.', pt: 'Então Davi partiu com os seus homens para Queila, pelejou contra os filisteus, levou-lhes o gado, e fez grande matança entre eles; assim Davi salvou os moradores de Queila.' },
      { v: 6, en: 'When Abiathar the son of Ahimelech fled to David to Keilah, he came down with an ephod in his hand.', pt: 'Ora, quando Abiatar, filho de Aimeleque, fugiu para Davi, a Queila, desceu com um éfode na mão.' },
      { v: 7, en: 'Saul was told that David had come to Keilah. Saul said, “God has delivered him into my hand; for he is shut in by entering into a town that has gates and bars.”', pt: 'Então foi anunciado a Saul que Davi tinha ido a Queila; e disse Saul: Deus o entregou nas minhas mãos; pois está encerrado, porque entrou numa cidade que tem portas e ferrolhos.' },
      { v: 8, en: 'Saul summoned all the people to war, to go down to Keilah, to besiege David and his men.', pt: 'E convocou todo o povo à peleja, para descerem a Queila, e cercar a Davi e os seus homens.' },
      { v: 9, en: 'David knew that Saul was devising mischief against him; and he said to Abiathar the priest, “Bring the ephod here.”', pt: 'Sabendo, pois, Davi que Saul maquinava este mal contra ele, disse a Abiatar, sacerdote: Traze aqui o éfode.' },
      { v: 10, en: 'Then David said, “O Yahweh, the God of Israel, your servant has surely heard that Saul seeks to come to Keilah, to destroy the city for my sake.', pt: 'E disse Davi: ç Senhor, Deus de Israel, teu servo acaba de ouvir que Saul procura vir a Queila, para destruir a cidade por causa de mim.' },
      { v: 11, en: 'Will the men of Keilah deliver me up into his hand? Will Saul come down, as your servant has heard? Yahweh, the God of Israel, I beg you, tell your servant.” Yahweh said, “He will come down.”', pt: 'Entregar-me-ão os cidadãos de Queila na mão dele? descerá Saul, como o teu servo tem ouvido? Ah, Senhor Deus de Israel! faze-o saber ao teu servo. Respondeu o Senhor: Descerá.' },
      { v: 12, en: 'Then David said, “Will the men of Keilah deliver me and my men into the hand of Saul?” Yahweh said, “They will deliver you up.”', pt: 'Disse mais Davi: Entregar-me-ão os cidadãos de Queila, a mim e aos meus homens, nas mãos de Saul? E respondeu o Senhor: Entregarão.' },
      { v: 13, en: 'Then David and his men, who were about six hundred, arose and departed out of Keilah, and went wherever they could go. Saul was told that David was escaped from Keilah; and he gave up going there.', pt: 'Levantou-se, então, Davi com os seus homens, cerca de seiscentos, e saíram de Queila, e foram-se aonde puderam. Saul, quando lhe foi anunciado que Davi escapara de Queila, deixou de sair contra ele.' },
      { v: 14, en: 'David stayed in the wilderness in the strongholds, and remained in the hill country in the wilderness of Ziph. Saul sought him every day, but God didn’t deliver him into his hand.', pt: 'E Davi ficou no deserto, em lugares fortes, permanecendo na região montanhosa no deserto de Zife. Saul o buscava todos os dias, porém Deus não o entregou na sua mao.' },
      { v: 15, en: 'David saw that Saul had come out to seek his life. David was in the wilderness of Ziph in the wood.', pt: 'Vendo, pois, Davi que Saul saíra à busca da sua vida, esteve no deserto de Zife, em Hores.' },
      { v: 16, en: 'Jonathan, Saul’s son, arose, and went to David into the woods, and strengthened his hand in God.', pt: 'Então se levantou Jônatas, filho de Saul, e foi ter com Davi em Hores, e o confortou em Deus;' },
      { v: 17, en: 'He said to him, “Don’t be afraid; for the hand of Saul my father won’t find you; and you will be king over Israel, and I will be next to you; and Saul my father knows that also.”', pt: 'e disse-lhe: Não temas; porque não te achará a mão de Saul, meu pai; porém tu reinarás sobre Israel, e eu serei contigo o segundo; o que também Saul, meu pai, bem sabe.' },
      { v: 18, en: 'They both made a covenant before Yahweh. Then David stayed in the woods, and Jonathan went to his house.', pt: 'E ambos fizeram aliança perante o Senhor; Davi ficou em Hores, e Jônatas, voltou para sua casa.' },
      { v: 19, en: 'Then the Ziphites came up to Saul to Gibeah, saying, “Doesn’t David hide himself with us in the strongholds in the woods, in the hill of Hachilah, which is on the south of the desert?', pt: 'Então subiram os zifeus a Saul, a Gibea, dizendo: Não se escondeu Davi entre nós, nos lugares fortes em Hores, no outeiro de Haquila, que está à mão direita de Jesimom?' },
      { v: 20, en: 'Now therefore, O king, come down. According to all the desire of your soul to come down; and our part will be to deliver him up into the king’s hand.”', pt: 'Agora, pois, ó rei, desce apressadamente, conforme todo o desejo da tua alma; a nós nos cumpre entregá-lo nas mãos do rei.' },
      { v: 21, en: 'Saul said, “You are blessed by Yahweh; for you have had compassion on me.', pt: 'Então disse Saul: Benditos sejais vós do Senhor, porque vos compadecestes de mim:' },
      { v: 22, en: 'Please go make yet more sure, and know and see his place where his haunt is, and who has seen him there; for I have been told that he deals very crafty.', pt: 'Ide, pois, informai-vos ainda melhor; sabei e notai o lugar que ele freqüenta, e quem o tenha visto ali; porque me foi dito que é muito astuto.' },
      { v: 23, en: 'See therefore, and take knowledge of all the lurking places where he hides himself, and come again to me with certainty, and I will go with you. It shall happen, if he is in the land, that I will search him out among all the thousands of Judah.”', pt: 'Pelo que atentai bem, e informai-vos acerca de todos os esconderijos em que ele se oculta; e então voltai para mim com notícias exatas, e eu irei convosco. E há de ser que, se estiver naquela terra, eu o buscarei entre todos os milhares de Judá.' },
      { v: 24, en: 'They arose, and went to Ziph before Saul: but David and his men were in the wilderness of Maon, in the Arabah on the south of the desert.', pt: 'Eles, pois, se levantaram e foram a Zife adiante de Saul; Davi, porém, e os seus homens estavam no deserto de Maom, na campina ao sul de Jesimom.' },
      { v: 25, en: 'Saul and his men went to seek him. When David was told, he went down to the rock, and stayed in the wilderness of Maon. When Saul heard that, he pursued David in the wilderness of Maon.', pt: 'E Saul e os seus homens foram em busca dele. Sendo isso anunciado a Davi, desceu ele à penha que está no deserto de Maom. Ouvindo-o Saul, foi ao deserto de Maom, a perseguir Davi.' },
      { v: 26, en: 'Saul went on this side of the mountain, and David and his men on that side of the mountain; and David hurried to get away for fear of Saul; for Saul and his men surrounded David and his men to take them.', pt: 'Saul ia de uma banda do monte, e Davi e os seus homens da outra banda. E Davi se apressava para escapar, por medo de Saul, porquanto Saul e os seus homens iam cercando a Davi e aos seus homens, para os prender.' },
      { v: 27, en: 'But a messenger came to Saul, saying, “Hurry and come; for the Philistines have made a raid on the land!”', pt: 'Nisso veio um mensageiro a Saul, dizendo: Apressa-te, e vem, porque os filisteus acabam de invadir a terra.' },
      { v: 28, en: 'So Saul returned from pursuing David, and went against the Philistines. Therefore they called that place Sela Hammahlekoth.', pt: 'Pelo que Saul voltou de perseguir a Davi, e se foi ao encontro dos filisteus. Por esta razão aquele lugar se chamou Selá-Hamalecote.' },
      { v: 29, en: 'David went up from there, and lived in the strongholds of En Gedi.', pt: 'Depois disto, Davi subiu e ficou nos lugares fortes de En-Gedi.' },
    ],
    24: [
      { v: 1, en: 'When Saul had returned from following the Philistines, he was told, “Behold, David is in the wilderness of En Gedi.”', pt: 'Ora, quando Saul voltou de perseguir os filisteus, foi-lhe dito: Eis que Davi está no deserto de En-Gedi.' },
      { v: 2, en: 'Then Saul took three thousand chosen men out of all Israel, and went to seek David and his men on the rocks of the wild goats.', pt: 'Então tomou Saul três mil homens, escolhidos dentre todo o Israel, e foi em busca de Davi e dos seus homens, até sobre as penhas das cabras montesas.' },
      { v: 3, en: 'He came to the sheep pens by the way, where there was a cave; and Saul went in to relieve himself. Now David and his men were staying in the innermost parts of the cave.', pt: 'E chegou no caminho a uns currais de ovelhas, onde havia uma caverna; e Saul entrou nela para aliviar o ventre. Ora Davi e os seus homens estavam sentados na parte interior da caverna.' },
      { v: 4, en: 'David’s men said to him, “Behold, the day of which Yahweh said to you, ‘Behold, I will deliver your enemy into your hand, and you shall do to him as it shall seem good to you.’” Then David arose, and cut off the skirt of Saul’s robe secretly.', pt: 'Então os homens de Davi lhe disseram: Eis aqui o dia do qual o Senhor te disse: Eis que entrego o teu inimigo nas tuas mãos; far-lhe-ás como parecer bem aos teus olhos. Então Davi se levantou, e de mansinho cortou a orla do manto de Saul.' },
      { v: 5, en: 'Afterward, David’s heart struck him, because he had cut off Saul’s skirt.', pt: 'Sucedeu, porém, que depois doeu o coração de Davi, por ter cortado a orla do manto de Saul.' },
      { v: 6, en: 'He said to his men, “Yahweh forbid that I should do this thing to my lord, Yahweh’s anointed, to stretch out my hand against him, since he is Yahweh’s anointed.”', pt: 'E disse aos seus homens: O Senhor me guarde de que eu faça tal coisa ao meu senhor, ao ungido do Senhor, que eu estenda a minha mão contra ele, pois é o ungido do Senhor.' },
      { v: 7, en: 'So David checked his men with these words, and didn’t allow them to rise against Saul. Saul rose up out of the cave, and went on his way.', pt: 'com essas palavras Davi conteve os seio chegando para se permitiu que se levantassem contra Saul. E Saul se levantou da caverna, e prosseguiu o seu caminho.' },
      { v: 8, en: 'David also arose afterward, and went out of the cave, and cried after Saul, saying, “My lord the king!” When Saul looked behind him, David bowed with his face to the earth, and showed respect.', pt: 'Depois também Davi se levantou e, saindo da caverna, gritou por detrás de Saul, dizendo: ç rei, meu senhor! Quando Saul olhou para trás, Davi se inclinou com o rosto em terra e lhe fez reverência.' },
      { v: 9, en: 'David said to Saul, “Why do you listen to men’s words, saying, ‘Behold, David seeks to harm you?’', pt: 'Então disse Davi a Saul: por que dás ouvidos às palavras dos homens que dizem: Davi procura fazer-te mal?' },
      { v: 10, en: 'Behold, today your eyes have seen how Yahweh had delivered you today into my hand in the cave. Some urged me to kill you; but I spared you; and I said, I will not stretch out my hand against my lord; for he is Yahweh’s anointed.', pt: 'Eis que os teus olhos acabam de ver que o Senhor hoje te pôs em minhas mãos nesta caverna; e alguns disseram que eu te matasse, porém a minha mão te poupou; pois eu disse: Não estenderei a minha mão contra o meu senhor, porque é o ungido do Senhor.' },
      { v: 11, en: 'Moreover, my father, behold, yes, see the skirt of your robe in my hand; for in that I cut off the skirt of your robe, and didn’t kill you, know and see that there is neither evil nor disobedience in my hand, and I have not sinned against you, though you hunt for my life to take it.', pt: 'Olha, meu pai, vê aqui a orla do teu manto na minha mão, pois cortando-te eu a orla do manto, não te matei. Considera e vê que não há na minha mão nem mal nem transgressão alguma, e que não pequei contra ti, ainda que tu andes à caça da minha vida para ma tirares.' },
      { v: 12, en: 'May Yahweh judge between me and you, and may Yahweh avenge me of you; but my hand will not be on you.', pt: 'Julgue o Senhor entre mim e ti, e vingue-me o Senhor de ti; a minha mão, porém, não será contra ti.' },
      { v: 13, en: 'As the proverb of the ancients says, ‘Out of the wicked comes wickedness;’ but my hand will not be on you.', pt: 'Como diz o provérbio dos antigos: Dos ímpios procede a impiedade. A minha mão, porém, não será contra ti.' },
      { v: 14, en: 'Against whom has the king of Israel come out? Whom do you pursue? A dead dog? A flea?', pt: 'Após quem saiu o rei de Israel? a quem persegues tu? A um cão morto, a uma pulga!' },
      { v: 15, en: 'May Yahweh therefore be judge, and give sentence between me and you, and see, and plead my cause, and deliver me out of your hand.”', pt: 'Seja, pois, o Senhor juiz, e julgue entre mim e ti; e veja, e advogue a minha causa, e me livre da tua mão.' },
      { v: 16, en: 'It came to pass, when David had finished speaking these words to Saul, that Saul said, “Is that your voice, my son David?” Saul lifted up his voice, and wept.', pt: 'Acabando Davi de falar a Saul todas estas palavras, perguntou Saul: E esta a tua voz, meu filho Davi? Então Saul levantou a voz e chorou.' },
      { v: 17, en: 'He said to David, “You are more righteous than I; for you have done good to me, whereas I have done evil to you.', pt: 'E disse a Davi: Tu és mais justo do que eu, pois me recompensaste com bem, e eu te recompensei com mal.' },
      { v: 18, en: 'You have declared today how you have dealt well with me, because when Yahweh had delivered me up into your hand, you didn’t kill me.', pt: 'E tu mostraste hoje que procedeste bem para comigo, por isso que, havendo-me o Senhor entregado na tua mão, não me mataste.' },
      { v: 19, en: 'For if a man finds his enemy, will he let him go away unharmed? Therefore may Yahweh reward you good for that which you have done to me today.', pt: 'Pois, quem há que, encontrando o seu inimigo, o deixará ir o seu caminho? O Senhor, pois, te pague com bem, pelo que hoje me fizeste.' },
      { v: 20, en: 'Now, behold, I know that you will surely be king, and that the kingdom of Israel will be established in your hand.', pt: 'Agora, pois, sei que certamente hás de reinar, e que o reino de Israel há de se firmar na tua mão.' },
      { v: 21, en: 'Swear now therefore to me by Yahweh, that you will not cut off my offspring after me, and that you will not destroy my name out of my father’s house.”', pt: 'Portanto jura-me pelo Senhor que não desarraigarás a minha descendência depois de mim, nem extinguirás o meu nome da casa de meu pai.' },
      { v: 22, en: 'David swore to Saul. Saul went home, but David and his men went up to the stronghold.', pt: 'Então jurou Davi a Saul. E foi Saul para sua casa, mas Davi e os seus homens subiram ao lugar forte.' },
    ],
    25: [
      { v: 1, en: 'Samuel died; and all Israel gathered themselves together, and mourned for him, and buried him at his house at Ramah. Then David arose, and went down to the wilderness of Paran.', pt: 'Ora, faleceu Samuel; e todo o Israel se ajuntou e o pranteou; e o sepultaram na sua casa, em Ramá. E Davi se levantou e desceu ao deserto de Parã.' },
      { v: 2, en: 'There was a man in Maon, whose possessions were in Carmel; and the man was very great. He had three thousand sheep and a thousand goats; and he was shearing his sheep in Carmel.', pt: 'Havia um homem em Maom que tinha as suas possessões no Carmelo. Este homem era muito rico, pois tinha três mil ovelhas e mil Cabras e estava tosquiando as suas ovelhas no Carmelo.' },
      { v: 3, en: 'Now the name of the man was Nabal; and the name of his wife Abigail. This woman was intelligent and had a beautiful face; but the man was surly and evil in his doings. He was of the house of Caleb.', pt: 'Chamava-se o homem Nabal, e sua mulher chamava-se Abigail; era a mulher sensata e formosa; o homem porém, era duro, e maligno nas suas ações; e era da casa de Calebe.' },
      { v: 4, en: 'David heard in the wilderness that Nabal was shearing his sheep.', pt: 'Ouviu Davi no deserto que Nabal tosquiava as suas ovelhas,' },
      { v: 5, en: 'David sent ten young men, and David said to the young men, “Go up to Carmel, and go to Nabal, and greet him in my name.', pt: 'e enviou-lhe dez mancebos, dizendo-lhes: Subi ao Carmelo, ide a Nabal e perguntai-lhe, em meu nome, como está.' },
      { v: 6, en: 'Tell him, ‘Long life to you! Peace be to you, and peace be to your house, and peace be to all that you have.', pt: 'Assim lhe direis: Paz seja contigo, e com a tua casa, e com tudo o que tens.' },
      { v: 7, en: 'Now I have heard that you have shearers. Your shepherds have now been with us, and we didn’t harm them, neither was there anything missing from them, all the while they were in Carmel.', pt: 'Agora, pois, tenho ouvido que tens tosquiadores. Ora, os pastores que tens acabam de estar conosco; agravo nenhum lhes fizemos, nem lhes desapareceu coisa alguma por todo o tempo que estiveram no Carmelo.' },
      { v: 8, en: 'Ask your young men, and they will tell you. Therefore let the young men find favor in your eyes; for we come on a good day. Please give whatever comes to your hand, to your servants, and to your son David.’”', pt: 'Pergunta-o aos teus mancebos, e eles to dirão. Que achem, portanto, os teus servos graça aos teus olhos, porque viemos em boa ocasião. Dá, pois, a teus servos e a Davi, teu filho, o que achares à mão.' },
      { v: 9, en: 'When David’s young men came, they spoke to Nabal all those words in the name of David, and waited.', pt: 'Chegando, pois, os mancebos de Davi, falaram a Nabal todas aquelas palavras em nome de Davi, e se calaram.' },
      { v: 10, en: 'Nabal answered David’s servants, and said, “Who is David? Who is the son of Jesse? There are many servants who break away from their masters these days.', pt: 'Ao que Nabal respondeu aos servos de Davi, e disse: Quem é Davi, e quem o filho de Jessé? Muitos servos há que hoje fogem ao seu senhor.' },
      { v: 11, en: 'Shall I then take my bread, my water, and my meat that I have killed for my shearers, and give it to men who I don’t know where they come from?”', pt: 'Tomaria eu, pois, o meu pão, e a minha água, e a carne das minhas reses que degolei para os meus tosquiadores, e os daria a homens que não sei donde vêm?' },
      { v: 12, en: 'So David’s young men turned on their way, and went back, and came and told him all these words.', pt: 'Então os mancebos de Davi se puseram a caminho e, voltando, vieram anunciar-lhe todas estas palavras.' },
      { v: 13, en: 'David said to his men, “Every man put on his sword!” Every man put on his sword. David also put on his sword. About four hundred men followed David, and two hundred stayed by the baggage.', pt: 'Pelo que disse Davi aos seus homens: Cada um cinja a sua espada. E cada um cingiu a sua espada, e Davi também cingiu a sua, e subiram após Davi cerca de quatrocentos homens, e duzentos ficaram com a bagagem.' },
      { v: 14, en: 'But one of the young men told Abigail, Nabal’s wife, saying, “Behold, David sent messengers out of the wilderness to Greet our master; and he insulted them.', pt: 'um dentre os mancebos, porém, o anunciou a Abigail, mulher de Nabal, dizendo: Eis que Davi enviou mensageiros desde o deserto a saudar o nosso amo; e ele os destratou.' },
      { v: 15, en: 'But the men were very good to us, and we were not harmed, and we didn’t miss anything, as long as we went with them, when we were in the fields.', pt: 'Todavia, aqueles homens têm-nos sido muito bons, e nunca fomos agravados deles, e nada nos desapareceu por todo o tempo em que convivemos com eles quando estávamos no campo.' },
      { v: 16, en: 'They were a wall to us both by night and by day, all the while we were with them keeping the sheep.', pt: 'De muro em redor nos serviram, assim de dia como de noite, todos os dias que andamos com eles apascentando as ovelhas.' },
      { v: 17, en: 'Now therefore know and consider what you will do; for evil is determined against our master, and against all his house; for he is such a worthless fellow that one can’t speak to him.”', pt: 'Considera, pois, agora e vê o que hás de fazer, porque o mal já está de todo determinado contra o nosso amo e contra toda a sua casa; e ele é tal filho de Belial, que não há quem lhe possa falar.' },
      { v: 18, en: 'Then Abigail hurried and took two hundred loaves of bread, two bottles of wine, five sheep ready dressed, five seahs of parched grain, one hundred clusters of raisins, and two hundred cakes of figs, and laid them on donkeys.', pt: 'Então Abigail se apressou, e tomou duzentos pães, dois odres de vinho, cinco ovelhas assadas, cinco medidas de trigo tostado, cem cachos de passas, e duzentas pastas de figos secos, e os pôs sobre jumentos.' },
      { v: 19, en: 'She said to her young men, “Go on before me. Behold, I am coming after you.” But she didn’t tell her husband, Nabal.', pt: 'E disse aos seus mancebos: Ide adiante de mim; eis que vos seguirei de perto. Porém não o declarou a Nabal, seu marido.' },
      { v: 20, en: 'As she rode on her donkey, and came down by the covert of the mountain, that behold, David and his men came down toward her, and she met them.', pt: 'E quando ela, montada num jumento, ia descendo pelo encoberto do monte, eis que Davi e os seus homens lhe vinham ao encontro; e ela se encontrou com eles.' },
      { v: 21, en: 'Now David had said, “Surely in vain I have kept all that this fellow has in the wilderness, so that nothing was missed of all that pertained to him. He has returned me evil for good.', pt: 'Ora, Davi tinha dito: Na verdade que em vão tenho guardado tudo quanto este tem no deserto, de sorte que nada lhe faltou de tudo quanto lhe pertencia; e ele me pagou mal por bem.' },
      { v: 22, en: 'God do so to the enemies of David, and more also, if I leave of all that belongs to him by the morning light so much as one who urinates on a wall.”', pt: 'Assim faça Deus a Davi, e outro tanto, se eu deixar até o amanhecer, de tudo o que pertence a Nabal, um só varão.' },
      { v: 23, en: 'When Abigail saw David, she hurried and got off her donkey, and fell before David on her face, and bowed herself to the ground.', pt: 'Vendo, pois, Abigail a Davi, apressou-se, desceu do jumento e prostrou-se sobre o seu rosto diante de Davi, inclinando-se à terra,' },
      { v: 24, en: 'She fell at his feet, and said, “On me, my lord, on me be the blame! Please let your servant speak in your ears. Hear the words of your servant.', pt: 'e, prostrada a seus pés, lhe disse: Ah, senhor meu, minha seja a iniqüidade! Deixa a tua serva falar aos teus ouvidos, e ouve as palavras da tua serva.' },
      { v: 25, en: 'Please don’t let my lord pay attention to this worthless fellow, Nabal; for as his name is, so is he. Nabal is his name, and folly is with him; but I, your servant, didn’t see my lord’s young men, whom you sent.', pt: 'Rogo-te, meu senhor, que não faças caso deste homem de Belial, a saber, Nabal; porque tal é ele qual é o seu nome. Nabal é o seu nome, e a loucura está com ele; mas eu, tua serva, não vi os mancebos de meu senhor, que enviaste.' },
      { v: 26, en: 'Now therefore, my lord, as Yahweh lives, and as your soul lives, since Yahweh has withheld you from blood guiltiness, and from avenging yourself with your own hand, now therefore let your enemies, and those who seek evil to my lord, be as Nabal.', pt: 'Agora, pois, meu senhor, vive o Senhor, e vive a tua alma, porquanto o Senhor te impediu de derramares sangue, e de te vingares com a tua própria mão, sejam agora como Nabal os teus inimigos e os que procuram fazer o mal contra o meu senhor.' },
      { v: 27, en: 'Now this present which your servant has brought to my lord, let it be given to the young men who follow my lord.', pt: 'Aceita agora este presente que a tua serva trouxe a meu senhor; seja ele dado aos mancebos que seguem ao meu senhor.' },
      { v: 28, en: 'Please forgive the trespass of your servant. For Yahweh will certainly make my lord a sure house, because my lord fights Yahweh’s battles. Evil will not be found in you all your days.', pt: 'Perdoa, pois, a transgressão da tua serva; porque certamente fará o Senhor casa firme a meu senhor, pois meu senhor guerreia as guerras do Senhor; e não se achará mal em ti por todos os teus dias.' },
      { v: 29, en: 'Though men may rise up to pursue you, and to seek your soul, yet the soul of my lord will be bound in the bundle of life with Yahweh your God. He will sling out the souls of your enemies, as from the hollow of a sling.', pt: 'Se alguém se levantar para te perseguir, e para buscar a tua vida, então a vida de meu senhor será atada no feixe dos que vivem com o Senhor teu Deus; porém a vida de teus inimigos ele arrojará ao longe, como do côncavo de uma funda.' },
      { v: 30, en: 'It will come to pass, when Yahweh has done to my lord according to all the good that he has spoken concerning you, and has appointed you prince over Israel,', pt: 'Quando o Senhor tiver feito para com o meu senhor conforme todo o bem que já tem dito de ti, e te houver estabelecido por príncipe sobre Israel,' },
      { v: 31, en: 'that this shall be no grief to you, nor offense of heart to my lord, either that you have shed blood without cause, or that my lord has avenged himself. When Yahweh has dealt well with my lord, then remember your servant.”', pt: 'então, meu senhor, não terás no coração esta tristeza nem este remorso de teres derramado sangue sem causa, ou de haver-se vingado o meu senhor a si mesmo. E quando o Senhor fizer bem a meu senhor, lembra-te então da tua serva.' },
      { v: 32, en: 'David said to Abigail, “Blessed is Yahweh, the God of Israel, who sent you today to meet me!', pt: 'Ao que Davi disse a Abigail: Bendito seja o Senhor Deus de Israel, que hoje te enviou ao meu encontro!' },
      { v: 33, en: 'Blessed is your discretion, and blessed are you, who have kept me today from blood guiltiness, and from avenging myself with my own hand.', pt: 'E bendito seja o teu conselho, e bendita sejas tu, que hoje me impediste de derramar sangue, e de vingar-me pela minha própria mão!' },
      { v: 34, en: 'For indeed, as Yahweh, the God of Israel, lives, who has withheld me from harming you, unless you had hurried and come to meet me, surely there wouldn’t have been left to Nabal by the morning light so much as one who urinates on a wall.”', pt: 'Pois, na verdade, vive o Senhor Deus de Israel que me impediu de te fazer mal, que se tu não te apressaras e não me vieras ao encontro, não teria ficado a Nabal até a luz da manhã nem mesmo um menino.' },
      { v: 35, en: 'So David received from her hand that which she had brought him. Then he said to her, “Go up in peace to your house. Behold, I have listened to your voice, and have granted your request.”', pt: 'Então Davi aceitou da mão dela o que lhe tinha trazido, e lhe disse: Sobe em paz à tua casa; vê que dei ouvidos à tua voz, e aceitei a tua face.' },
      { v: 36, en: 'Abigail came to Nabal; and behold, he held a feast in his house, like the feast of a king. Nabal’s heart was merry within him, for he was very drunk. Therefore she told him nothing, until the morning light.', pt: 'Ora, quando Abigail voltou para Nabal, eis que ele fazia em sua casa um banquete, como banquete de rei; e o coração de Nabal estava alegre, pois ele estava muito embriagado; pelo que ela não lhe deu a entender nada daquilo, nem pouco nem muito, até a luz da manhã.' },
      { v: 37, en: 'In the morning, when the wine had gone out of Nabal, his wife told him these things, and his heart died within him, and he became as a stone.', pt: 'Sucedeu, pois, que, pela manhã, estando Nabal já livre do vinho, sua mulher lhe contou essas coisas; de modo que o seu coração desfaleceu, e ele ficou como uma pedra.' },
      { v: 38, en: 'About ten days later, Yahweh struck Nabal, so that he died.', pt: 'Passados uns dez dias, o Senhor feriu a Nabal, e ele morreu.' },
      { v: 39, en: 'When David heard that Nabal was dead, he said, “Blessed is Yahweh, who has pleaded the cause of my reproach from the hand of Nabal, and has kept back his servant from evil. Yahweh has returned the evildoing of Nabal on his own head.” David sent and spoke concerning Abigail, to take her to himself as wife.', pt: 'Quando Davi ouviu que Nabal morrera, disse: Bendito seja o Senhor, que me vingou da afronta que recebi de Nabal, e deteve do mal a seu servo, fazendo cair a maldade de Nabal sobre a sua cabeça. Depois mandou Davi falar a Abigail, para tomá-la por mulher.' },
      { v: 40, en: 'When David’s servants had come to Abigail to Carmel, they spoke to her, saying, “David has sent us to you, to take you to him as wife.”', pt: 'Vindo, pois, os servos de Davi a Abigail, no Carmelo, lhe falaram, dizendo: Davi nos mandou a ti, para te tomarmos por sua mulher.' },
      { v: 41, en: 'She arose, and bowed herself with her face to the earth, and said, “Behold, your servant is a servant to wash the feet of the servants of my lord.”', pt: 'Ao que ela se levantou, e se inclinou com o rosto em terra, e disse: Eis que a tua serva servirá de criada para lavar os pés dos servos de meu senhor.' },
      { v: 42, en: 'Abigail hurried, and arose, and rode on a donkey, with five ladies of hers who followed her; and she went after the messengers of David, and became his wife.', pt: 'Então Abigail se apressou e, levantando-se, montou num jumento, e levando as cinco moças que lhe assistiam, seguiu os mensageiros de Davi, que a recebeu por mulher.' },
      { v: 43, en: 'David also took Ahinoam of Jezreel; and they both became his wives.', pt: 'Davi tomou também a Ainoã de Jizreel; e ambas foram suas mulheres.' },
      { v: 44, en: 'Now Saul had given Michal his daughter, David’s wife, to Palti the son of Laish, who was of Gallim.', pt: 'Pois Saul tinha dado sua filha Mical, mulher de Davi, a Palti, filho de Laís, o qual era de Galim.' },
    ],
    26: [
      { v: 1, en: 'The Ziphites came to Saul to Gibeah, saying, “Doesn’t David hide himself in the hill of Hachilah, which is before the desert?”', pt: 'Ora, vieram os zifeus a Saul, a Gibeá, dizendo: Não está Davi se escondendo no outeiro de Haquila, defronte de Jesimom?' },
      { v: 2, en: 'Then Saul arose, and went down to the wilderness of Ziph, having three thousand chosen men of Israel with him, to seek David in the wilderness of Ziph.', pt: 'Então Saul se levantou, e desceu ao deserto de Zife, levando consigo três mil homens escolhidos de Israel, para buscar a Davi no deserto de Zife.' },
      { v: 3, en: 'Saul encamped in the hill of Hachilah, which is before the desert, by the way. But David stayed in the wilderness, and he saw that Saul came after him into the wilderness.', pt: 'E acampou-se Saul no outeiro de Haquila, defronte de Jesimom, junto ao caminho; porém Davi ficou no deserto, e percebendo que Saul vinha após ele ao deserto,' },
      { v: 4, en: 'David therefore sent out spies, and understood that Saul had certainly come.', pt: 'enviou espias, e certificou-se de que Saul tinha chegado.' },
      { v: 5, en: 'Then David arose, and came to the place where Saul had encamped; and David saw the place where Saul lay, with Abner the son of Ner, the captain of his army. Saul lay within the place of the wagons, and the people were encamped around him.', pt: 'Então Davi levantou-se e foi ao lugar onde Saul se tinha acampado; viu Davi o lugar onde se deitavam Saul e Abner, filho de Ner, chefe do seu exército. E Saul estava deitado dentro do acampamento, e o povo estava acampado ao redor dele.' },
      { v: 6, en: 'Then David answered and said to Ahimelech the Hittite, and to Abishai the son of Zeruiah, brother of Joab, saying, “Who will go down with me to Saul to the camp?” Abishai said, “I will go down with you.”', pt: 'Então Davi, dirigindo-se a Aimeleque, o heteu, e a Abisai, filho de Zeruia, irmão de Joabe, perguntou: Quem descerá comigo a Saul, ao arraial? Respondeu Abisai: Eu descerei contigo.' },
      { v: 7, en: 'So David and Abishai came to the people by night: and, behold, Saul lay sleeping within the place of the wagons, with his spear stuck in the ground at his head; and Abner and the people lay around him.', pt: 'Foram, pois, Davi e Abisai de noite ao povo; e eis que Saul estava deitado, dormindo dentro do acampamento, e a sua lança estava pregada na terra à sua cabeceira; e Abner e o povo estavam deitados ao redor dele.' },
      { v: 8, en: 'Then Abishai said to David, “God has delivered up your enemy into your hand today. Now therefore please let me strike him with the spear to the earth at one stroke, and I will not strike him the second time.”', pt: 'Então disse Abisai a Davi: Deus te entregou hoje nas mãos o teu inimigo; deixa-me, pois, agora encravá-lo na terra, com a lança, de um só golpe; não o ferirei segunda vez.' },
      { v: 9, en: 'David said to Abishai, “Don’t destroy him; for who can stretch out his hand against Yahweh’s anointed, and be guiltless?”', pt: 'Mas Davi respondeu a Abisai: Não o mates; pois quem pode estender a mão contra o ungido do Senhor, e ficar inocente?' },
      { v: 10, en: 'David said, “As Yahweh lives, Yahweh will strike him; or his day shall come to die; or he shall go down into battle and perish.', pt: 'Disse mais Davi: Como vive o Senhor, ou o Senhor o ferirá, ou chegará o seu dia e morrerá, ou descerá para a batalha e perecerá;' },
      { v: 11, en: 'Yahweh forbid that I should stretch out my hand against Yahweh’s anointed; but now please take the spear that is at his head, and the jar of water, and let us go.”', pt: 'o Senhor, porém, me guarde de que eu estenda a mão contra o ungido do Senhor. Agora, pois, toma a lança que está à sua cabeceira, e a bilha d\'água, e vamo-nos.' },
      { v: 12, en: 'So David took the spear and the jar of water from Saul’s head; and they went away: and no man saw it, or knew it, nor did any awake; for they were all asleep, because a deep sleep from Yahweh was fallen on them.', pt: 'Tomou, pois, Davi a lança e a bilha d\'água da cabeceira de Saul, e eles se foram. Ninguém houve que o visse, nem que o soubesse, nem que acordasse; porque todos estavam dormindo, pois da parte do Senhor havia caído sobre eles um profundo sono.' },
      { v: 13, en: 'Then David went over to the other side, and stood on the top of the mountain afar off; a great space being between them;', pt: 'Então Davi, passando à outra banda, pôs-se no cume do monte, ao longe, de maneira que havia grande distância entre eles.' },
      { v: 14, en: 'and David cried to the people, and to Abner the son of Ner, saying, “Don’t you answer, Abner?” Then Abner answered, “Who are you who cries to the king?”', pt: 'E Davi bradou ao povo, e a Abner, filho de Ner, dizendo: Não responderás, Abner? Então Abner respondeu e disse: Quem és tu, que bradas ao rei?' },
      { v: 15, en: 'David said to Abner, “Aren’t you a man? Who is like you in Israel? Why then have you not kept watch over your lord, the king? For one of the people came in to destroy the king your lord.', pt: 'Ao que disse Davi a Abner: Não és tu um homem? e quem há em Israel como tu? Por que, então, não guardaste o rei, teu senhor? porque um do povo veio para destruir o rei, teu senhor.' },
      { v: 16, en: 'This thing isn’t good that you have done. As Yahweh lives, you are worthy to die, because you have not kept watch over your lord, Yahweh’s anointed. Now see where the king’s spear is, and the jar of water that was at his head.”', pt: 'Não é bom isso que fizeste. Vive o Senhor, que sois dignos de morte, porque não guardastes a vosso senhor, o ungido do Senhor. Vede, pois, agora onde está a lança do rei, e a bilha d\'água que estava à sua cabeceira.' },
      { v: 17, en: 'Saul knew David’s voice, and said, “Is this your voice, my son David?” David said, “It is my voice, my lord, O king.”', pt: 'Saul reconheceu a voz de Davi, e disse: Não é esta a tua voz, meu filho Davi? Respondeu Davi: E minha voz, ó rei, meu senhor.' },
      { v: 18, en: 'He said, “Why does my lord pursue his servant? For what have I done? What evil is in my hand?', pt: 'Disse mais: Por que o meu senhor persegue tanto o seu servo? que fiz eu? e que maldade se acha na minha mão?' },
      { v: 19, en: 'Now therefore, please let my lord the king hear the words of his servant. If it is so that Yahweh has stirred you up against me, let him accept an offering. But if it is the children of men, they are cursed before Yahweh; for they have driven me out today that I shouldn’t cling to Yahweh’s inheritance, saying, ‘Go, serve other gods!’', pt: 'Ouve pois agora, ó rei, meu senhor, as palavras de teu servo: Se é o Senhor quem te incita contra mim, receba ele uma oferta; se, porém, são os filhos dos homens, malditos sejam perante o Senhor, pois eles me expulsaram hoje para que eu não tenha parte na herança do Senhor, dizendo: Vai, serve a outros deuses.' },
      { v: 20, en: 'Now therefore, don’t let my blood fall to the earth away from the presence of Yahweh; for the king of Israel has come out to seek a flea, as when one hunts a partridge in the mountains.”', pt: 'Agora, pois, não caia o meu sangue em terra fora da presença do Senhor; pois saiu o rei de Israel em busca duma pulga, como quem persegue uma perdiz nos montes.' },
      { v: 21, en: 'Then Saul said, “I have sinned. Return, my son David; for I will no more do you harm, because my life was precious in your eyes today. Behold, I have played the fool, and have erred exceedingly.”', pt: 'Então disse Saul: Pequei; volta, meu filho Davi, pois não tornarei a fazer-te mal, porque a minha vida foi hoje preciosa aos teus olhos. Eis que procedi como um louco, e errei grandissimamente.' },
      { v: 22, en: 'David answered, “Behold the spear, O king! Then let one of the young men come over and get it.', pt: 'Davi então respondeu, e disse: Eis aqui a lança, ó rei! venha cá um os mancebos, e leve-a.' },
      { v: 23, en: 'Yahweh will render to every man his righteousness and his faithfulness; because Yahweh delivered you into my hand today, and I wouldn’t stretch out my hand against Yahweh’s anointed.', pt: 'O Senhor, porém, pague a cada um a sua justiça e a sua lealdade; pois o Senhor te entregou hoje na minha mão, mas eu não quis estender a mão contra o ungido do Senhor.' },
      { v: 24, en: 'Behold, as your life was respected today in my eyes, so let my life be respected in Yahweh’s eyes, and let him deliver me out of all oppression.”', pt: 'E assim como foi a tua vida hoje preciosa aos meus olhos, seja a minha vida preciosa aos olhos do Senhor, e livre-me ele de toda a tribulação.' },
      { v: 25, en: 'Then Saul said to David, “You are blessed, my son David. You will both do mightily, and will surely prevail.” So David went his way, and Saul returned to his place.', pt: 'Então Saul disse a Davi: Bendito sejas tu, meu filho Davi, pois grandes coisas farás e também certamente prevalecerás. Então Davi se foi o seu caminho e Saul voltou para o seu lugar.' },
    ],
    27: [
      { v: 1, en: 'David said in his heart, “I will now perish one day by the hand of Saul. There is nothing better for me than that I should escape into the land of the Philistines; and Saul will despair of me, to seek me any more in all the borders of Israel. So shall I escape out of his hand.”', pt: 'Disse, porém, Davi no seu coração: Ora, perecerei ainda algum dia pela mão de Saul; não há coisa melhor para mim do que escapar para a terra dos filisteus, para que Saul perca a esperança de mim, e cesse de me buscar por todos os termos de Israel; assim escaparei da sua mão.' },
      { v: 2, en: 'David arose, and passed over, he and the six hundred men who were with him, to Achish the son of Maoch, king of Gath.', pt: 'Então Davi se levantou e passou, com os seiscentos homens que com ele estavam, para Áquis, filho de Maoque, rei de Gate.' },
      { v: 3, en: 'David lived with Achish at Gath, he and his men, every man with his household, even David with his two wives, Ahinoam the Jezreelitess, and Abigail the Carmelitess, Nabal’s wife.', pt: 'E Davi ficou com Áquis em Gate, ele e os seus homens, cada um com a sua família, e Davi com as suas duas mulheres, Ainoã, a jizreelita, e Abigail, que fora mulher de Nabal, o carmelita.' },
      { v: 4, en: 'Saul was told that David had fled to Gath: and he sought no more again for him.', pt: 'Ora, sendo Saul avisado de que Davi tinha fugido para Gate, não cuidou mais de buscá-lo.' },
      { v: 5, en: 'David said to Achish, “If now I have found favor in your eyes, let them give me a place in one of the cities in the country, that I may dwell there. For why should your servant dwell in the royal city with you?”', pt: 'Disse Davi a Áquis: Se eu tenho achado graça aos teus olhos, que se me dê lugar numa das cidades do país, para que eu ali habite; pois, por que haveria o teu servo de habitar contigo na cidade real?' },
      { v: 6, en: 'Then Achish gave him Ziklag that day: therefore Ziklag belongs to the kings of Judah to this day.', pt: 'Então lhe deu Áquis naquele dia a cidade de Ziclague; pelo que Ziclague pertence aos reis de Judá, até o dia de hoje.' },
      { v: 7, en: 'The number of the days that David lived in the country of the Philistines was a full year and four months.', pt: 'E o número dos dias que Davi habitou na terra dos filisteus foi de um ano e quatro meses.' },
      { v: 8, en: 'David and his men went up and raided the Geshurites, the Girzites, and the Amalekites; for those were the inhabitants of the land, who were of old, on the way to Shur, even to the land of Egypt.', pt: 'Ora, Davi e os seus homens subiam e davam sobre os gesuritas, e os girzitas, e os amalequitas; pois, desde tempos remotos, eram estes os moradores da terra que se estende na direção de Sur até a terra do Egito.' },
      { v: 9, en: 'David struck the land, and saved no man or woman alive, and took away the sheep, the cattle, the donkeys, the camels, and the clothing. Then he returned, and came to Achish.', pt: 'E Davi feria aquela terra, não deixando com vida nem homem nem mulher; e, tomando ovelhas, bois, jumentos, camelos e vestuários, voltava, e vinha a Áquis.' },
      { v: 10, en: 'Achish said, “Against whom have you made a raid today?” David said, “Against the South of Judah, against the South of the Jerahmeelites, and against the South of the Kenites.”', pt: 'E quando Áquis perguntava: Sobre que parte fizestes incursão hoje? Davi respondia: Sobre o Negebe de Judá; ou: Sobre o Negebe dos jerameelitas; ou: Sobre o Negebe dos queneus.' },
      { v: 11, en: 'David saved neither man nor woman alive, to bring them to Gath, saying, “Lest they should tell about us, saying, ‘David did this, and this has been his way all the time he has lived in the country of the Philistines.’”', pt: 'E Davi não deixava com vida nem homem nem mulher para trazê-los a Gate, pois dizia: Para que porventura não nos denunciem, dizendo: Assim fez Davi. E este era o seu costume por todos os dias que habitou na terra dos filisteus.' },
      { v: 12, en: 'Achish believed David, saying, “He has made his people Israel utterly to abhor him. Therefore he will be my servant forever.”', pt: 'Áquis, pois, confiava em Davi, dizendo: Fez-se ele por certo aborrecível para com o seu povo em Israel; pelo que me será por servo para sempre.' },
    ],
    28: [
      { v: 1, en: 'In those days, the Philistines gathered their armies together for warfare, to fight with Israel. Achish said to David, “Know assuredly that you will go out with me in the army, you and your men.”', pt: 'Naqueles dias ajuntaram os filisteus os seus exércitos para a guerra, para pelejarem contra Israel. Disse Áquis a Davi: Sabe de certo que sairás comigo ao arraial, tu e os teus homens.' },
      { v: 2, en: 'David said to Achish, “Therefore you will know what your servant can do.” Achish said to David, “Therefore I will make you my bodyguard forever.”', pt: 'Respondeu Davi a Áquis: Assim saberás o que o teu servo há de fazer. E disse Áquis a Davi: Por isso te farei para sempre guarda da minha pessoa.' },
      { v: 3, en: 'Now Samuel was dead, and all Israel had mourned for him, and buried him in Ramah, even in his own city. Saul had sent away those who had familiar spirits and the wizards out of the land.', pt: 'Ora, Samuel já havia morrido, e todo o Israel o tinha chorado, e o tinha sepultado e em Ramá, que era a sua cidade. E Saul tinha desterrado es necromantes e os adivinhos.' },
      { v: 4, en: 'The Philistines gathered themselves together, and came and encamped in Shunem; and Saul gathered all Israel together, and they encamped in Gilboa.', pt: 'Ajuntando-se, pois, os filisteus, vieram acampar-se em Suném; Saul ajuntou também todo o Israel, e se acamparam em Gilboa.' },
      { v: 5, en: 'When Saul saw the army of the Philistines, he was afraid, and his heart trembled greatly.', pt: 'Vendo Saul o arraial dos filisteus, temeu e estremeceu muito o seu coração.' },
      { v: 6, en: 'When Saul inquired of Yahweh, Yahweh didn’t answer him by dreams, by Urim, or by prophets.', pt: 'Pelo que consultou Saul ao Senhor, porém o Senhor não lhe respondeu, nem por sonhos, nem por Urim, nem por profetas.' },
      { v: 7, en: 'Then Saul said to his servants, “Seek for me a woman who has a familiar spirit, that I may go to her, and inquire of her.” His servants said to him, “Behold, there is a woman who has a familiar spirit at Endor.”', pt: 'Então disse Saul aos seus servos: Buscai-me uma necromante, para que eu vá a ela e a consulte. Disseram-lhe os seus servos: Eis que em En-Dor há uma mulher que é necromante.' },
      { v: 8, en: 'Saul disguised himself and put on other clothing, and went, he and two men with him, and they came to the woman by night. Then he said, “Please consult for me by the familiar spirit, and bring me up whomever I shall name to you.”', pt: 'Então Saul se disfarçou, vestindo outros trajes; e foi ele com dois homens, e chegaram de noite à casa da mulher. Disse-lhe Saul: Peço-te que me adivinhes pela necromancia, e me faças subir aquele que eu te disser.' },
      { v: 9, en: 'The woman said to him, “Behold, you know what Saul has done, how he has cut off those who have familiar spirits, and the wizards, out of the land. Why then do you lay a snare for my life, to cause me to die?”', pt: 'A mulher lhe respondeu: Tu bem sabes o que Saul fez, como exterminou da terra os necromantes e os adivinhos; por que, então, me armas um laço à minha vida, para me fazeres morrer?' },
      { v: 10, en: 'Saul swore to her by Yahweh, saying, “As Yahweh lives, no punishment will happen to you for this thing.”', pt: 'Saul, porém, lhe jurou pelo Senhor, dizendo: Como vive o Senhor, nenhum castigo te sobrevirá por isso.' },
      { v: 11, en: 'Then the woman said, “Whom shall I bring up to you?” He said, “Bring Samuel up for me.”', pt: 'A mulher então lhe perguntou: Quem te farei subir? Respondeu ele: Faze-me subir Samuel.' },
      { v: 12, en: 'When the woman saw Samuel, she cried with a loud voice; and the woman spoke to Saul, saying, “Why have you deceived me? For you are Saul!”', pt: 'Vendo, pois, a mulher a Samuel, gritou em alta voz, e falou a Saul, dizendo: Por que me enganaste? pois tu mesmo és Saul.' },
      { v: 13, en: 'The king said to her, “Don’t be afraid! What do you see?” The woman said to Saul, “I see a god coming up out of the earth.”', pt: 'Ao que o rei lhe disse: Não temas; que é que vês? Então a mulher respondeu a Saul: Vejo um deus que vem subindo de dentro da terra.' },
      { v: 14, en: 'He said to her, “What does he look like?” She said, “An old man comes up. He is covered with a robe.” Saul perceived that it was Samuel, and he bowed with his face to the ground, and showed respect.', pt: 'Perguntou-lhe ele: Como é a sua figura? E disse ela: Vem subindo um ancião, e está envolto numa capa. Entendendo Saul que era Samuel, inclinou-se com o rosto em terra, e lhe fez reverência.' },
      { v: 15, en: 'Samuel said to Saul, “Why have you disturbed me, to bring me up?” Saul answered, “I am very distressed; for the Philistines make war against me, and God has departed from me, and answers me no more, by prophets, or by dreams. Therefore I have called you, that you may make known to me what I shall do.”', pt: 'Samuel disse a Saul: Por que me inquietaste, fazendo-me subir? Então disse Saul: Estou muito angustiado, porque os filisteus guerreiam contra mim, e Deus se tem desviado de mim, e já não me responde, nem por intermédio dos profetas nem por sonhos; por isso te chamei, para que me faças saber o que hei de fazer.' },
      { v: 16, en: 'Samuel said, “Why then do you ask me, since Yahweh has departed from you and has become your adversary?', pt: 'Então disse Samuel: Por que, pois, me perguntas a mim, visto que o Senhor se tem desviado de ti, e se tem feito teu inimigo?' },
      { v: 17, en: 'Yahweh has done to you as he spoke by me. Yahweh has torn the kingdom out of your hand, and given it to your neighbor, even to David.', pt: 'O Senhor te fez como por meu intermédio te disse; pois o Senhor rasgou o reino da tua mão, e o deu ao teu próximo, a Davi.' },
      { v: 18, en: 'Because you didn’t obey Yahweh’s voice, and didn’t execute his fierce wrath on Amalek, therefore Yahweh has done this thing to you today.', pt: 'Porquanto não deste ouvidos à voz do Senhor, e não executaste e furor da sua ira contra Amaleque, por isso o Senhor te fez hoje isto.' },
      { v: 19, en: 'Moreover Yahweh will deliver Israel also with you into the hand of the Philistines; and tomorrow you and your sons will be with me. Yahweh will deliver the army of Israel also into the hand of the Philistines.”', pt: 'E o Senhor entregará também a Israel contigo na mão dos filisteus. Amanhã tu e teus filhos estareis comigo, e o Senhor entregará o arraial de Israel na mão dos filisteus.' },
      { v: 20, en: 'Then Saul fell immediately his full length on the earth, and was terrified, because of Samuel’s words. There was no strength in him; for he had eaten no bread all day long or all night long.', pt: 'Imediatamente Saul caiu estendido por terra, tomado de grande medo por causa das palavras de Samuel; e não houve força nele, porque nada havia comido todo aquele dia e toda aquela noite.' },
      { v: 21, en: 'The woman came to Saul, and saw that he was very troubled, and said to him, “Behold, your servant has listened to your voice, and I have put my life in my hand, and have listened to your words which you spoke to me.', pt: 'Então a mulher se aproximou de Saul e, vendo que estava tão perturbado, disse-lhe: Eis que a tua serva deu ouvidos à tua voz; pus a minha vida na minha mão, dando ouvidos às palavras que disseste.' },
      { v: 22, en: 'Now therefore, please listen also to the voice of your servant, and let me set a morsel of bread before you. Eat, that you may have strength, when you go on your way.”', pt: 'Agora, pois, ouve também tu as palavras da tua serva, e permite que eu ponha um bocado de pão diante de ti; come, para que tenhas forças quando te puseres a caminho.' },
      { v: 23, en: 'But he refused, and said, “I will not eat.” But his servants, together with the woman, constrained him; and he listened to their voice. So he arose from the earth and sat on the bed.', pt: 'Ele, porém, recusou, dizendo: Não comerei. Mas os seus servos e a mulher o constrangeram, e ele deu ouvidos à sua voz; e levantando-se do chão, sentou-se na cama.' },
      { v: 24, en: 'The woman had a fattened calf in the house. She hurried and killed it; and she took flour, and kneaded it, and baked unleavened bread of it.', pt: 'Ora, a mulher tinha em casa um bezerro cevado; apressou-se, pois, e o degolou; tambem tomou farinha, e a amassou, e a cozeu em bolos ázimos.' },
      { v: 25, en: 'She brought it before Saul, and before his servants; and they ate. Then they rose up, and went away that night.', pt: 'Então pôs tudo diante de Saul e de seus servos; e eles comeram. Depois levantaram-se e partiram naquela mesma noite.' },
    ],
    29: [
      { v: 1, en: 'Now the Philistines gathered together all their armies to Aphek; and the Israelites encamped by the spring which is in Jezreel.', pt: 'Os filisteus ajuntaram todos os seus exércitos em Afeque; e acamparam-se os israelitas junto à fonte que está em Jizreel.' },
      { v: 2, en: 'The lords of the Philistines passed on by hundreds and by thousands; and David and his men passed on in the rear with Achish.', pt: 'Então os chefes dos filisteus se adiantaram com centenas e com milhares; e Davi e os seus homens iam com Áquis na retaguarda.' },
      { v: 3, en: 'Then the princes of the Philistines said, “What about these Hebrews?” Achish said to the princes of the Philistines, “Isn’t this David, the servant of Saul the king of Israel, who has been with me these days, or rather these years, and I have found no fault in him since he fell away to today?”', pt: 'Perguntaram os chefes dos filisteus: que fazem aqui estes hebreus? Respondeu Áquis aos chefes dos filisteus: Não é este Davi, o servo de Saul, rei de Israel, que tem estado comigo alguns dias ou anos? e nenhuma culpa tenho achado nele desde o dia em que se revoltou, até o dia de hoje.' },
      { v: 4, en: 'But the princes of the Philistines were angry with him; and the princes of the Philistines said to him, “Make the man return, that he may go back to his place where you have appointed him, and let him not go down with us to battle, lest in the battle he become an adversary to us. For with what should this fellow reconcile himself to his lord? Should it not be with the heads of these men?', pt: 'Mas os chefes dos filisteus muito se indignaram contra ele, e disseram a Áquis: Faze voltar este homem para que torne ao lugar em que o puseste; não desça ele conosco à batalha, a fim de que não se torne nosso adversário no combate; pois, como se tornaria este agradável a seu senhor? porventura não seria com as cabeças destes homens?' },
      { v: 5, en: 'Isn’t this David, of whom people sang to one another in dances, saying, ‘Saul has slain his thousands, and David his ten thousands?’”', pt: 'Este não é aquele Davi, a respeito de quem cantavam nas danças: Saul feriu os seus milhares, mas Davi os seus dez milhares?' },
      { v: 6, en: 'Then Achish called David, and said to him, “As Yahweh lives, you have been upright, and your going out and your coming in with me in the army is good in my sight; for I have not found evil in you since the day of your coming to me to this day. Nevertheless, the lords don’t favor you.', pt: 'Então Áquis chamou a Davi e disse-lhe: Como vive o Senhor, tu és reto, e a sua entrada e saída comigo no arraial é boa aos meus olhos, pois nenhum mal tenho achado em ti, desde o dia em que vieste ter comigo, até o dia de hoje; porém aos chefes não agradas.' },
      { v: 7, en: 'Therefore now return, and go in peace, that you not displease the lords of the Philistines.”', pt: 'Volta, pois, agora, e vai em paz, para não desagradares os chefes dos filisteus.' },
      { v: 8, en: 'David said to Achish, “But what have I done? What have you found in your servant so long as I have been before you to this day, that I may not go and fight against the enemies of my lord the king?”', pt: 'Ao que Davi disse a Áquis: Por quê? que fiz eu? ou, que achaste no teu servo, desde o dia em que vim ter contigo, até o dia de hoje, para que eu não vá pelejar contra es inimigos do rei meu senhor?' },
      { v: 9, en: 'Achish answered David, “I know that you are good in my sight, as an angel of God. Notwithstanding the princes of the Philistines have said, ‘He shall not go up with us to the battle.’', pt: 'Respondeu, porém, Áquis e disse a Davi: Bem o sei; e, na verdade, aos meus olhos és bom como um anjo de Deus; contudo os chefes dos filisteus disseram: Este não há de subir conosco à batalha.' },
      { v: 10, en: 'Therefore now rise up early in the morning with the servants of your lord who have come with you; and as soon as you are up early in the morning, and have light, depart.”', pt: 'Levanta-te, pois, amanhã de madrugada, tu e os servos de teu senhor que vieram contigo; e, tendo vos levantado de madrugada, parti logo que haja luz.' },
      { v: 11, en: 'So David rose up early, he and his men, to depart in the morning, to return into the land of the Philistines, and the Philistines went up to Jezreel.', pt: 'Madrugaram, pois, Davi e os seus homens, a fim de partirem, pela manhã, e voltarem à terra dos filisteus; e os filisteus subiram a Jizreel.' },
    ],
    30: [
      { v: 1, en: 'When David and his men had come to Ziklag on the third day, the Amalekites had made a raid on the South, and on Ziklag, and had struck Ziklag, and burned it with fire,', pt: 'Sucedeu, pois, que, chegando Davi e os seus homens ao terceiro dia a Ziclague, os amalequitas tinham feito uma incursão sobre o Negebe, e sobre Ziclague, e tinham ferido a Ziclague e a tinham queimado a fogo;' },
      { v: 2, en: 'and had taken captive the women and all who were in it, both small and great. They didn’t kill any, but carried them off, and went their way.', pt: 'e tinham levado cativas as mulheres, e todos os que estavam nela, tanto pequenos como grandes; a ninguém, porém, mataram, tão-somente os levaram consigo, e foram o seu caminho.' },
      { v: 3, en: 'When David and his men came to the city, behold, it was burned with fire; and their wives, their sons, and their daughters were taken captive.', pt: 'Quando Davi e os seus homens chegaram à cidade, eis que estava queimada a fogo, e suas mulheres, seus filhos e suas filhas tinham sido levados cativos.' },
      { v: 4, en: 'Then David and the people who were with him lifted up their voice and wept until they had no more power to weep.', pt: 'Então Davi e o povo que se achava com ele alçaram a sua voz, e choraram, até que não ouve neles mais forças para chorar.' },
      { v: 5, en: 'David’s two wives were taken captive, Ahinoam the Jezreelitess, and Abigail the wife of Nabal the Carmelite.', pt: 'Também as duas mulheres de Davi foram levadas cativas: Ainoã, a jizreelita, e Abigail, que fora mulher de Nabal, o carmelita.' },
      { v: 6, en: 'David was greatly distressed; for the people spoke of stoning him, because the souls of all the people were grieved, every man for his sons and for his daughters; but David strengthened himself in Yahweh his God.', pt: 'Também Davi se angustiou; pois o povo falava em apedrejá-lo, porquanto a alma de todo o povo estava amargurada por causa de seus filhos e de suas filhas. Mas Davi se fortaleceu no Senhor seu Deus.' },
      { v: 7, en: 'David said to Abiathar the priest, the son of Ahimelech, “Please bring the ephod here to me.” Abiathar brought the ephod to David.', pt: 'Disse Davi a Abiatar, o sacerdote, filho de Aimeleque: Traze-me aqui o éfode. E Abiatar trouxe o éfode a Davi.' },
      { v: 8, en: 'David inquired of Yahweh, saying, “If I pursue after this troop, will I overtake them?” He answered him, “Pursue; for you will surely overtake them, and will without fail recover all.”', pt: 'Então consultou Davi ao Senhor, dizendo: Perseguirei eu a esta tropa? alcançá-la-ei? Respondeu-lhe o Senhor: Persegue-a; porque de certo a alcançarás e tudo recobrarás.' },
      { v: 9, en: 'So David went, he and the six hundred men who were with him, and came to the brook Besor, where those who were left behind stayed.', pt: 'Ao que partiu Davi, ele e os seiscentos homens que com ele se achavam, e chegaram ao ribeiro de Besor, onde pararam os que tinham ficado para trás.' },
      { v: 10, en: 'But David pursued, he and four hundred men; for two hundred stayed behind, who were so faint that they couldn’t go over the brook Besor.', pt: 'Mas Davi ainda os perseguia, com quatrocentos homens, enquanto que duzentos ficaram atrás, por não poderem, de cansados que estavam, passar o ribeiro de Besor.' },
      { v: 11, en: 'They found an Egyptian in the field, and brought him to David, and gave him bread, and he ate; and they gave him water to drink.', pt: 'Ora, acharam no campo um egípcio, e o trouxeram a Davi; deram-lhe pão a comer, e água a beber;' },
      { v: 12, en: 'They gave him a piece of a cake of figs, and two clusters of raisins. When he had eaten, his spirit came again to him; for he had eaten no bread, and drank no water for three days and three nights.', pt: 'deram-lhe também um pedaço de massa de figos secos e dois cachos de passas. Tendo ele comido, voltou-lhe o ânimo; pois havia três dias e três noites que não tinha comido pão nem bebido água.' },
      { v: 13, en: 'David asked him, “To whom do you belong? Where are you from?” He said, “I am a young man of Egypt, servant to an Amalekite; and my master left me, because three days ago I got sick.', pt: 'Então Davi lhe perguntou: De quem és tu, e donde vens? Respondeu ele: Sou um moço egípcio, servo dum amalequita; e o meu senhor me abandonou, porque adoeci há três dias.' },
      { v: 14, en: 'We made a raid on the South of the Cherethites, and on that which belongs to Judah, and on the South of Caleb; and we burned Ziklag with fire.”', pt: 'Nós fizemos uma incursão sobre o Negebe dos queretitas, sobre o de Judá e sobre o de Calebe, e pusemos fogo a Ziclague.' },
      { v: 15, en: 'David said to him, “Will you bring me down to this troop?” He said, “Swear to me by God that you will not kill me and not deliver me up into the hands of my master, and I will bring you down to this troop.”', pt: 'Perguntou-lhe Davi: Poderias descer e guiar-me a essa tropa? Respondeu ele: Jura-me tu por Deus que não me matarás, nem me entregarás na mão de meu senhor, e eu descerei e te guiarei a essa tropa.' },
      { v: 16, en: 'When he had brought him down, behold, they were spread around over all the ground, eating, drinking, and dancing, because of all the great plunder that they had taken out of the land of the Philistines, and out of the land of Judah.', pt: 'Desceu, pois, e o guiou; e eis que eles estavam espalhados sobre a face de toda a terra, comendo, bebendo e dançando, por causa de todo aquele grande despojo que haviam tomado da terra dos filisteus e a terra de Judá.' },
      { v: 17, en: 'David struck them from the twilight even to the evening of the next day. Not a man of them escaped from there, except four hundred young men, who rode on camels and fled.', pt: 'Então Davi os feriu, desde o crepúsculo até a tarde do dia seguinte, e nenhum deles escapou, senão só quatrocentos mancebos que, montados sobre camelos, fugiram.' },
      { v: 18, en: 'David recovered all that the Amalekites had taken; and David rescued his two wives.', pt: 'Assim recobrou Davi tudo quanto os amalequitas haviam tomado; também libertou as suas duas mulheres.' },
      { v: 19, en: 'There was nothing lacking to them, neither small nor great, neither sons nor daughters, neither plunder, nor anything that they had taken to them. David brought back all.', pt: 'De modo que não lhes faltou coisa alguma, nem pequena nem grande, nem filhos nem filhas, nem qualquer coisa de tudo quanto os amalequitas lhes haviam tomado; tudo Davi tornou a trazer.' },
      { v: 20, en: 'David took all the flocks and the herds, which they drove before those other livestock, and said, “This is David’s plunder.”', pt: 'Davi lhes tomou também todos os seus rebanhos e manadas; e o povo os levava adiante do outro gado, e dizia: Este é o despojo de Davi.' },
      { v: 21, en: 'David came to the two hundred men, who were so faint that they could not follow David, whom also they had made to stay at the brook Besor; and they went out to meet David, and to meet the people who were with him. When David came near to the people, he greeted them.', pt: 'Quando Davi chegou aos duzentos homens que, de cansados que estavam, não tinham podido segui-los, e que foram obrigados a ficar ao pé do ribeiro de Besor, estes saíram ao encontro de Davi e do povo que com ele vinha; e Davi, aproximando-se deles, os saudou em paz.' },
      { v: 22, en: 'Then all the wicked men and worthless fellows, of those who went with David, answered and said, “Because they didn’t go with us, we will not give them anything of the plunder that we have recovered, except to every man his wife and his children, that he may lead them away, and depart.”', pt: 'Então todos os malvados e perversos, dentre os homens que tinham ido com Davi, disseram: Visto que não foram conosco, nada lhes daremos do despojo que recobramos, senão a cada um sua mulher e seus filhos, para que os levem e se retirem.' },
      { v: 23, en: 'Then David said, “Do not do so, my brothers, with that which Yahweh has given to us, who has preserved us, and delivered the troop that came against us into our hand.', pt: 'Mas Davi disse: Não fareis assim, irmãos meus, com o que nos deu o Senhor, que nos guardou e entregou nas nossas mãos a tropa que vinha contra nós.' },
      { v: 24, en: 'Who will listen to you in this matter? For as his share is who goes down to the battle, so shall his share be who stays with the baggage. They shall share alike.”', pt: 'E quem vos daria ouvidos nisso? pois qual é a parte dos que desceram à batalha, tal será também a parte dos que ficaram com a bagagem; receberão partes.' },
      { v: 25, en: 'It was so from that day forward, that he made it a statute and an ordinance for Israel to this day.', pt: 'E assim foi daquele dia em diante, ficando estabelecido por estatuto e direito em Israel até o dia de hoje.' },
      { v: 26, en: 'When David came to Ziklag, he sent some of the plunder to the elders of Judah, even to his friends, saying, “Behold, a present for you from the plunder of Yahweh’s enemies.”', pt: 'Quando Davi chegou a Ziclague, enviou do despojo presente aos anciãos de Judá, seus amigos, dizendo: Eis aí para vós um presente do despojo dos inimigos do Senhor;' },
      { v: 27, en: 'He sent it to those who were in Bethel, to those who were in Ramoth of the South, to those who were in Jattir,', pt: 'aos de Betel, aos de Ramote do Sul, e aos de Jatir;' },
      { v: 28, en: 'to those who were in Aroer, to those who were in Siphmoth, to those who were in Eshtemoa,', pt: 'aos de Aroer, aos de Sifmote, e aos de Estemoa;' },
      { v: 29, en: 'to those who were in Racal, to those who were in the cities of the Jerahmeelites, to those who were in the cities of the Kenites,', pt: 'aos de Racal, aos das cidades dos jerameelitas, e aos das cidades dos queneus;' },
      { v: 30, en: 'to those who were in Hormah, to those who were in Borashan, to those who were in Athach,', pt: 'aos de Horma, aos de Corasã, e aos de Atace;' },
      { v: 31, en: 'to those who were in Hebron, and to all the places where David himself and his men used to stay.', pt: 'e aos de Hebrom, e aos de todos os lugares que Davi e os seus homens costumavam freqüentar.' },
    ],
    31: [
      { v: 1, en: 'Now the Philistines fought against Israel; and the men of Israel fled from before the Philistines, and fell down slain on Mount Gilboa.', pt: 'Ora, os filisteus pelejaram contra Israel; e os homens de Israel fugiram de diante dos filisteus, e caíram mortos no monte Gilboa.' },
      { v: 2, en: 'The Philistines overtook Saul and on his sons; and the Philistines killed Jonathan, Abinadab, and Malchishua, the sons of Saul.', pt: 'E os filisteus apertaram com Saul e seus filhos, e mataram a Jônatas, a Abinadabe e e a Malquisua, filhos de Saul.' },
      { v: 3, en: 'The battle went hard against Saul, and the archers overtook him; and he was greatly distressed by reason of the archers.', pt: 'A peleja se agravou contra Saul, e os flecheiros o alcançaram, e o feriram gravemente.' },
      { v: 4, en: 'Then Saul said to his armor bearer, “Draw your sword, and thrust me through with it, lest these uncircumcised come and thrust me through, and abuse me!” But his armor bearer would not; for he was terrified. Therefore Saul took his sword, and fell on it.', pt: 'Pelo que disse Saul ae seu escudeiro: Arranca a tua espada, e atravessa-me com ela, para que porventura não venham esses incircuncisos, e me atravessem e escarneçam de mim. Mas o seu escudeiro não quis, porque temia muito. Então Saul tomou a espada, e se lançou sobre ela.' },
      { v: 5, en: 'When his armor bearer saw that Saul was dead, he likewise fell on his sword, and died with him.', pt: 'Vendo, pois, e seu escudeiro que Saul já era morto, também ele se lançou sobre a sua espada, e morreu com ele.' },
      { v: 6, en: 'So Saul died, and his three sons, and his armor bearer, and all his men, that same day together.', pt: 'Assim morreram juntamente naquele dia Saul, seus três filhos, e seu escudeiro, e todos os seus homens.' },
      { v: 7, en: 'When the men of Israel who were on the other side of the valley, and those who were beyond the Jordan, saw that the men of Israel fled, and that Saul and his sons were dead, they abandoned the cities and fled; and the Philistines came and lived in them.', pt: 'Quando os israelitas que estavam no outro lado do vale e os que estavam além de Jordão viram que os homens de Israel tinham fugido, e que Saul e seus filhos estavam mortos, abandonaram as suas cidades e fugiram; e vieram os filisteus e habitaram nelas.' },
      { v: 8, en: 'On the next day, when the Philistines came to strip the slain, they found Saul and his three sons fallen on Mount Gilboa.', pt: 'No dia seguinte, quando os filisteus vieram para despojar os mortos, acharam Saul e seus três filhos estirados no monte Gilboa.' },
      { v: 9, en: 'They cut off his head, stripped off his armor, and sent into the land of the Philistines all around, to carry the news to the house of their idols, and to the people.', pt: 'Então cortaram a cabeça a Saul e o despejaram das suas armas; e enviaram pela terra dos filisteus, em redor, a anunciá-lo no templo dos seus ídolos e entre e povo,' },
      { v: 10, en: 'They put his armor in the house of the Ashtaroth, and they fastened his body to the wall of Beth Shan.', pt: 'Puseram as armas de Saul no templo de Astarote; e penduraram o seu corpo no muro de Bete-Sã.' },
      { v: 11, en: 'When the inhabitants of Jabesh Gilead heard what the Philistines had done to Saul,', pt: 'Quando os moradores de Jabes-Gileade ouviram isso a respeito de Saul, isto é, o que os filisteus lhe tinham feito,' },
      { v: 12, en: 'all the valiant men arose, went all night, and took the body of Saul and the bodies of his sons from the wall of Beth Shan; and they came to Jabesh, and burned them there.', pt: 'todos os homens valorosos se levantaram e, caminhando a noite toda, tiraram e corpo de Saul e os corpos de seus filhos do muro de Bete-Sã; e voltando a Jabes, ali os queimaram.' },
      { v: 13, en: 'They took their bones and buried them under the tamarisk tree in Jabesh, and fasted seven days.', pt: 'Depois tomaram os seus ossos, e os sepultaram debaixo da tamargueira, em Jabes, e jejuaram sete dias.' },
    ],
  },
};

export default book;
